-- Poems batch 169
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a5a319cc-2d02-4aad-82ec-8b571c12a6ae','重送處州斯遠三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','登臨長病獨成吟，連壁相依照映深。',32,'全唐诗/poet.song.167000.json','["登臨長病獨成吟，連壁相依照映深。", "寄謝青山無偃蹇，好聽絕唱亂清音。"]'),
('115940c5-cda0-42a2-99c8-2ca4c7bf99d9','重送處州斯遠三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','萬木蒼蒼古釣臺，白雲樓觀隔溪開。',32,'全唐诗/poet.song.167000.json','["萬木蒼蒼古釣臺，白雲樓觀隔溪開。", "賦成赤壁後無對，好與驅從筆下來。"]'),
('1ddf1231-93d5-4e8f-932e-a7196fda6a7b','重送處州斯遠三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','文字投盟不計官，古人能爾在今難。',32,'全唐诗/poet.song.167000.json','["文字投盟不計官，古人能爾在今難。", "使君於此自爲德，我輩因留後代看。"]'),
('c60c518d-1e00-41ad-9803-353c94119317','送曾耆英持胡端殿書謁張袁州四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','是家風節在峨岷，仍見諸孫文字貧。',32,'全唐诗/poet.song.167000.json','["是家風節在峨岷，仍見諸孫文字貧。", "聞道江南有蜀士，不辭犇走犯蕭晨。"]'),
('a14d9a52-005e-428d-87de-658593b3dcec','送曾耆英持胡端殿書謁張袁州四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君知龍門不易陟，頗欲乞書南郡胡。',32,'全唐诗/poet.song.167000.json','["君知龍門不易陟，頗欲乞書南郡胡。", "一幅斜行半年得，費君趼足幾工夫。"]'),
('ee791585-9dc2-4cda-b5cf-9f664116744a','送曾耆英持胡端殿書謁張袁州四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','袁州張侯吾所聞，政事不減大馮君。',32,'全唐诗/poet.song.167000.json','["袁州張侯吾所聞，政事不減大馮君。", "如云已召符節令，行矣君其無憚勤。"]'),
('8969343f-03d9-4b2a-a304-af0cd0c57882','送曾耆英持胡端殿書謁張袁州四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','我聞諸侯一朝享，可作寒士終年儲。',32,'全唐诗/poet.song.167000.json','["我聞諸侯一朝享，可作寒士終年儲。", "張家衣被及四海，不但一州歌袴襦。"]'),
('fda30667-490f-4cde-8192-7fcb2589b4b8','送劉克昌文顯二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','驛使相看合寄梅，日邊消息幾時回。',32,'全唐诗/poet.song.167000.json','["驛使相看合寄梅，日邊消息幾時回。", "平生所積故已厚，九萬不須風更培。"]'),
('95b3173a-0913-4cb9-ab14-3852c03207f9','送劉克昌文顯二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','柳暗知津君送我，江臨快閣我辭君。',32,'全唐诗/poet.song.167000.json','["柳暗知津君送我，江臨快閣我辭君。", "君行過我南山塔，爲道長懷日暮雲。"]'),
('a8cd472d-935d-4344-b647-fa435f996ecb','從禮折花携具見過且賦二詩  其一','趙蕃','宋','宋诗','song-poetry','','[]','出門政覺病軀難，已分春風負牡丹。',32,'全唐诗/poet.song.167000.json','["出門政覺病軀難，已分春風負牡丹。", "送花載酒能俱至，愧爾交情殊未闌。"]'),
('c4041fd2-b230-4783-9ae9-33b7c3d18b71','從禮折花携具見過且賦二詩  其二','趙蕃','宋','宋诗','song-poetry','','[]','花好千金未當價，只宜屏隠繡芙蓉。',32,'全唐诗/poet.song.167000.json','["花好千金未當價，只宜屏隠繡芙蓉。", "調笑頗似年少日，妄心今已退重重。"]'),
('272f049f-a08d-464d-b2a8-69199e0d8db4','從鄭秀才覓菊二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','好事風流有鄭莊，買園栽菊待重陽。',32,'全唐诗/poet.song.167000.json','["好事風流有鄭莊，買園栽菊待重陽。", "儻能憐我耽佳句，爲遣秋根到草堂。"]'),
('90c5b9d0-02aa-43cb-8a3f-5e087b39d51a','從鄭秀才覓菊二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','漫從僧舍移甘菊，清蘂重陽摘未堪。',32,'全唐诗/poet.song.167000.json','["漫從僧舍移甘菊，清蘂重陽摘未堪。", "徑欲過君籬下看，二兒端可爲輿籃。"]'),
('ed56657e-8594-4950-aa44-82ce5153a2f9','賦道傍菊  其一','趙蕃','宋','宋诗','song-poetry','','[]','園亭種菊只須多，名實相求半已訛。',32,'全唐诗/poet.song.167000.json','["園亭種菊只須多，名實相求半已訛。", "紫蔓弱莖真此物，顧埋林莽雜蓬萊。"]'),
('bb4bb8b7-c60b-4398-8402-8c60f7618e11','賦道傍菊  其二','趙蕃','宋','宋诗','song-poetry','','[]','世無元亮亦無詩，菊亦凄涼孰汝知。',32,'全唐诗/poet.song.167000.json','["世無元亮亦無詩，菊亦凄涼孰汝知。", "問我無詩寧愛菊，落英聞道可充饑。"]'),
('da68ace5-b7a6-4a70-bf66-848c3c205df7','賦道傍菊  其三','趙蕃','宋','宋诗','song-poetry','','[]','山行漸欲墮荆榛，夾道黄花獨爾新。',32,'全唐诗/poet.song.167000.json','["山行漸欲墮荆榛，夾道黄花獨爾新。", "野外籬邊非失所，尚能寒眼動詩人。"]'),
('1ad9f6a8-a956-4c83-a603-660623514a62','賦道傍菊  其四','趙蕃','宋','宋诗','song-poetry','','[]','三逕雖荒菊尚存，江東書到每傷神。',32,'全唐诗/poet.song.167000.json','["三逕雖荒菊尚存，江東書到每傷神。", "七盤八疊辰州路，頼爾相看作故人。"]'),
('be4286bf-6b95-4901-8522-e44ffbfff237','賦道傍菊  其五','趙蕃','宋','宋诗','song-poetry','','[]','日和猶有采花蜂，日冷凄然難爲容。',32,'全唐诗/poet.song.167000.json','["日和猶有采花蜂，日冷凄然難爲容。", "不以無人廢芳事，政應蘭薏與同宗。"]'),
('8d1bf664-e0cf-4c7c-80b0-ce8145169bd2','賦道傍菊  其六','趙蕃','宋','宋诗','song-poetry','','[]','黄菊花中黄蝶飛，似憐節晚悵餘暉。',32,'全唐诗/poet.song.167000.json','["黄菊花中黄蝶飛，似憐節晚悵餘暉。", "春風桃李明年事，十月清霜何處歸。"]'),
('9eed0f89-7738-4b31-a818-caa6db95a902','道傍菊有感','趙蕃','宋','宋诗','song-poetry','','[]','昔日曾升君子堂，祇今蕭艾與俱長。',32,'全唐诗/poet.song.167000.json','["昔日曾升君子堂，祇今蕭艾與俱長。", "可憐冷蝶無時態，盡日伶俜爲汝忙。"]'),
('5514a2d0-d5ee-48b4-9b5b-52b5af9f6e09','道店菊','趙蕃','宋','宋诗','song-poetry','','[]','種花本欲娛行客，客子逢花特地悲。',32,'全唐诗/poet.song.167000.json','["種花本欲娛行客，客子逢花特地悲。", "忽忽重陽今半月，依然青蘂網蛛絲。"]'),
('39ba433d-fba8-4670-a258-aa7bf9add497','招仲威不至反辱惠梨','趙蕃','宋','宋诗','song-poetry','','[]','屢廢招呼定可人，豈嫌昏暮叩門頻。',32,'全唐诗/poet.song.167000.json','["屢廢招呼定可人，豈嫌昏暮叩門頻。", "不來醉我傾家釀，反更分渠飣坐珍。"]'),
('7e88ec08-85fe-4982-9a9d-dfc5987f182f','食枸杞','趙蕃','宋','宋诗','song-poetry','','[]','誰道春風未發生，杞苗試摘已堪羹。',32,'全唐诗/poet.song.167000.json','["誰道春風未發生，杞苗試摘已堪羹。", "莫將口腹爲人累，竹瘦殊勝豕腹亨。"]'),
('f5b5ba91-a658-4981-8a56-bab99f279411','倪秀才惠橄欖二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','故憐枉作近南官，南果何曾上客盤。',32,'全唐诗/poet.song.167000.json','["故憐枉作近南官，南果何曾上客盤。", "橄欖忽來蕉作裹，欣然却作近鄉看。"]'),
('561017d3-2caf-411b-aa1a-e12ac35a3eab','倪秀才惠橄欖二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','直道堪嗟故不容，更持諫味欲誰從。',32,'全唐诗/poet.song.167000.json','["直道堪嗟故不容，更持諫味欲誰從。", "昏昏度日惟貪睡，茗椀聊充午後供。"]'),
('18ab4b9e-b3ae-4b98-986a-dd83beaa5f21','以山藥茶送沈宜之兄','趙蕃','宋','宋诗','song-poetry','','[]','山藥本爲林下享，筠籃那得致兵厨。',32,'全唐诗/poet.song.167000.json','["山藥本爲林下享，筠籃那得致兵厨。", "傳擔雲月併持與，長夜讀書應所須。"]'),
('bcba4682-19dd-43aa-b67d-e0324d88a920','以湖州酥秀州木犀面油太和石本觀音像送莫萬安三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','蟻浮猶臘要酥同，長恨中州信不通。',32,'全唐诗/poet.song.167000.json','["蟻浮猶臘要酥同，長恨中州信不通。", "忽得吳中所持寄，急令分減報鄉風。"]'),
('701a9378-15cf-4fed-b89d-e1df24205fea','以湖州酥秀州木犀面油太和石本觀音像送莫萬安三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','天教桂蘂擅秋分，只道非秋無復存。',32,'全唐诗/poet.song.167000.json','["天教桂蘂擅秋分，只道非秋無復存。", "底事蘭開梅落際，忽於膏飾見追魂。"]'),
('4fedbb70-4c28-4468-86d2-581de7350566','以湖州酥秀州木犀面油太和石本觀音像送莫萬安三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','涪翁昔作白下宰，遺墨到今多鴈書。',32,'全唐诗/poet.song.167000.json','["涪翁昔作白下宰，遺墨到今多鴈書。", "盡說補陀存相好，更傳雷火護持餘。"]'),
('5c4e1fd5-9101-40ec-bc2f-21660114d202','謝彭沅陵送貓','趙蕃','宋','宋诗','song-poetry','','[]','怪來米盡鼠忘遷，嚼齧侵尋到簡編。',32,'全唐诗/poet.song.167000.json','["怪來米盡鼠忘遷，嚼齧侵尋到簡編。", "珍重令君憐此意，不勞魚聘乞銜蟬。"]'),
('bc522e03-47a0-4dcc-a403-2abc0237afcc','送蕨與成父','趙蕃','宋','宋诗','song-poetry','','[]','道人惠我南山蕨，頗带齋厨法醤香。',32,'全唐诗/poet.song.167000.json','["道人惠我南山蕨，頗带齋厨法醤香。", "聞道城中少蔬供，急令健步走傾筐。"]'),
('5f323ad4-2003-486f-b97b-c33fec600383','初寒無衾買紙被以紓急作四絕  其一','趙蕃','宋','宋诗','song-poetry','','[]','平生結得楮生緣，覓句抄書日費捐。',32,'全唐诗/poet.song.167000.json','["平生結得楮生緣，覓句抄書日費捐。", "只有夜窗宜暫舍，也須包裹伴幽眠。"]'),
('f246c519-b7fb-4983-ae5a-094e88c3c759','初寒無衾買紙被以紓急作四絕  其二','趙蕃','宋','宋诗','song-poetry','','[]','瑟縮從渠體尚生，不妨欹擁度天明。',32,'全唐诗/poet.song.167000.json','["瑟縮從渠體尚生，不妨欹擁度天明。", "書生活計能消底，太息牛衣王仲卿。"]'),
('25375d18-333b-4f77-bfdc-4f3552aa4e80','初寒無衾買紙被以紓急作四絕  其三','趙蕃','宋','宋诗','song-poetry','','[]','度夕陰風吹扊扅，布衾如鐵念嬌兒。',32,'全唐诗/poet.song.167000.json','["度夕陰風吹扊扅，布衾如鐵念嬌兒。", "夜來例拜奇溫賜，但覺安眠曉不知。"]'),
('c7f0eb8a-9415-43a7-890e-79a91a79ed85','初寒無衾買紙被以紓急作四絕  其四','趙蕃','宋','宋诗','song-poetry','','[]','識字誰令勝爛奚，自應無褐更無衣。',32,'全唐诗/poet.song.167000.json','["識字誰令勝爛奚，自應無褐更無衣。", "宵安亦念明朝計，兒報屋簷生早暉。"]'),
('812ca868-db0b-41ef-9306-af7f01ba1478','閻伯善以孟東野集見惠二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','文字何關達與窮，悵君一尉已龍鍾。',32,'全唐诗/poet.song.167000.json','["文字何關達與窮，悵君一尉已龍鍾。", "過君舊邑求君集，行橐蕭然足慰儂。"]'),
('06cd097e-e1ea-4e96-95bd-8aac221dc388','閻伯善以孟東野集見惠二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','幾度相從酌酒深，向來相識未如今。',32,'全唐诗/poet.song.167000.json','["幾度相從酌酒深，向來相識未如今。", "臨分念我亦窮者，乞與郊詩俾細吟。"]'),
('c6f9d0d9-e5e2-483e-a437-b20f2b0d28a9','小釀告熟童子索覆瓶紙坼舊藁與之','趙蕃','宋','宋诗','song-poetry','','[]','太玄適足覆醤瓿，舊藁乃獲塓酒尊。',32,'全唐诗/poet.song.167000.json','["太玄適足覆醤瓿，舊藁乃獲塓酒尊。", "從來事有幸不幸，一笑掀髯誰與論。"]'),
('7fdd0f7d-2fc9-4c74-a4e7-d73b31bb8f4d','讀謝幼槃集  其一','趙蕃','宋','宋诗','song-poetry','','[]','茗椀不能驅睡魔，漫携詩冊向庭柯。',32,'全唐诗/poet.song.167000.json','["茗椀不能驅睡魔，漫携詩冊向庭柯。", "世人祇愛高官職，孰與公家兄弟過。"]'),
('1cbf9de0-eb94-481c-8fc4-c4e8a916f2b3','讀謝幼槃集  其二','趙蕃','宋','宋诗','song-poetry','','[]','自汲清泉除硯垢，樹陰微息晚涼初。',32,'全唐诗/poet.song.167000.json','["自汲清泉除硯垢，樹陰微息晚涼初。", "箇中得意誰知我，筆下忘言我羨渠。"]'),
('7421ae35-5e74-4845-bdf3-1f3861860ba3','題船子和尚圖','趙蕃','宋','宋诗','song-poetry','','[]','縱有絲綸不暇施，癡魚吞月自驚疑。',32,'全唐诗/poet.song.167000.json','["縱有絲綸不暇施，癡魚吞月自驚疑。", "旁觀莫作風波想，比著人間未是危。"]'),
('8f4a0766-46bf-4826-93cd-2aec0ca784ad','自桃川至辰州絕句四十有二  其一','趙蕃','宋','宋诗','song-poetry','','[]','甕子灘頭百丈牽，此其小小大猶前。',32,'全唐诗/poet.song.167000.json','["甕子灘頭百丈牽，此其小小大猶前。", "命輕人鮓曾聞說，楚蜀懸知險並然。"]'),
('b7807e73-063e-4d1d-9b65-f69dbf194d9a','自桃川至辰州絕句四十有二  其二','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','過了磯頭尚有湋，長江萬里此爲稀。',32,'全唐诗/poet.song.167000.json','["過了磯頭尚有湋，長江萬里此爲稀。", "悵予何可數乘此，宜爾山禽頻勸歸。"]'),
('e0873122-2c28-4c19-afbb-67b4cc8a690d','自桃川至辰州絕句四十有二  其三','趙蕃','宋','宋诗','song-poetry','','[]','上得磯來勢已危，忽然纜斷不能支。',32,'全唐诗/poet.song.167000.json','["上得磯來勢已危，忽然纜斷不能支。", "驚心釣渚河邊石，值爾應當應手糜。"]'),
('b8da6af1-06e7-4709-8d00-bd23907b2cea','自桃川至辰州絕句四十有二  其四','趙蕃','宋','宋诗','song-poetry','','[]','釣石疑爲借石低，月岩穿石兩空梯。',32,'全唐诗/poet.song.167000.json','["釣石疑爲借石低，月岩穿石兩空梯。", "逃虛尚說聞人喜，況此依然面目迷。"]'),
