('4fdb854e-5da1-4795-b1b7-0986884aeb34','懷遠父斯遠成父  其二','趙蕃','宋','宋诗','song-poetry','','[]','春風吹雨晝成昏，蕭寺蕭條早閉門。',32,'全唐诗/poet.song.167000.json','["春風吹雨晝成昏，蕭寺蕭條早閉門。", "坐久行人更蕭瑟，定傾老酒向何村。"]'),
('e463f4d2-ba48-43c2-8af1-ceac2cd57aa1','次韵斯遠去秋八月十三日午睡既醒登山遠望見懷  其一','趙蕃','宋','宋诗','song-poetry','','[]','驅去復來仍此都，豈惟人誚鬼揶揄。',32,'全唐诗/poet.song.167000.json','["驅去復來仍此都，豈惟人誚鬼揶揄。", "顧防未免罹矰繳，却使高人賦鴈奴。"]'),
('0f907335-f82e-495e-8f6e-3c5d42d90476','次韵斯遠去秋八月十三日午睡既醒登山遠望見懷  其二','趙蕃','宋','宋诗','song-poetry','','[]','數行書裏兩章詩，坐誦行哦晝屢移。',32,'全唐诗/poet.song.167000.json','["數行書裏兩章詩，坐誦行哦晝屢移。", "賦當疎雨梧桐日，題就扶疎夏木時。"]'),
('81c48093-0dfd-4df5-8ff1-05f8e696c161','舟行遇雪二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','老樹槎牙凍不枯，雪花初集更敷腴。',32,'全唐诗/poet.song.167000.json','["老樹槎牙凍不枯，雪花初集更敷腴。", "懸崖斗峻人蹤絕，漠漠荒祠落社烏。"]'),
('e7cb8155-dff7-44fa-a926-2869c716d00a','舟行遇雪二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','沙嘴縈分直更紆，望中不盡渺愁予。',32,'全唐诗/poet.song.167000.json','["沙嘴縈分直更紆，望中不盡渺愁予。", "晚來一雨便成雪，翠巘修林同一如。"]'),
('657bca53-c2a2-4f43-b030-780ff5e39d8d','聞李處州亡','趙蕃','宋','宋诗','song-poetry','','[]','時時聞說故人死，日日自悲垂老身。',32,'全唐诗/poet.song.167000.json','["時時聞說故人死，日日自悲垂老身。", "白髮不生應不得，青山長在屬何人。"]'),
('596546da-db8d-42f1-9612-f96788aa49ec','哀文鼎  其一','趙蕃','宋','宋诗','song-poetry','','[]','晦日書來四月收，報余新失趙湖州。',32,'全唐诗/poet.song.167000.json','["晦日書來四月收，報余新失趙湖州。", "祇今交友如渠幾，一展來書一淚流。"]'),
('aea40261-1836-411c-9874-49e6662da614','哀文鼎  其二','趙蕃','宋','宋诗','song-poetry','','[]','海內忘形獨漢中，幾回日暮憶江東。',32,'全唐诗/poet.song.167000.json','["海內忘形獨漢中，幾回日暮憶江東。", "不惟吾子傷形影，我亦交遊不太窮。"]'),
