('2d1cd872-a145-41e0-b150-3188c577853f','梅花十絕句  其三','趙蕃','宋','宋诗','song-poetry','','[]','斷崖脩竹是吾廬，亦有梅花手自鋤。',32,'全唐诗/poet.song.167000.json','["斷崖脩竹是吾廬，亦有梅花手自鋤。", "歲晚平安久無報，不知春到又何如。"]'),
('64c3d5b9-e4be-4e12-af19-5796505deec8','梅花十絕句  其四','趙蕃','宋','宋诗','song-poetry','','[]','風月懸知非俗物，與梅相對却成三。',32,'全唐诗/poet.song.167000.json','["風月懸知非俗物，與梅相對却成三。", "是中故有無窮意，曲几團蒲須細參。"]'),
('a3f1ecc5-22c5-42a4-bec6-790f9a5ccd7d','梅花十絕句  其五','趙蕃','宋','宋诗','song-poetry','','[]','桃李紛紛倚市門，豈知幽谷有佳人。',32,'全唐诗/poet.song.167000.json','["桃李紛紛倚市門，豈知幽谷有佳人。", "莫嗟玉粒終無偶，人物誰知溫太真。"]'),
('d5dbc8dc-1a31-4ddb-bac0-9d908b83a34e','梅花十絕句  其六','趙蕃','宋','宋诗','song-poetry','','[]','江上人家烟雨間，意行曾憶犯榛菅。',32,'全唐诗/poet.song.167000.json','["江上人家烟雨間，意行曾憶犯榛菅。", "祇今冷落人誰問，輸與白鷗相對閒。"]'),
('f2c6c108-2b43-4ac1-814b-b61da63a8e26','梅花十絕句  其七','趙蕃','宋','宋诗','song-poetry','','[]','雨薄梅花似有情，定應憐我太饑生。',32,'全唐诗/poet.song.167000.json','["雨薄梅花似有情，定應憐我太饑生。", "不同玉屑和朝露，且效夕餐收落英。"]'),
('fd513e5e-7284-4cc5-9a47-78ccd806b34a','梅花十絕句  其八','趙蕃','宋','宋诗','song-poetry','','[]','十里荆溪溪上梅，故人幾日寄詩來。',32,'全唐诗/poet.song.167000.json','["十里荆溪溪上梅，故人幾日寄詩來。", "相應載酒裴回次，憶我去年同此杯。"]'),
('4bb20969-113b-412e-81fc-c9d7168feebf','梅花十絕句  其九','趙蕃','宋','宋诗','song-poetry','','[]','梅花佳處是孤影，月落參橫真見之。',32,'全唐诗/poet.song.167000.json','["梅花佳處是孤影，月落參橫真見之。", "幾欲煩我爲摹寫，却愁才盡不能支。"]'),
('5a43bc8d-6177-4e17-89a8-5727f96463ab','梅花十絕句  其一○','趙蕃','宋','宋诗','song-poetry','','[]','松風亭下盛開時，曾辱蘇仙與賦詩。',32,'全唐诗/poet.song.167000.json','["松風亭下盛開時，曾辱蘇仙與賦詩。", "今日折花懷此老，端如嗅菊念東籬。"]'),
('2b75e8e4-4080-4300-bf41-ceda0f4c1e01','梅花絕句五首要明叔仲威同作  其一','趙蕃','宋','宋诗','song-poetry','','[]','起步寒梢百尺長，驟驚觸目盡琳琅。',32,'全唐诗/poet.song.167000.json','["起步寒梢百尺長，驟驚觸目盡琳琅。", "直疑霜月能爲幻，作意檻之還有香。"]'),
('be7b15b0-47c4-47b6-b2ee-46b354a55cf5','梅花絕句五首要明叔仲威同作  其二','趙蕃','宋','宋诗','song-poetry','','[]','誰能當此風霜面，政要渠儂鐵石心。',32,'全唐诗/poet.song.167000.json','["誰能當此風霜面，政要渠儂鐵石心。", "我亦苦吟羞不足，願從千古覓遺香。"]'),
('fc1fa976-ed44-49b8-9bb3-11e798f66edf','梅花絕句五首要明叔仲威同作  其三','趙蕃','宋','宋诗','song-poetry','','[]','木犀猶假菊爲裳，蘭也仍須紫作章。',32,'全唐诗/poet.song.167000.json','["木犀猶假菊爲裳，蘭也仍須紫作章。", "不似梅花最高潔，溫然全是玉之良。"]'),
('6e072f4e-9c2a-44e4-8c6f-1915ecdeb0be','梅花絕句五首要明叔仲威同作  其四','趙蕃','宋','宋诗','song-poetry','','[]','傍觀怪我底多病，不奈俗塵來敗人。',32,'全唐诗/poet.song.167000.json','["傍觀怪我底多病，不奈俗塵來敗人。", "故人寄我山中信，竹故歲寒梅告春。"]'),
('7da79dbb-e3e3-40d4-b938-29874c4baf04','梅花絕句五首要明叔仲威同作  其五','趙蕃','宋','宋诗','song-poetry','','[]','陳君胸中殊不麤，胡子臞甚語則腴。',32,'全唐诗/poet.song.167000.json','["陳君胸中殊不麤，胡子臞甚語則腴。", "梅花佳處我不識，付與二妙煩追摹。"]'),
('8f0c20e0-919b-404f-a412-caede2452f33','贈雲卿','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','迺翁里居時，曾上廬山牘。',96,'全唐诗/poet.song.167000.json','["迺翁里居時，曾上廬山牘。", "懷賢訪其孤，今值詞人牧。", "我嘗愛臨川，韓草刊於陸。", "爾侯古雅趣，與陸堪並躅。", "而翁詞翰佳，世亦思在目。", "爾其持此詩，勿憚拜僕僕。", "侯寧謂我易，未遂嗔爾瀆。", "峩峩兮西山，光燄那久伏。"]'),
('f7f1e581-9d18-4d42-8707-6e760dc2bb9f','祝游子泉劉叔通二家孤寡','趙蕃','宋','宋诗','song-poetry','','[]','貧賤可余置，死生無彼拋。',24,'全唐诗/poet.song.167000.json','["貧賤可余置，死生無彼拋。", "遺書曾不博，斗粟與枝巢。"]'),
('4e3aea12-4273-4b64-b4bc-366d239ad89e','跋韓澗泉詩','趙蕃','宋','宋诗','song-poetry','','[]','周漢歷歷上下秦，侯王將相史疊陳。',96,'全唐诗/poet.song.167000.json','["周漢歷歷上下秦，侯王將相史疊陳。", "辱斯榮斯仁不仁，桃源鹿門商山人。", "南磵遠孫澗之濱，所以三人入呻吟。", "桃源本是耕稼民，鹿門商山抱經綸。", "一世雖屈九原伸，所以絕筆於獲麟。", "我之擬賦非厥倫，感公語我淚沾巾。"]'),
('6bf785c5-be1c-40e8-bba3-4f39f57f88de','賦山居','趙蕃','宋','宋诗','song-poetry','','[]','何謂雪名寮，應同立積腰。',48,'全唐诗/poet.song.167000.json','["何謂雪名寮，應同立積腰。", "要爲膏以潤，不作晛而消。", "園小鋤斯食，書多復不枵。", "青雲附能顯，況乃白雲招。"]'),
('f6e0ed15-5220-4bad-ba24-31e66dd6b7ca','跋劉溪翁題韓府詩  其一','趙蕃','宋','宋诗','song-poetry','','[]','何人詠出韓家府，是我建陽劉叔通。',32,'全唐诗/poet.song.167000.json','["何人詠出韓家府，是我建陽劉叔通。", "盡道唐人工樂府，罕能褒貶似渠工。"]'),
('897acf79-4bc6-4d7b-97c5-9ea5e246f94b','跋劉溪翁題韓府詩  其二','趙蕃','宋','宋诗','song-poetry','','[]','誰詠韓家府，建陽劉叔通。',48,'全唐诗/poet.song.167000.json','["誰詠韓家府，建陽劉叔通。", "是爲聞以戒，斯可謂之風。", "妄矣彼侂胄，哀哉吾魏公。", "向來歌頌者，豈但劇秦雄。"]'),
('d5476ed0-35e9-4d27-84d8-23f95ccafc67','暖甚去綿衣','趙蕃','宋','宋诗','song-poetry','','[]','誰道江南春有寒，未經社日衣能單。',64,'全唐诗/poet.song.167000.json','["誰道江南春有寒，未經社日衣能單。", "桑麻過雨日夜長，桃李因風高下殘。", "舊說中州政如此，了知瘴氣不能干。", "天公似憫斯民病，故體淳熙詔令寬。"]'),
('e7230f24-db34-43e6-a65d-42876ce3b8ac','出郭','趙蕃','宋','宋诗','song-poetry','','[]','疎籬樹樹李花雪，野寺條條楊柳絲。',64,'全唐诗/poet.song.167000.json','["疎籬樹樹李花雪，野寺條條楊柳絲。", "春風收雨雨收後，白日變晴晴變時。", "有餘不足無盡景，截長補短何限詩。", "烟霞痼疾句成僻，老矣折肱真得醫。"]'),
('531f4372-0340-4007-b69b-c98c5d2a80dc','二月十日喜雨呈李純教授去非尉曹','趙蕃','宋','宋诗','song-poetry','','[]','滄浪一夜起鳴雷，雨陣因之續續來。',64,'全唐诗/poet.song.167000.json','["滄浪一夜起鳴雷，雨陣因之續續來。", "所病農家成久旱，未論花事有新開。", "書生狂妄常憂國，聖代飄零豈棄才。", "儒館尉曹俱國士，好爲詩賦詠康哉。"]'),
('2e5fc7a1-1195-4531-a1b8-94485e16c51a','詩一首','趙蕃','宋','宋诗','song-poetry','','[]','學語渾似學參禪，要保心傳與耳傳。',32,'全唐诗/poet.song.167000.json','["學語渾似學參禪，要保心傳與耳傳。", "秋菊春蘭寧易地，清風明月本同天。"]'),
('e7a31eec-4e87-461e-ba80-f95789c34a9d','松湖和曾文清公韵','趙蕃','宋','宋诗','song-poetry','','[]','有水可爲湖，栽松欲以呼。',48,'全唐诗/poet.song.167000.json','["有水可爲湖，栽松欲以呼。", "不貪魚鱉數，無取芰荷都。", "老杜論能擬，陶翁興不孤。", "風吟與雪釣，曾有畫圖無。"]'),
('9a026dfa-91fe-4e26-8767-cdba64c6ce95','成父居於普寧寺鐘樓之下闢以爲齋舊名坎止近易榜曰發深省衡州舅氏書之僕爲賦四小詩以發深省齋爲韵  其一','趙蕃','宋','宋诗','song-poetry','','[]','瓦礫何所知，說法猶咄咄。',24,'全唐诗/poet.song.167000.json','["瓦礫何所知，說法猶咄咄。", "況此空洞中，孰能無啟發。"]'),
('5f1863c3-d79b-4a74-afc3-182b78f4e869','成父居於普寧寺鐘樓之下闢以爲齋舊名坎止近易榜曰發深省衡州舅氏書之僕爲賦四小詩以發深省齋爲韵  其二','趙蕃','宋','宋诗','song-poetry','','[]','危岑百尺高，下有溪流深。',24,'全唐诗/poet.song.167000.json','["危岑百尺高，下有溪流深。", "高深日相激，合此無盡音。"]'),
('4754904a-622f-4590-bea2-f657172f1a90','成父居於普寧寺鐘樓之下闢以爲齋舊名坎止近易榜曰發深省衡州舅氏書之僕爲賦四小詩以發深省齋爲韵  其三','趙蕃','宋','宋诗','song-poetry','','[]','人行冥昧中，遇坎輒自省。',24,'全唐诗/poet.song.167000.json','["人行冥昧中，遇坎輒自省。", "聞是微妙音，安得忘所警。"]'),
('e2a02a8f-fd26-4da5-9955-c2c48c2c5d70','成父居於普寧寺鐘樓之下闢以爲齋舊名坎止近易榜曰發深省衡州舅氏書之僕爲賦四小詩以發深省齋爲韵  其四','趙蕃','宋','宋诗','song-poetry','','[]','我有嗜睡癖，衾枕長與偕。',24,'全唐诗/poet.song.167000.json','["我有嗜睡癖，衾枕長與偕。", "晨昏要無失，曷日住君齋。"]'),
('b01c2938-27ec-40d8-abb3-313e878b2d34','謝答嚴用韵送綠萼梅','趙蕃','宋','宋诗','song-poetry','','[]','瀟湘艮玉質，淺黛拂修眉。',24,'全唐诗/poet.song.167000.json','["瀟湘艮玉質，淺黛拂修眉。", "倚竹無人問，碧雲添一涯。"]'),
('d5efcadc-d162-4066-8d14-7f2fc35f5613','次韵何叔信二月蠟梅猶盛之作','趙蕃','宋','宋诗','song-poetry','','[]','江梅未醒如凍蠅，蠟梅先折能寧馨。',96,'全唐诗/poet.song.167000.json','["江梅未醒如凍蠅，蠟梅先折能寧馨。", "江梅既開瘦欲絕，蠟梅吐香方未歇。", "幾思覓句攄襟期，嫌如蔬筍傷肝脾。", "君詩與花辱俱見，却悔臨淵祇癡羨。", "君因此花詩再題，過讀快若垢得篦。", "從渠見者不著目，亦勝長安紛市鬻。"]'),
('1a89988b-1537-45cb-851f-685a5a901400','詠蠟梅','趙蕃','宋','宋诗','song-poetry','','[]','蠟梅初看十日前，黄深紫鮮香欲然。',128,'全唐诗/poet.song.167000.json','["蠟梅初看十日前，黄深紫鮮香欲然。", "要充銅瓶頓棐几，欲折罷折還加憐。", "蠟梅重看十日後，黄淡紫蔫香欲覆。", "是當雪砌與霜檐，欲開未開咸未就。", "山叟山居山徑荒，祇有竹樹參天長。", "浮花不省著老眼，此物未免搜枯腸。", "雪消霜熟冬行莫，凜日凝天應有數。", "蠟梅引破春風路，紅潔緗繁看樹樹。"]'),
('abbf3196-61a7-4f54-8928-33fe57303201','朱村道中','趙蕃','宋','宋诗','song-poetry','','[]','綠竹人家近小塘，暮秋村釀熟村場。',32,'全唐诗/poet.song.167000.json','["綠竹人家近小塘，暮秋村釀熟村場。", "我行甚亟忘休歇，孤負木犀來往香。"]'),
('c8ad739c-7875-48e0-b5b9-61224ee0610a','爲龍泉令趙舜徒題','趙蕃','宋','宋诗','song-poetry','','[]','誠能得初心，何必返初服。',24,'全唐诗/poet.song.167000.json','["誠能得初心，何必返初服。", "有以固中扃，不須防外逐。"]'),
('fd844ce6-4129-4722-a8ca-438c1465733d','獨行五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','所思終不見，渺渺政愁余。',24,'全唐诗/poet.song.167000.json','["所思終不見，渺渺政愁余。", "試向江頭釣，怕逢雙鯉魚。"]'),
('b9feaac9-0fd7-467c-ac58-6508c1f24d09','獨行五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','烹魚得素書，欲讀字半漫。',24,'全唐诗/poet.song.167000.json','["烹魚得素書，欲讀字半漫。", "上如說相思，下如祝加餐。"]'),
('99c2e956-e3c5-472a-87db-8592d5c685b8','初八日人事少閒命車出遊因以尋詩首訪滕王閣紛然屠沽思爲之敗已過東湖得孺子亭亭閣幽邃乃陳阜卿復作者一時詩板甚多擇數知名句錄之又東數步得孺子祠有像設及曾公衮書南豐所作祠堂記及沈持要重立歲月壁崩糞積殊異敬事迤邐避雨入總持寺謁澹臺子羽墓閲雷公祠墓有大篆立於其前祠有樂章無盡所作雨止絕南昌縣徑還艤舟之地作五詩','趙蕃','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','細雨微風湖上亭，柳深荷密競青青。',64,'全唐诗/poet.song.167000.json','["細雨微風湖上亭，柳深荷密競青青。", "生平漫與形神接，客裏孤游耳目醒。", "題詠紛紜幾詩板，畫圖零落半幽屏。", "像祠只在荒墩外，小復輿籃更一經。"]'),
('6f30678e-3906-4231-990d-e2a7093d86b6','過貴溪數里望月巖作','趙蕃','宋','宋诗','song-poetry','','[]','宿雨洗清秋，行行早放舟。',48,'全唐诗/poet.song.167000.json','["宿雨洗清秋，行行早放舟。", "團團正林杪，隠隠半巖幽。", "永謝妖蟆食，寧須玉斧修。", "少微并婺女，何事獨名州。"]'),
('b0abcb06-1b20-4de4-add0-f92cc345602e','公擇客於玉山簿尉之館忽有挽爲宜黄之行者公擇過余謀之作詩呈公擇兼簡簿尉','趙蕃','宋','宋诗','song-poetry','','[]','我裾未洗閩山土，君駕柴車過茅宇。',96,'全唐诗/poet.song.167000.json','["我裾未洗閩山土，君駕柴車過茅宇。", "相從僅作一夕留，冒雨衝風何自苦。", "如君人才豈終滯，瑚璉要爲清廟器。", "宜黄玉山俱作客，近湜何殊遠居易。", "我貧不得爲君謀，恐君遠適關我憂。", "作詩寄示三徑蔣，併簡平生顧曲周。"]'),
('a4557d6d-0646-49a1-b08d-093235f4d55d','聞邑中燈夕頗盛作詩呈子肅','趙蕃','宋','宋诗','song-poetry','','[]','晨起猶如欲雪天，晚來旋覺散晴煙。',64,'全唐诗/poet.song.167000.json','["晨起猶如欲雪天，晚來旋覺散晴煙。", "傳聞隘郭沸燈火，想見當筵雜管絃。", "鐵馬春冰期異日，賣薪買酒看今年。", "誰憐病叟寒窗底，獨擁殘灰整舊編。"]'),
('9c76898a-372c-41bf-8407-3f69616298e0','柳','趙蕃','宋','宋诗','song-poetry','','[]','松菊猶存歲晚期，五株柳樹復奚爲。',32,'全唐诗/poet.song.167000.json','["松菊猶存歲晚期，五株柳樹復奚爲。", "風流不在春風日，要看秋風摇落時。"]'),
('bf2fe195-e6e9-465b-b13a-27ca74256358','句  其一','趙蕃','宋','宋诗','song-poetry','','[]','王家碧香釀，劉尹建安詩。',12,'全唐诗/poet.song.167000.json','["王家碧香釀，劉尹建安詩。"]'),
('9109da59-7009-4020-961f-969c9690a7d8','句  其二','趙蕃','宋','宋诗','song-poetry','','[]','青雲道遠龍媒老，白雪詞高鬼膽寒。',16,'全唐诗/poet.song.167000.json','["青雲道遠龍媒老，白雪詞高鬼膽寒。"]'),
('954e6cb1-8553-45ba-8025-b2e25953753a','句','孫子肅','宋','宋诗','song-poetry','','[]','揖仙亭上觀秋漲，坐我吳江雲水鄉。',16,'全唐诗/poet.song.167000.json','["揖仙亭上觀秋漲，坐我吳江雲水鄉。"]'),
('9c4f24fb-331a-48b1-87d1-34857e72d565','句','孫子進','宋','宋诗','song-poetry','','[]','酒祿嗟予薄。',6,'全唐诗/poet.song.167000.json','["酒祿嗟予薄。"]'),
('b5ca4f80-94c1-494c-89fb-a8a3b7108923','句','某教授','宋','宋诗','song-poetry','','[]','作法孰爲凉。',6,'全唐诗/poet.song.167000.json','["作法孰爲凉。"]'),
('d40a49cd-76ab-4d1a-ac17-c16fd7225026','句','章少隠','宋','宋诗','song-poetry','','[]','片片梅花隨雨脫，渾疑春雪墮林梢。',16,'全唐诗/poet.song.167000.json','["片片梅花隨雨脫，渾疑春雪墮林梢。"]'),
('9c60b0bc-7233-4c0e-b6ce-f6688226d987','句','張王臣','宋','宋诗','song-poetry','','[]','半落半開梅好處，似無似有草生時。',16,'全唐诗/poet.song.168000.json','["半落半開梅好處，似無似有草生時。"]'),
('b9c3609a-4e55-42c3-9638-de000c04f20a','壽周益公  其一','李商叟','宋','宋诗','song-poetry','','[]','天佑熙朝世産賢，承平舊業至今傳。',64,'全唐诗/poet.song.168000.json','["天佑熙朝世産賢，承平舊業至今傳。", "萊公少避中元日，潞國同生丙午年。", "翰墨獨傳千古秘，聲名崛在二公先。", "功成野服平園去，要伴靈龜巢碧蓮。"]'),
('3ad5e0d6-e79d-4c18-9461-eeb3b9acc376','壽周益公  其二','李商叟','宋','宋诗','song-poetry','','[]','昨夜微雲概太清，銀河映带壽星明。',64,'全唐诗/poet.song.168000.json','["昨夜微雲概太清，銀河映带壽星明。", "祥開碧落中元節，人頌昇平上相生。", "天上異恩尊帝傅，洛陽好事寫耆英。", "長身獨樂園中老，疑是平園舊弟兄。"]'),
('1469e14f-6cb0-463c-bea4-1a2bfb15e7e5','壽周益公  其三','李商叟','宋','宋诗','song-poetry','','[]','袖中勳業拂雲煙，筆底文章響澗泉。',64,'全唐诗/poet.song.168000.json','["袖中勳業拂雲煙，筆底文章響澗泉。", "已是貴爲天下宰，不妨長作地行仙。", "蟻浮玉友秋初熟，鵲報銀河月正圓。", "滿引壽觴今夜看，相星重入太微垣。"]'),
('1f8bb325-3267-4e65-ac5e-f6746db86c28','疏山','李商叟','宋','宋诗','song-poetry','','[]','忙中安得此身閒，杖策西風自往還。',32,'全唐诗/poet.song.168000.json','["忙中安得此身閒，杖策西風自往還。", "今日已償雲水債，籃輿带雨下疏山。"]'),
('865cfad7-41e8-4b8f-ae82-435332b53421','壽周益公','李商叟','宋','宋诗','song-poetry','','[]','百年能幾見英豪，主聖臣賢未易遭。',64,'全唐诗/poet.song.168000.json','["百年能幾見英豪，主聖臣賢未易遭。", "□□□□新制度，宗臣當國大勳勞。", "三師告老恩榮備，□□藏書日月高。", "猶有治安貽百世，天教仙子見蟠桃。"]'),
('2d3b381d-1899-49b6-929b-1bbfe8137846','壽周少保','李商叟','宋','宋诗','song-poetry','','[]','皎皎銀河夜氣開，衆星重喜見三台。',64,'全唐诗/poet.song.168000.json','["皎皎銀河夜氣開，衆星重喜見三台。", "白麻詔自日邊下，紫府人從春際來。", "身被玉階新衮繡，手調金鼎舊鹽梅。", "鯫生頌德無他望，願與菁莪樂育材。"]'),
('011cc37a-a0f0-4ade-8ab4-9f89ca779227','壽吳宰  其一','李商叟','宋','宋诗','song-poetry','','[]','神仙風骨本巍峩，日角珠庭氣更和。',64,'全唐诗/poet.song.168000.json','["神仙風骨本巍峩，日角珠庭氣更和。", "絳縣丹顔長不老，灞城銅狄會重磨。", "風高鶴算三千遠，天闊鵬程九萬多。", "弱水蓬萊歸未晚，道山瀛館看先過。"]'),
('8d0564b6-f990-48ec-a76b-82999fd78067','壽吳宰  其二','李商叟','宋','宋诗','song-poetry','','[]','清規三尺信持平，何獨聲華百里稱。',64,'全唐诗/poet.song.168000.json','["清規三尺信持平，何獨聲華百里稱。", "易俗移風乃餘事，抑强扶弱見真能。", "翩翩氣岸真衝斗，湛湛心臺清映冰。", "爲問回資封壽母，不知今昔幾人曾。"]'),
('287d2e6e-400a-4217-aeb5-a4fe30bc581b','壽吳宰  其三','李商叟','宋','宋诗','song-poetry','','[]','向曉親闈共舉觴，老人星出翠巖傍。',64,'全唐诗/poet.song.168000.json','["向曉親闈共舉觴，老人星出翠巖傍。", "狻猊奩暖沉香裊，孔雀屏開紗蠟光。", "霜月正當圓此夕，江梅先已發奇祥。", "定知與國長無極，壽考祺維頌魯章。"]'),
('c23f26b0-17ea-4059-a206-a547dc952866','壽陳左相  其一','李商叟','宋','宋诗','song-poetry','','[]','龜蹲印勢接靈峰，傑出真賢盛代中。',64,'全唐诗/poet.song.168000.json','["龜蹲印勢接靈峰，傑出真賢盛代中。", "玉燕昔符仙夢異，金甌果覆相名雄。", "兩京政擬汾陽復，六計應論戶牖功。", "世合中興多喜色，邊頭時有捷書通。"]'),
('cec16d27-56fb-49cf-aba4-06f1e8dce31b','壽陳左相  其二','李商叟','宋','宋诗','song-poetry','','[]','祥風吹曉動簾旌，香裊狻猊幾縷青。',64,'全唐诗/poet.song.168000.json','["祥風吹曉動簾旌，香裊狻猊幾縷青。", "佳氣遠浮黄閣滿，老人高拱紫微明。", "月將圓影來華席，梅放新香入寶觥。", "千歲定知仁者壽，喜看無汗玉枝橫。"]'),
('61214b32-21f5-428d-a035-38b22f44e231','壽陳左相  其三','李商叟','宋','宋诗','song-poetry','','[]','萬方名教頼薰陶，相國由來德業高。',64,'全唐诗/poet.song.168000.json','["萬方名教頼薰陶，相國由來德業高。", "固有才華亞韓柳，豈惟功業並蕭曹。", "恩逢圖像登麟閣，綵戲文鳴列鳳毛。", "可是平生耐官職，不容車馬閙庭臯。"]'),
('6611821a-569b-4e60-b551-7d0f51d417b1','壽陳左相  其四','李商叟','宋','宋诗','song-poetry','','[]','愚生自幼感磨鎸，才拙慚非宅相賢。',64,'全唐诗/poet.song.168000.json','["愚生自幼感磨鎸，才拙慚非宅相賢。", "甘遯山村承素萼，濫隨軒冕厠官聯。", "困魚止箔今誰念，倦鵲依巢只自憐。", "拜壽不辭千里遠，欲陪珠履侍陶甄。"]'),
('e5fb9565-6be3-48e7-814d-1f9923b4a24e','壽時相  其一','李商叟','宋','宋诗','song-poetry','','[]','龍盤虎踞王金陵，傑出天人致太平。',64,'全唐诗/poet.song.168000.json','["龍盤虎踞王金陵，傑出天人致太平。", "千載精神真會聚，一朝文物益彰明。", "扶持直使乾坤正，指顧能令海岱清。", "二紀同□□□□，□□□□□肥民。"]'),
('ef97fb4f-8db6-4106-bd64-60d0b6e0e860','壽時相  其二','李商叟','宋','宋诗','song-poetry','','[]','農家鼓舞總安田，億兆欣逢大有年。',64,'全唐诗/poet.song.168000.json','["農家鼓舞總安田，億兆欣逢大有年。", "道路漁樵爭擊壤，江鄉薪米不論錢。", "含淳詠德聲盈耳，易俗移風事格天。", "守郡深漸無報稱，但陪民社感陶甄。"]'),
('70605d17-8533-4e48-99f3-17f0c16a412e','壽韓尚書  其一','李商叟','宋','宋诗','song-poetry','','[]','一時冠冕競加鞭，誰似先生晚節賢。',64,'全唐诗/poet.song.168000.json','["一時冠冕競加鞭，誰似先生晚節賢。", "鬢雪自因憂國選，顔丹端爲省塵緣。", "山林喜近生申日，海宇爭期致主年。", "聞道相看起安石，寧容高卧樂詩禪。"]'),
('4c2c376a-7efc-4b10-9079-c7c24fd82a9b','壽韓尚書  其二','李商叟','宋','宋诗','song-poetry','','[]','靈峰高映玉溪光，花草時薰知見香。',64,'全唐诗/poet.song.168000.json','["靈峰高映玉溪光，花草時薰知見香。", "未用胡麻金椀飯，且浮昌歜碧霞觴。", "松櫺照北塵埃遠，澗水流南氣象長。", "舞鶴獨知千歲永，風雲猶欲會明良。"]'),
('746922b3-99e4-43d1-8d81-388ab964c166','壽辛太尉','李商叟','宋','宋诗','song-poetry','','[]','昭代群龍用，名家奕世昌。',288,'全唐诗/poet.song.168000.json','["昭代群龍用，名家奕世昌。", "儲精生輔佐，挺秀誕忠良。", "郁郁充閭瑞，熒熒照室祥。", "蓮花雄址峻，竹箭慶源長。", "碩德宜廊廟，英材命棟梁。", "公清凌灝氣，嚴肅厲秋霜。", "寶運符千載，威名贍八荒。", "量陂吞玉海，言派瀉銀潢。", "功業彝章顯，謀猷棣萼芳。", "檢身金井潔，落節翠螭驤。", "列郡依仁牧，千英服智囊。", "精忠裨主聖，膏澤致時康。", "鄧禹重興漢，汾陽再造唐。", "公心平國是，勠力振朝綱。", "斧鉞安南服，威稜振北疆。", "溫恭謙節著，仁惠德風揚。", "鸑鷟金昆盛，貔貅虎旅强。", "望風辭印綬，當路悚豺狼。", "電掃除妖孽，雷驅息叛亡。", "一心仁以厚，五福壽而臧。", "論議留青簡，勳庸紀太常。", "鴻恩非易報，盛德固難忘。", "便合持樞極，那容著海鄉。", "莊椿祈不老，遼鶴竚來翔。"]'),
('3735eadb-5cba-4a56-9fa8-2d26cfda7637','壽傅憲','李商叟','宋','宋诗','song-poetry','','[]','籍甚河陽地，江山秀色連。',288,'全唐诗/poet.song.168000.json','["籍甚河陽地，江山秀色連。", "家聲自巖野，帝夢協台躔。", "彝鼎功鎸勒，衣冠喜接聯。", "相門當出相，賢父又生賢。", "歲必爲霖雨，舟宜濟大川。", "渥洼龍種異，丹穴鳳毛鮮。", "擊甕知奇略，惜陰起妙年。", "五車胸磊磊，萬卷腹便便。", "韓柳堪同步，班揚可並肩。", "千言看落紙，一掃快飛煙。", "未說才如錦，端知□似椽。", "斯文當振耀，吾道不沉綿。", "揮麈談噴麝，書麟思湧泉。", "鴒原真孝友，鴈塔壓儒先。", "聲價機雲上，風流王謝邊。", "兩科能俯拾，百行更兼全。", "當代江都相，今時司馬遷。", "紬書蓬館盛，主爵粉闈專。", "致主心公正，經邦力勉旃。", "嘉謀辰必告，宣席夜應前。", "遽向急流退，猶爲郡紱牽。", "道州迎竹馬，漳浦示蒲鞭。", "一節方持遠，十行俄促還。", "雲霄知有路，雨露正無偏。"]'),
('3870193c-1789-4df8-8169-e1ff3ff6e456','句','李商叟','宋','宋诗','song-poetry','','[]','初日放晨光。',6,'全唐诗/poet.song.168000.json','["初日放晨光。"]'),
('64dec88f-7ce4-41c0-8775-50dd7e595aa4','登舟客有誦杜詩春水船如天上坐之句因成一絕','徐恢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','暖風收拾乍晴烟，春水西湖並半船。',32,'全唐诗/poet.song.168000.json','["暖風收拾乍晴烟，春水西湖並半船。", "若使杜陵輕著眼，應言直下是青天。"]'),
('c38e38a0-4377-4c34-aef2-958e671abd44','讀劉賓客詩再賦','徐恢','宋','宋诗','song-poetry','','[]','山泉何地發輕雷，直使煙雲對面開。',32,'全唐诗/poet.song.168000.json','["山泉何地發輕雷，直使煙雲對面開。", "可惜隠侯無妙語，却教詩自雍州來。"]'),
('ffc3b79b-c0c7-4097-9196-f9d71071c28c','余夜坐必看東湖詩心悟神會非它人所與知也比來老態併見殊覺少味感而成詩','徐恢','宋','宋诗','song-poetry','','[]','清絕東湖舊看詩，夜窗風味許誰知。',32,'全唐诗/poet.song.168000.json','["清絕東湖舊看詩，夜窗風味許誰知。", "眼花頭白今憔悴，不似向來燈下時。"]'),
('7b1be233-914b-41ac-8b4b-818836dbcdaf','蒙劉元中數示東坡詩','徐恢','宋','宋诗','song-poetry','','[]','無邪公文天所贊，汩汩詞源倒河漢。',144,'全唐诗/poet.song.168000.json','["無邪公文天所贊，汩汩詞源倒河漢。", "一篇新出紙爲貴，萬國爭傳金可換。", "晚節投荒無芥蔕，畢景著書自娛玩。", "天之所寶雷電取，渠不愛惜風雨散。", "兩河漕僚真好事，五筦遺文盡堆案。", "似聞傾蓋劇推許，親以削牘定真贋。", "分傳餉我枉銀鈎，貧室驟驚滿珠貫。", "無坫共推玉界尺，爭求當置鐵門限。", "世人不識蔡伯喈，欲問圖書覓王粲。"]'),
('ba6fb055-5dce-4fe3-826c-957a54e501b6','臨川洪守游南湖命予賦詩','徐恢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','芙蓉堂前春水綠，芙蓉堂後春花開。',256,'全唐诗/poet.song.168000.json','["芙蓉堂前春水綠，芙蓉堂後春花開。", "芙蓉堂中醉歌舞，芙蓉堂下車如雷。", "輕舟弄水買一笑，遊人競逐牆陰來。", "浪痕不受塵滓涴，東風吹入黄金盃。", "鞦韆欲上綵繩穩，老翁稚子連聲催。", "遨頭春思濃似酒，劇飲誰能問升斗。", "博山香軟珠簾低，坐客請行時被肘。", "觥籌交錯興未已，更著山殽并野蔌。", "歸來門巷影散亂，舍南舍北黄埃走。", "輕衫短帽亦不惡，追歡豈落醉翁後。", "小姬顧盼揚秋波，十十五五細馬馱。", "紅旗夾道映斜日，金釵墜處肩相摩。", "旁觀定自雙眼飽，但見兩臉生微渦。", "從今湖上愈清好，纖腰長袖成奔梭。", "冥搜付與紙上語，朱顔爲我商聲歌。", "願公歸侍玉皇側，更向西湖弄春色。"]'),
('4de6a909-8d2c-44d9-bae1-d1b3ecd85f7f','寄題趙昌父發深省齋','徐恢','宋','宋诗','song-poetry','','[]','寄語前身杜拾遺，夢回深省不須疑。',32,'全唐诗/poet.song.168000.json','["寄語前身杜拾遺，夢回深省不須疑。", "鐘聲薦處渾閑事，薦起鐘聲未起時。"]'),
('2e532cc4-017f-48fd-a189-033850987515','紅梅','徐恢','宋','宋诗','song-poetry','','[]','江梅閑盡臘梅稀，又是紅梅占曉枝。',32,'全唐诗/poet.song.168000.json','["江梅閑盡臘梅稀，又是紅梅占曉枝。", "却憶東坡詩上語，淡粧濃抹總相宜。"]'),
('af023037-e58d-4f32-a299-1306119a8ff5','會故人二首  其一','徐恢','宋','宋诗','song-poetry','','[]','江南江北每淹留，懶聽寒蟬噪暮秋。',64,'全唐诗/poet.song.168000.json','["江南江北每淹留，懶聽寒蟬噪暮秋。", "句裏豈能窺鮑謝，暗中聊解識曹劉。", "清如老鶴翻秋露，快似神駒略九州。", "只恐蛟龍得雲雨，未容蓮社與僧遊。"]'),
('b43f6929-779e-424c-a5d6-8e7f71941acf','會故人二首  其二','徐恢','宋','宋诗','song-poetry','','[]','毛郎才湧似潮頭，莫比寒蟲泣夜秋。',64,'全唐诗/poet.song.168000.json','["毛郎才湧似潮頭，莫比寒蟲泣夜秋。", "要上蘭臺揖班馬，不聯石鼎玩侯劉。", "定知有道能醫國，稍喜談禪勘趙州。", "顧我雖無陶謝手，尚堪述作與同遊。"]'),
('1066d12f-bb93-4852-91b5-8339105957be','三賢堂','徐恢','宋','宋诗','song-poetry','','[]','六井猶存記，三賢尚有堂。',48,'全唐诗/poet.song.168000.json','["六井猶存記，三賢尚有堂。", "地連金色界，廟接水仙王。", "市井空陳迹，杉松只舊行。", "唯公識真意，此處酒難忘。"]'),
('b5de6ffd-4580-4a3e-bbb4-694edac98134','望西興偶成','徐恢','宋','宋诗','song-poetry','','[]','痕痕雪壁隠疎烟，正是西興落日邊。',32,'全唐诗/poet.song.168000.json','["痕痕雪壁隠疎烟，正是西興落日邊。", "潮水退黄山送碧，問人還有渡江船。"]'),
('60c42530-e3c0-4189-ae4b-bc0cd6dbaed5','遊處州石門洞賦長句二十韵','徐恢','宋','宋诗','song-poetry','','[]','我聞石洞今幾年，一朝來繫秋風船。',320,'全唐诗/poet.song.168000.json','["我聞石洞今幾年，一朝來繫秋風船。", "大船膖肛小船遠，漁舟替涉幽澗泉。", "拖舟上上抵砂礫，更與略彴相夤緣。", "黄冠道士衣翩翩，殷勤爲我臨澗邊。", "相逢一笑挽登岸，忽見珍館羅修椽。", "謝公舊隠無處問，洗眼但看山中篇。", "佳哉南國典刑在，大羹遺味朱絲絃。", "當是發興豈神助，兩峰對面攙青天。", "主人掉頭謂不爾，尚能飛瀑千仞懸。", "杖筇西下取微徑，其境過清神凜然。", "初疑窮冬藴積雪，驚飈擁下陰崖巔。", "又疑冰綃掛林杪，薄暮縹緲摇輕煙。", "蔽空乍覺微雨集，墮地復作跳珠圓。", "謝公得爾句偏好，我今其忍相棄捐。", "山奇水怪世莫測，神龍定自藏九淵。", "龍兮汝能水下土，胡爲懶惰貪晝眠。", "自淮以北皆故壤，犬羊爛熳疆域羶。", "挽河莫假壯士力，奔雷走電一洗湔。", "我詩雖乏漫郎語，强顔猶可供磨鎸。", "爲君他日落此筆，千秋萬歲令人傳。"]'),
('80c1fd3a-61e9-4c7a-86b2-78649d1df830','燈夕多爲城中之約因賦此篇','徐恢','宋','宋诗','song-poetry','','[]','春來懶倦半相仍，全似諸方怕事僧。',64,'全唐诗/poet.song.168000.json','["春來懶倦半相仍，全似諸方怕事僧。", "薄有篇章堪對酒，畧無情緒要觀燈。", "湖山帝里夢頻往，泉石吳鄉歸未能。", "四海平生幾兄弟，箇般滋味更誰曾。"]'),
('9b87dd29-dce5-473e-aeab-63679442a119','漁父','游次公','宋','宋诗','song-poetry','','[]','竹裏茅茨傍小溪，粼粼白石護漁磯。',32,'全唐诗/poet.song.168000.json','["竹裏茅茨傍小溪，粼粼白石護漁磯。", "想應日日來垂釣，石上蓑衣不带歸。"]'),
('4ea012b3-2e15-4062-817e-50146e20b966','早起','游次公','宋','宋诗','song-poetry','','[]','銀牀露濕井華寒，自挈銅瓶汲水還。',32,'全唐诗/poet.song.168000.json','["銀牀露濕井華寒，自挈銅瓶汲水還。", "宿雨未乾池館靜，凉蟬猶在棟梁間。"]'),
('529124d7-b9fc-4f1f-becf-f161f9565a7b','耒陽道中','游次公','宋','宋诗','song-poetry','','[]','山頭磴石危梯險，山下荒田野草悲。',32,'全唐诗/poet.song.168000.json','["山頭磴石危梯險，山下荒田野草悲。", "更著秋風吹兩鬢，不消幾日盡成絲。"]'),
('b985271d-9c1a-4fdc-9a8b-ba8dabf51bdc','畫虎','游次公','宋','宋诗','song-poetry','','[]','平生射虎裴將軍，馬獰如龍弓百鈞。',128,'全唐诗/poet.song.168000.json','["平生射虎裴將軍，馬獰如龍弓百鈞。", "手撚白羽旁無人，注虎使虎不敢奔。", "須臾叢薄爛斑出，人馬不知俱辟易。", "矢如蓬蒿弓減力，將軍得歸幾敗績。", "徐行爪牙元不露，眈眈垂頭若微顧。", "尾翦霜風林葉飛，倏忽山頭日光暮。", "包家畫出真於菟，我尚不敢編其鬚。", "昔人作詩譏畫圖，吁嗟畫圖今亦無。"]'),
('7f7d2510-6a92-4f7f-adb1-69432ce8530d','秋蟲','游次公','宋','宋诗','song-poetry','','[]','一氣動芒沕，鳴蟲應清商。',96,'全唐诗/poet.song.168000.json','["一氣動芒沕，鳴蟲應清商。", "天機發天籟，託彼蛩與螿。", "凄然起秋聲，感我徹肺腸。", "幽思不自識，遠興來何方。", "至音有如此，始晤韶與章。", "風霜入凄斷，月露皆悲凉。", "天地有聲樂，呻吟委寒荒。", "爾非絲竹奏，那得登君堂。"]'),
('4684c309-e4fa-482e-97af-70fe568cef58','湖州題顔魯公祠堂','童敏德','宋','宋诗','song-poetry','','[]','挂帆一縱疾於鳥，長興夜發吳興曉。',128,'全唐诗/poet.song.168000.json','["挂帆一縱疾於鳥，長興夜發吳興曉。", "杖黎上訪魯公祠，一見目明心皦皦。", "未說邦人懷使君，且爲前古惜忠臣。", "德宗更用盧杞相，出當斯位誠艱辛。", "生逆龍鱗死虎口，要與乃兄同不朽。", "狂童希烈何足罪，姦邪嫉忠假渠手。", "乃知成仁或殺身，保身不必皆哲人。", "此公安得世復有，洗空凡馬須麒麟。"]'),
('07c85bf5-5c20-471a-8a67-fde8812ab24e','題新繁句氏盤溪  其一','句昌泰','宋','宋诗','song-poetry','','[]','黄塵沒車轂，平地得林丘。',48,'全唐诗/poet.song.168000.json','["黄塵沒車轂，平地得林丘。", "花木風光早，陂池煙雨秋。", "不彈長劍鋏，甘賦大刀頭。", "九軌利名痼，逢君應少瘳。"]'),
('32102195-7488-4082-9a7e-de79d4b916d3','題新繁句氏盤溪  其二','句昌泰','宋','宋诗','song-poetry','','[]','從俗鮮所得，九牛中一毛。',48,'全唐诗/poet.song.168000.json','["從俗鮮所得，九牛中一毛。", "强牽麋鹿性，要學豹龍韜。", "野服顔常好，晴窗首自蚤。", "向來誤應聘，塵土污吾袍。"]'),
('b8004b47-bf40-4c7e-848f-b191cae64c47','題新繁句氏盤溪  其三','句昌泰','宋','宋诗','song-poetry','','[]','客至輒命酌，爲言花已開。',48,'全唐诗/poet.song.168000.json','["客至輒命酌，爲言花已開。", "青山長委髻，白骨舊生苔。", "不飲固癡絕，能詩宜數來。", "頗憂明日雨，紅紫落成堆。"]'),
('2141cd7c-ad6a-4af5-a9e2-a284de4cf678','題新繁句氏盤溪  其四','句昌泰','宋','宋诗','song-poetry','','[]','勝簪不肯黑，浮頰故能紅。',48,'全唐诗/poet.song.168000.json','["勝簪不肯黑，浮頰故能紅。", "心寄塵埃外，春歸杖履中。", "徑松青謖謖，庭草碧茸茸。", "無術繫白日，年光如轉蓬。"]'),
('a4b23fb6-4361-4d10-b3d0-c883a53ecc02','句','洪邃','宋','宋诗','song-poetry','','[]','重重山勢荆門去，衮衮江流蜀道來。',16,'全唐诗/poet.song.168000.json','["重重山勢荆門去，衮衮江流蜀道來。"]'),
('50fa85de-c273-4197-94ce-85dd01fca980','敘州','史申之','宋','宋诗','song-poetry','','[]','東樓特傑少陵詩，鎖江頡頏涪翁題。',32,'全唐诗/poet.song.168000.json','["東樓特傑少陵詩，鎖江頡頏涪翁題。", "兩翁詩陣屹相向，千載名與江山齊。"]'),
('907d6355-59c2-41c2-9cd1-fab1017f8181','題錢過庭梅花圖','釋惟謹','宋','宋诗','song-poetry','','[]','已把神傳畫譜，又看格在詩評。',28,'全唐诗/poet.song.168000.json','["已把神傳畫譜，又看格在詩評。", "月落難尋清夢，雪空乃見高情。"]'),
('3788f785-375f-4a8e-99e7-5bea125fe2b8','舟泊括蒼溪口','釋惟謹','宋','宋诗','song-poetry','','[]','茅店在山下，檥舟茅店邊。',48,'全唐诗/poet.song.168000.json','["茅店在山下，檥舟茅店邊。", "鐘鳴何處寺，日落滿溪船。", "欹枕雁初到，離家月又圓。", "向來曾過此，夜泊石門前。"]'),
('463c6762-2101-4efd-8f55-79e1c616dbbd','答崑山李明府','釋惟謹','宋','宋诗','song-poetry','','[]','殘雲微綠一簾深，風送弦歌出晝陰。',64,'全唐诗/poet.song.168000.json','["殘雲微綠一簾深，風送弦歌出晝陰。", "山近烟霞多變態，官清猿鶴亦歸心。", "錦囊剩有新詩在，庭戶何妨茂草侵。", "元亮曾爲蓮社客，許令飛舄遠相尋。"]'),
('3dfb32d9-ee94-4682-b0df-6ce1486142e0','詩二首  其一','釋惟謹','宋','宋诗','song-poetry','','[]','年方十五去遊方，終日修行學道忙。',32,'全唐诗/poet.song.168000.json','["年方十五去遊方，終日修行學道忙。", "說我半生辛苦事，石人應下淚千行。"]'),
('4582a116-6dd7-40ae-b71d-95403ec51097','詩二首  其二','釋惟謹','宋','宋诗','song-poetry','','[]','看了青燈夢不成，東風混雪落寒聲。',32,'全唐诗/poet.song.168000.json','["看了青燈夢不成，東風混雪落寒聲。", "半生客裏無窮恨，告訴梅花說到明。"]'),
('cdc99727-e0ae-44d0-bf63-8d919f853513','句','釋惟謹','宋','宋诗','song-poetry','','[]','滿徑露漙黄般若，戛簷風裊翠真如。',16,'全唐诗/poet.song.168000.json','["滿徑露漙黄般若，戛簷風裊翠真如。"]'),
('203c2a56-db17-415f-998c-6b892b60e0c1','寒食野步','釋文坦','宋','宋诗','song-poetry','','[]','寒食出重闉，郊原忽愴神。',48,'全唐诗/poet.song.168000.json','["寒食出重闉，郊原忽愴神。", "人悲新舊塚，花落古今春。", "名位空標史，賢愚盡委塵。", "斜陽回首處，壟木噪鴉頻。"]'),
('54816eb9-5574-450c-9efa-1d5812d99074','餞友宰丹陽','万俟紹之','宋','宋诗','song-poetry','','[]','昔曾覘吏事，不是小規模。',48,'全唐诗/poet.song.168000.json','["昔曾覘吏事，不是小規模。", "萬象胸中布，全牛眼底無。", "迅雷推敏速，片月對清孤。", "鐵甕城邊邑，今番凋瘵蘇。"]'),
('79e33f60-ecd6-4e17-abaa-05fb38e32424','傑閣','万俟紹之','宋','宋诗','song-poetry','','[]','傑閣倚空闊，身高眇萬山。',48,'全唐诗/poet.song.168000.json','["傑閣倚空闊，身高眇萬山。", "棟雲飛縹緲，簷鐵閙虛閑。", "地步氛埃外，天威咫尺間。", "好風吹笑語，餘響落人寰。"]'),
('9763e897-9a19-4d5d-8d90-6e14273b17d5','方水滴子','万俟紹之','宋','宋诗','song-poetry','','[]','質由良冶就，心向主人傾。',48,'全唐诗/poet.song.168000.json','["質由良冶就，心向主人傾。", "外倣片金制，中藏勺水清。", "兔毫芳露染，龍尾濕雲生。", "終令雙眸炯，曾窺妙女成。"]'),
('a9ee913b-ccb5-4999-bda5-0af7e71ef85b','陸墓寺','万俟紹之','宋','宋诗','song-poetry','','[]','距城纔五里，野景自蕭然。',48,'全唐诗/poet.song.168000.json','["距城纔五里，野景自蕭然。", "塘水清環寺，窯烟黑翳天。", "市多沽酒旅，橋列賣魚船。", "欲酹宣公塚，淵陵幾變遷。"]'),
('f8b4e132-4d3a-4dfb-8c5b-5b04be464c33','旅中','万俟紹之','宋','宋诗','song-poetry','','[]','僦樓如斗大，不與嬾相便。',48,'全唐诗/poet.song.168000.json','["僦樓如斗大，不與嬾相便。", "杯酒常妨飯，瓶花亦費錢。", "狂蹤依客燕，短夢怯啼鵑。", "欲去老丘壑，無謀可買田。"]'),
('79583c82-ba50-45e4-b603-244c67f681d4','次郊行韵','万俟紹之','宋','宋诗','song-poetry','','[]','蝶怕花殘舞更忙，隨風柳絮鬭輕狂。',64,'全唐诗/poet.song.168000.json','["蝶怕花殘舞更忙，隨風柳絮鬭輕狂。", "尋芳客去馬蹄倦，試酒人歸衣汗香。", "過雨千林舒翠葉，護田一水露針秧。", "留春無計空惆悵，信手敲棋語夜長。"]'),
('de4434ec-5fb3-4899-975c-0113fe53d8a8','送觀書記住山','万俟紹之','宋','宋诗','song-poetry','','[]','本是儒流學釋流，枝藤所寓即清幽。',64,'全唐诗/poet.song.168000.json','["本是儒流學釋流，枝藤所寓即清幽。", "西山不用一錢買，北磵空爲百計留。", "禪向靜中能妙覺，詩于閑處得冥搜。", "秋風芳蒂甜如蜜，許我溪頭繫小舟。"]'),
('55b532a4-6345-49ff-908f-c9f62590633e','游天平山白雲泉','万俟紹之','宋','宋诗','song-poetry','','[]','踏開松徑幾層陰，一勺寒泉洗客心。',64,'全唐诗/poet.song.168000.json','["踏開松徑幾層陰，一勺寒泉洗客心。", "高處天風吹面泠，險邊石磴警人深。", "祠尊范像香煙潤，碑刻唐詩蘚暈侵。", "鳥道更通幽絕處，恨無足力可登臨。"]'),
('88050e8f-5fcf-4b8d-9e2e-6f17460cc748','游建康碧瑶洞','万俟紹之','宋','宋诗','song-poetry','','[]','洞口篔簹幾百竿，洞深襟袂易生寒。',64,'全唐诗/poet.song.168000.json','["洞口篔簹幾百竿，洞深襟袂易生寒。", "鹿眠桃塢春常在，鶴唳松梢夜未闌。", "瓦鼎香騰秋霧薄，石盤棋撒曉星殘。", "道人許換塵凡骨，同向壇前說煉丹。"]'),
('d78370f1-b831-4bf5-8e55-df7efd4b9016','謁曾祖提刑墓','万俟紹之','宋','宋诗','song-poetry','','[]','簪纓輝映紹興間，身後清貧陋巷顔。',64,'全唐诗/poet.song.168000.json','["簪纓輝映紹興間，身後清貧陋巷顔。", "猶有雲仍在西浙，遠思霜露拜南山。", "祖風三世未應息，天道百年今好還。", "欲去欲留松下路，藤花染淚路斕斑。"]'),
('41619ddb-b506-43c2-ac96-151b92893b18','席上次韵','万俟紹之','宋','宋诗','song-poetry','','[]','東風幾度客京華，今日飄零天一涯。',64,'全唐诗/poet.song.168000.json','["東風幾度客京華，今日飄零天一涯。", "無奈剛腸欺竹葉，幸因清坐對梅花。", "更長不覺銷銀燭，寒峭從教透碧紗。", "語到前朝行樂處，綠楊深院是誰家。"]'),
('fca61d5a-3944-403a-a327-7c0309473e81','呈印主學','万俟紹之','宋','宋诗','song-poetry','','[]','君世通城我石城，不堪兩處總烽塵。',64,'全唐诗/poet.song.168000.json','["君世通城我石城，不堪兩處總烽塵。", "向時未快披雲願，今日同爲避地人。", "襟宇光風無盡藏，杯盤夜雨有餘春。", "喚回十載槐黄夢，欲借靈槎去問津。"]'),
('ea22c8d8-252d-4c85-b1a9-de1cc0b88fda','婢態','万俟紹之','宋','宋诗','song-poetry','','[]','纔入園中便折花，厨頭坐語是生涯。',64,'全唐诗/poet.song.168000.json','["纔入園中便折花，厨頭坐語是生涯。", "不時掐數週年限，每事誇稱舊主家。", "遷怒故將甌碗擲，傚矉剛借粉脂搽。", "隔屏竊聽賓朋語，汲汲訛傳又妄加。"]'),
('c9504ed8-c1c9-4bb8-87a7-9a65219812a7','次新竹韵','万俟紹之','宋','宋诗','song-poetry','','[]','籜粉飄零幹拂簷，午陰比似舊時添。',64,'全唐诗/poet.song.168000.json','["籜粉飄零幹拂簷，午陰比似舊時添。", "棲留薄霧生秋意，勾引清風滌夏炎。", "弱質自同詩骨瘦，新竿也學舞腰纖。", "丁寧養就化龍杖，休劈輕絲織繡簾。"]'),
('ff184268-e7e9-4436-b701-7b5e8ae4436c','訪新城宰','万俟紹之','宋','宋诗','song-poetry','','[]','野花香細綠陰成，風著征衫暑尚輕。',64,'全唐诗/poet.song.168000.json','["野花香細綠陰成，風著征衫暑尚輕。", "流水有聲如學語，亂山無數不知名。", "柘林葉盡蠶初熟，麥隴人行雉不驚。", "少駐籃輿聊問俗，兒童亦說長官清。"]'),
('7e58875d-fe81-4b24-af8f-3140c9afbecb','餞常熟宰  其一','万俟紹之','宋','宋诗','song-poetry','','[]','籠鶴歸來到北關，玉墀春裏趣朝班。',32,'全唐诗/poet.song.168000.json','["籠鶴歸來到北關，玉墀春裏趣朝班。", "九重定問琴川事，爲奏通川一渡閒。"]'),
('2881bb54-7a57-4fab-bc34-c29ef132ef3d','餞常熟宰  其二','万俟紹之','宋','宋诗','song-poetry','','[]','多幸三年依德字，喜無一事到公庭。',32,'全唐诗/poet.song.168000.json','["多幸三年依德字，喜無一事到公庭。", "庭前柳是公遺愛，去後相看眼更青。"]'),
('3f4f2fa0-0fa2-49e6-bc5b-40d16125ab86','金陵郊行','万俟紹之','宋','宋诗','song-poetry','','[]','快提金勒走郊原，拂面東風醒醉魂。',32,'全唐诗/poet.song.168000.json','["快提金勒走郊原，拂面東風醒醉魂。", "好景流連天易晚，來朝更過杏花村。"]'),
('affe36a0-673c-4728-97d4-fc4ef77d8644','冬閨怨','万俟紹之','宋','宋诗','song-poetry','','[]','塑出獅毬對畫闌，笑呼女伴傍前看。',32,'全唐诗/poet.song.168000.json','["塑出獅毬對畫闌，笑呼女伴傍前看。", "宮鞋濕透猶堪著，未抵空閨繡被寒。"]'),
('96c77cf7-7a23-4c76-9d00-d37b38aa8f72','寄永興窣兄  其一','万俟紹之','宋','宋诗','song-poetry','','[]','相閥崢嶸南渡初，萬事遺緒要人扶。',32,'全唐诗/poet.song.168000.json','["相閥崢嶸南渡初，萬事遺緒要人扶。", "從知物理終無否，棠笏于今屬魏謨。"]'),
('8aad0539-bed9-4c2e-85d3-7aa1e509d7f5','寄永興窣兄  其二','万俟紹之','宋','宋诗','song-poetry','','[]','憶昔京華聚首時，大兄常念阿連癡。',32,'全唐诗/poet.song.168000.json','["憶昔京華聚首時，大兄常念阿連癡。", "別來相望天涯遠，長誦對床風雨詩。"]'),
('e1f60660-ac84-494e-a643-1530f941e1c3','題扇面','万俟紹之','宋','宋诗','song-poetry','','[]','起晚慵粧立小樓，杜鵑聲裏萬紅休。',32,'全唐诗/poet.song.168000.json','["起晚慵粧立小樓，杜鵑聲裏萬紅休。", "儂愁未逐春酲解，飛盡楊花不舉頭。"]'),
('4c137bef-d084-48b0-911f-7c2c2aeb19d5','元夕','万俟紹之','宋','宋诗','song-poetry','','[]','小小茅居傍野橋，青燈一點度元宵。',64,'全唐诗/poet.song.168000.json','["小小茅居傍野橋，青燈一點度元宵。", "新詩多在景中得，宿酒都從睡裏消。", "繞舍菜滋春後雨，過門船趁晚來潮。", "休嫌不住繁華境，最喜親朋近可邀。"]'),
('db60518d-77a1-4fc4-bd2f-65592cbb06cd','巾山曉望','岳甫','宋','宋诗','song-poetry','','[]','角逐東來幾巨鼇，化爲奠位兩山高。',64,'全唐诗/poet.song.168000.json','["角逐東來幾巨鼇，化爲奠位兩山高。", "江楓作意紅千疊，野水何心綠一遭。", "露洗松巔沈曉籟，霜明天際察秋毫。", "會須竹院求餘地，歲晚安閒讀楚騷。"]'),
('b0bbdb07-68c3-4136-b98f-0d2d89ec8109','凌丹亭','岳甫','宋','宋诗','song-poetry','','[]','石門莎徑綠回環，月掛虛簷滴露寒。',32,'全唐诗/poet.song.168000.json','["石門莎徑綠回環，月掛虛簷滴露寒。", "自有松風時度曲，我琴高掛不須彈。"]'),
('2398b5f0-d999-4609-8df0-0f37aa835a41','歸田','陳紹年','宋','宋诗','song-poetry','','[]','咫尺天關隔，丹心空上書。',48,'全唐诗/poet.song.168000.json','["咫尺天關隔，丹心空上書。", "便隨遷客返，還就野人居。", "竹裏烟喧雀，溪頭沙汎魚。", "飛泉觀物性，俯仰自舒徐。"]'),
('15b3033b-f743-4edc-9328-dc23fbf18f03','香爐山','鄭鑑','宋','宋诗','song-poetry','','[]','峙立交輝紫翠間，疎簾半捲鎮長閒。',32,'全唐诗/poet.song.168000.json','["峙立交輝紫翠間，疎簾半捲鎮長閒。", "神仙似有祈年術，一縷青煙起博山。"]'),
('c0869f39-3bd8-4f98-b9a6-1f7828789f40','焚衣街','馬之純','宋','宋诗','song-poetry','','[]','玉指親裁五彩衣，尚方工作極纖奇。',64,'全唐诗/poet.song.168000.json','["玉指親裁五彩衣，尚方工作極纖奇。", "看來亡國都緣此，𬋖向通衢了不遺。", "鷸羽化爲青燒去，雉頭還有紫煙隨。", "更須大字書華表，要使將來盡得知。"]'),
('57bc602b-58fa-45be-a483-23e14fa4dee5','烏衣巷','馬之純','宋','宋诗','song-poetry','','[]','依依燕子可憐生，相向於人真有情。',64,'全唐诗/poet.song.168000.json','["依依燕子可憐生，相向於人真有情。", "不道華堂曾止息，如今窮巷莫經營。", "六朝盛事同流水，千載遺蹤只舊城。", "白日飛忙難話此，話時須等夕陽明。"]'),
('c55f35de-7175-4ce9-8bd9-7932c4ccaac6','宋帝馳道','馬之純','宋','宋诗','song-poetry','','[]','南城來到北城隅，更北直趨玄武湖。',64,'全唐诗/poet.song.168000.json','["南城來到北城隅，更北直趨玄武湖。", "一上雕鞍三十里，兩傍官柳數千株。", "六朝都邑真如此，舊日咸秦得似無。", "暑月行人不張盖，漫天自有翠屠蘇。"]'),
('58144c67-2b1c-46b0-9c73-81ccb31df856','白楊路','馬之純','宋','宋诗','song-poetry','','[]','此路如何名白楊，白楊林木苦非良。',64,'全唐诗/poet.song.168000.json','["此路如何名白楊，白楊林木苦非良。", "聞知宰樹常多種，想見墳塋在兩傍。", "三國英雄塵一窖，六朝興廢字千行。", "行人過此休惆悵，往古來今總渾茫。"]'),
('0ded00a7-225c-47e4-b964-1bd72215c860','周郎橋','馬之純','宋','宋诗','song-poetry','','[]','周郎可是世英豪，談笑功成乃不勞。',64,'全唐诗/poet.song.168000.json','["周郎可是世英豪，談笑功成乃不勞。", "爾大阿瞞猶似此，茲時小笮定應逃。", "雙鞬錦領紛相逐，白羽青絲各自操。", "料得軍行爭看此，霜天健鶻已辭絛。"]'),
('2b2cb8fa-c1ca-487a-a18d-ccd11dac56e6','二十四航','馬之純','宋','宋诗','song-poetry','','[]','秦淮二十四浮航，何似高高虹作梁。',64,'全唐诗/poet.song.168000.json','["秦淮二十四浮航，何似高高虹作梁。", "恐有兵戎來暮夜，可除扳索當城隍。", "淮深尚欲橫鞭渡，河廣猶將一葦杭。", "好是維持令有道，却將夷狄守封疆。"]'),
('77b257eb-01bb-4097-87dd-f8b45d833529','四航','馬之純','宋','宋诗','song-poetry','','[]','要識當時朱雀航，秦淮岸口駕浮梁。',64,'全唐诗/poet.song.168000.json','["要識當時朱雀航，秦淮岸口駕浮梁。", "既爲銅雀施重屋，又作璇題揭上方。", "波底浄涵樓閣影，橋間望斷水雲鄉。", "不知此處今何在，須有遺基在兩傍。"]'),
('2e1da78d-fcd8-4c72-b538-793f55053295','麾扇渡','馬之純','宋','宋诗','song-poetry','','[]','此扇拈來一羽輕，如何退得十千兵。',64,'全唐诗/poet.song.168000.json','["此扇拈來一羽輕，如何退得十千兵。", "百年雨露蒙君賜，一日衣冠繫賊營。", "正欲倒戈爲向背，遠觀揮手極分明。", "而今但得旌旗白，便可中原取次行。"]'),
('98ef6867-db11-4003-a2fa-926ba28a12cc','雞鳴埭','馬之純','宋','宋诗','song-poetry','','[]','臺城五里到青溪，埭在青溪西復西。',64,'全唐诗/poet.song.168000.json','["臺城五里到青溪，埭在青溪西復西。", "向日只緣貪射雉，常時過此始鳴鷄。", "翬鷂用處亦無幾，羽翮貢來誰敢稽。", "便是遊田須有節，如何晨夕恣荒迷。"]'),
('0eae8520-9c73-4d78-bc9f-1c76260af95e','桂嶺','馬之純','宋','宋诗','song-poetry','','[]','桂花千樹占嵌巖，絕勝淮南一小山。',64,'全唐诗/poet.song.168000.json','["桂花千樹占嵌巖，絕勝淮南一小山。", "竽籟有時吹木末，天香無限滿人間。", "懸知彼處有金粟，爲見如今聞麝蘭。", "躡磴緣崖期採摘，分明如向月中攀。"]'),
('5b90a4aa-0b88-4c32-8810-e0f583abd7d2','栽松峴','馬之純','宋','宋诗','song-poetry','','[]','鍾山山上亦僮僮，吏課何妨使種松。',64,'全唐诗/poet.song.168000.json','["鍾山山上亦僮僮，吏課何妨使種松。", "還似農桑分殿最，亦如榆柳計功庸。", "初時出土平如薺，後日橫空矯似龍。", "每見路傍多合抱，不知手植是誰儂。"]'),
('6b1f6b8e-e770-46ba-8312-7df2fb3dfc0a','秦淮','馬之純','宋','宋诗','song-poetry','','[]','城中那有大川行，惟有秦淮入帝城。',64,'全唐诗/poet.song.168000.json','["城中那有大川行，惟有秦淮入帝城。", "十里牙檣并錦纜，萬家碧瓦與朱甍。", "船多直使水無路，人閙不容波作聲。", "流到石頭方好去，望中渺渺與雲平。"]'),
('26b92473-a649-4631-8190-79df17b5c55c','玄武湖','馬之純','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬頃冥茫水拍隄，當時於此習舟師。',64,'全唐诗/poet.song.168000.json','["萬頃冥茫水拍隄，當時於此習舟師。", "長江天險雖堪恃，鬭艦人謀可勿施。", "莫使黑龍離舊窟，且教玄武入新詞。", "如何又作蓬瀛景，地節來遊看水嬉。"]'),
('e70654ea-46ba-42aa-9a5d-4b443dd064e3','半陽湖','馬之純','宋','宋诗','song-poetry','','[]','一半寒泉一半湯，同爲此水異炎凉。',64,'全唐诗/poet.song.168000.json','["一半寒泉一半湯，同爲此水異炎凉。", "湯泉是處雖多有，鍾阜斯池特廣長。", "誰說吹噓如口鼻，或云底下有硫黄。", "好尋舊迹重開鑿，地寶無容久瘞藏。"]'),
('2536d985-3f0d-4195-831b-1f8e46c997e3','燕雀湖','馬之純','宋','宋诗','song-poetry','','[]','在昔曾爲舜帝墳，象來耕作鳥來耘。',64,'全唐诗/poet.song.168000.json','["在昔曾爲舜帝墳，象來耕作鳥來耘。", "今茲封土麒麟冢，乃有銜泥燕雀羣。", "玉海沖融侔至性，錦江燦爛擬高文。", "區區羽物猶依戀，想見人情望白雲。"]'),
('2796e7c2-a0bf-43c6-af61-14d73a57ab2e','青溪  其一','馬之純','宋','宋诗','song-poetry','','[]','人道青溪有九曲，如今一曲僅能存。',64,'全唐诗/poet.song.168000.json','["人道青溪有九曲，如今一曲僅能存。", "江家宅畔成花圃，東府門前作菜園。", "登閣尚堪觀疊嶂，泛舟猶可醉芳樽。", "料應當日皆無恙，苕霅瀟湘不足言。"]'),
('24825314-80e8-4175-a030-25487d1a1bfd','青溪  其二','馬之純','宋','宋诗','song-poetry','','[]','人日泛青溪，青溪曲易迷。',48,'全唐诗/poet.song.168000.json','["人日泛青溪，青溪曲易迷。", "船回波上下，簾捲日東西。", "景物行行見，壺觴處處携。", "浮航消得醉，極目水雲低。"]'),
('a90c6b6e-b049-4d76-b932-2b02bbd23ca6','潮溝','馬之純','宋','宋诗','song-poetry','','[]','潮溝溝外盡深泥，泥上潮生溝却低。',64,'全唐诗/poet.song.168000.json','["潮溝溝外盡深泥，泥上潮生溝却低。", "直向北行連運瀆，折從東去入青溪。", "空中不斷檣烏過，岸上相望瓦翼齊。", "好是畫橋深北處，荷花盈蕩柳垂堤。"]'),
('f250f866-5f62-4453-8572-65eb55d8ce1e','直瀆','馬之純','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','直瀆如何計得工，長江雖遠欲相通。',64,'全唐诗/poet.song.168000.json','["直瀆如何計得工，長江雖遠欲相通。", "比嘗開鑿不勝苦，已復淤填還似空。", "聞鬼夜中皆有語，棄泥江裏解成功。", "有司號令纔依此，衮衮波流漸向東。"]'),
('ad91a37c-f02a-4244-8fdb-a448fd7ac769','善泉池','馬之純','宋','宋诗','song-poetry','','[]','十頃青瑶浸碧流，更添景趣極深幽。',64,'全唐诗/poet.song.168000.json','["十頃青瑶浸碧流，更添景趣極深幽。", "帝爲九洲十八島，上有五城十二樓。", "苕霅荷花風度曉，瀟湘蘆竹雨生秋。", "昭明心想知何似，好聽騎鯨汗漫遊。"]'),
('5c871d98-4b42-4b23-8a1c-6360f6ddd2ba','覆盃池','馬之純','宋','宋诗','song-poetry','','[]','當初一馬過江來，幕府山頭刈草萊。',64,'全唐诗/poet.song.168000.json','["當初一馬過江來，幕府山頭刈草萊。", "無數流離未安集，幾多政事合圖回。", "只應早起觀庭燎，安得時常近酒盃。", "江左中興仗誰力，一池春水泛新醅。"]'),
('fc226bde-e63e-45e0-a7da-f3a29bace4d2','柵塘','馬之純','宋','宋诗','song-poetry','','[]','六朝何處立都城，十里秦淮城外行。',64,'全唐诗/poet.song.168000.json','["六朝何處立都城，十里秦淮城外行。", "上設浮航如道路，外施行馬似屯營。", "關防直可防津渡，緩急徒能御盜兵。", "非是後來謀改築，如何今日作陪京。"]'),
('db52002a-6e44-4f03-b805-939979f1a70e','橫塘','馬之純','宋','宋诗','song-poetry','','[]','如今何處是橫塘，在府城南淮兩旁。',64,'全唐诗/poet.song.168000.json','["如今何處是橫塘，在府城南淮兩旁。", "魏蜀兩都皆不似，蓬萊三島足相方。", "烏衣巷口排金屋，朱雀橋邊立粉牆。", "有底繁華難說似，何妨把作畫圖張。"]'),
('4eeef4ac-c659-40bd-a0d3-e93e7d2b42f4','景陽井','馬之純','宋','宋诗','song-poetry','','[]','應說兵來且莫降，急尋宮井共深藏。',64,'全唐诗/poet.song.168000.json','["應說兵來且莫降，急尋宮井共深藏。", "側身待作凌波步，仰首還成半面粧。", "已分葬埋依古甃，可憐牽挽出銀牀。", "至今汲水人皆說，猶带烟脂舊日香。"]'),
('e9b07256-f857-4146-84c1-1ddae5e27468','應潮井','馬之純','宋','宋诗','song-poetry','','[]','俯看滄海仰看山，相去分明霄壤間。',64,'全唐诗/poet.song.168000.json','["俯看滄海仰看山，相去分明霄壤間。", "有井無冬亦無夏，與潮俱往又俱還。", "想應透徹深無底，怪得浮沉轉似環。", "不用浙江亭上望，請君來此一憑欄。"]'),
('d105130b-6e2c-424c-a66c-131071e8414c','藏冰井','馬之純','宋','宋诗','song-poetry','','[]','向日周家有凌人，後來此事特相因。',64,'全唐诗/poet.song.168000.json','["向日周家有凌人，後來此事特相因。", "冬時室內收藏早，夏日宮中給賜新。", "但得滿盤堆水玉，不須對面著風輪。", "看來深闊能多少，調得陰陽冷熱均。"]'),
('c647476c-1741-4fe2-b59e-adf0ec07f297','八功德水','馬之純','宋','宋诗','song-poetry','','[]','鍾山有嶺號屏風，碧石青林一徑通。',64,'全唐诗/poet.song.168000.json','["鍾山有嶺號屏風，碧石青林一徑通。", "聽得山腰鳴陸續，看來海眼浄浺瀜。", "初嘗但得煩心解，再飲能令百慮空。", "軟美輕清無限好，經中所說正相同。"]'),
('6eded9df-998c-4889-8264-b48ac6c9c420','汝南灣','馬之純','宋','宋诗','song-poetry','','[]','當時只號汝南灣，後有三人住此間。',64,'全唐诗/poet.song.168000.json','["當時只號汝南灣，後有三人住此間。", "自謂逸民須隠約，並稱賢士想高閑。", "祇緣水味都殊異，且欲鄰居數往還。", "好是有時相就飲，不妨鐺脚對青山。"]'),
('248976e0-1084-4e94-9fc1-464c37380140','長命洲','馬之純','宋','宋诗','song-poetry','','[]','如何長命作洲名，梁武當時此放生。',64,'全唐诗/poet.song.168000.json','["如何長命作洲名，梁武當時此放生。", "鵝鴨成羣如市肆，鷄豚無數似屯營。", "豈知半被狸奴食，寧免私爲鶴戶烹。", "不殺自然能不放，却將實禍博虛聲。"]'),
('78260031-7e6f-4ab9-adfc-712c62848ce5','儀賢堂','馬之純','宋','宋诗','song-poetry','','[]','鶴髮龐眉四老人，鶉衣躡履一何貧。',67,'全唐诗/poet.song.168000.json','["鶴髮龐眉四老人，鶉衣躡履一何貧。", "堂中論事君心喜，寺裏譚經衆說新。", "蜀杰仉{黹耑}皆古字，甪黄園綺定前身。", "胡爲朝士無人識，惟有昭明極見親。"]'),
('2c6ce312-963c-42cb-8e9f-f88fad73e4fc','蠶堂','馬之純','宋','宋诗','song-poetry','','[]','桑林倒影媚晴川，中有蠶堂半燠寒。',64,'全唐诗/poet.song.168000.json','["桑林倒影媚晴川，中有蠶堂半燠寒。", "翟茀先期移過此，鞠衣拂曉定來看。", "未眠曲薄心方急，已洗繰盆事始寬。", "瞻彼北宮猶若此，田家婦子可偷安。"]'),
('06e47827-5a88-4ed9-a68b-f24400a53dba','白鷺亭','馬之純','宋','宋诗','song-poetry','','[]','白鷺亭前白鷺飛，山如屏障水如圍。',64,'全唐诗/poet.song.168000.json','["白鷺亭前白鷺飛，山如屏障水如圍。", "水中獨立鸞窺鏡，沙上羣行雪滿磯。", "白日不來爭碧樹，有時同往送斜暉。", "江山得此方成畫，撩得遊人不憶歸。"]'),
('b0047c67-382f-48cf-87e5-fb799cd0809e','白鷺亭和人韵','馬之純','宋','宋诗','song-poetry','','[]','一見斯亭喜可知，風來拂拂更清微。',64,'全唐诗/poet.song.168000.json','["一見斯亭喜可知，風來拂拂更清微。", "青山坐處天開畫，白鷺飛時雪滿磯。", "何必搜奇效康樂，正應得句似玄暉。", "最憐別浦潮生後，須有征帆萬點歸。"]'),
('a7ebf8a8-47be-42f4-b880-2f10e5fa39cb','東冶亭','馬之純','宋','宋诗','song-poetry','','[]','舊時只說東西冶，今日轉爲長短亭。',64,'全唐诗/poet.song.168000.json','["舊時只說東西冶，今日轉爲長短亭。", "無奈梅花臨水白，可堪柳色向人青。", "十分瀲灧苦難把，三疊凄凉誰忍聽。", "不道離愁堆滿屋，往來車馬放教停。"]'),
('e6dca4ca-dc40-4021-82c0-8a3a0e231c20','新亭  其一','馬之純','宋','宋诗','song-poetry','','[]','相對何庸作楚囚，一時凜凜氣橫秋。',64,'全唐诗/poet.song.168000.json','["相對何庸作楚囚，一時凜凜氣橫秋。", "定知決意誰能止，何事空言竟亦休。", "敢謂扶持非爾力，要須恢復有奇謀。", "壺漿滿路無人至，空使遺民歎白頭。"]'),
('c2e3a3eb-0bc5-4efb-9b6e-b16e7a028a50','新亭  其二','馬之純','宋','宋诗','song-poetry','','[]','新亭見說在山頭，看見江河衮衮流。',64,'全唐诗/poet.song.168000.json','["新亭見說在山頭，看見江河衮衮流。", "何事後人輕變改，不教遺址且存留。", "憐他一代稱賢相，說此諸人似楚囚。", "若使有人來訪舊，一番人見一番羞。"]'),
('80a59cc2-d4d5-4f17-bb28-90253bd596e4','新亭  其三','馬之純','宋','宋诗','song-poetry','','[]','憶昔諸賢扶晉室，冠蓋多於此雲集。',144,'全唐诗/poet.song.168000.json','["憶昔諸賢扶晉室，冠蓋多於此雲集。", "坐中翻作兒女悲，世換人非但陳迹。", "我來正值三月春，花落鳥啼春寂寂。", "江河雖異事略同，風景不殊今視昔。", "磨滅英雄得喪多，山重水複無終極。", "安能鬰鬰老江左，尅復神州當勠力。", "未論重見管夷吾，祇今誰爲楚囚泣。", "徙倚令人三歎息，徙倚令人淚橫臆。", "狄夷相殘春又春，時乎時乎難再得。"]'),
('293a266b-66d5-4896-b053-ca46919cbb8c','白下亭','馬之純','宋','宋诗','song-poetry','','[]','白下非今白下亭，府城西北舊曾城。',64,'全唐诗/poet.song.168000.json','["白下非今白下亭，府城西北舊曾城。", "石山四面若環合，江水一條如带橫。", "庾亮憑高臨賊騎，安都間道走齊兵。", "地形峻極真如此，全勝當時却月營。"]'),
('ae76865c-dc55-4f8d-9d2e-be97fda6aeed','勞勞亭','馬之純','宋','宋诗','song-poetry','','[]','誰把勞勞目此亭，從來於此送人行。',64,'全唐诗/poet.song.168000.json','["誰把勞勞目此亭，從來於此送人行。", "三盃別酒傾桑落，一曲離歌唱渭城。", "此到伊邊還幾日，不知何日是歸程。", "分携更復憑高望，滿目青山萬疊橫。"]'),
('3c1a897b-6268-433d-90fa-0d9974352571','不受暑亭','馬之純','宋','宋诗','song-poetry','','[]','驅車曾向暑中來，望見塵襟已豁開。',64,'全唐诗/poet.song.168000.json','["驅車曾向暑中來，望見塵襟已豁開。", "裊裊羊腸知幾折，亭亭鳳翅與俱回。", "渭川沮洳何如此，佛國清凉亦快哉。", "久坐不禁清霧濕，却須酒力喚春回。"]'),
('348a423d-34f4-4df2-8e79-5d5b81b8d3a9','鳳凰臺','馬之純','宋','宋诗','song-poetry','','[]','鳳凰不見祇空臺，底事臺存鳳不來。',64,'全唐诗/poet.song.168000.json','["鳳凰不見祇空臺，底事臺存鳳不來。", "應到緱山還且住，定游阿閣不能回。", "江山不改當時舊，賓客何妨盡日陪。", "待作簫聲勾喚處，有時飛舞下雲堆。"]'),
('eb2a1bb7-0fe5-4b52-a5ec-99b9f823a6bb','雨花臺','馬之純','宋','宋诗','song-poetry','','[]','居士室中天女現，生公臺上雨華懸。',64,'全唐诗/poet.song.168000.json','["居士室中天女現，生公臺上雨華懸。", "只因妙語傾人聽，非有真花墮我前。", "却似文章稱錦麗，亦如咳唾說珠圓。", "不知誰向癡人道，令望虛空眼欲穿。"]'),
('3b586dd2-b3da-4450-8788-66c15c1766db','烽火臺','馬之純','宋','宋诗','song-poetry','','[]','此到西陵路五千，烽臺列置若星連。',64,'全唐诗/poet.song.168000.json','["此到西陵路五千，烽臺列置若星連。", "欲知萬騎還千騎，只看三烟與兩烟。", "不用赤囊來塞下，何須羽檄報軍前。", "如何向日緣褒姒，無事蓬蓬火又燃。"]'),
('c097561a-35f4-4ccb-aeb3-bc494cb94540','獨足臺','馬之純','宋','宋诗','song-poetry','','[]','無端獨足上高臺，以咮縱橫作字來。',64,'全唐诗/poet.song.168000.json','["無端獨足上高臺，以咮縱橫作字來。", "茂草爲灰猶可解，朱門傍水直難猜。", "宮城後向煙中盡，府第還當洛口開。", "洪範五行劉向傳，莫言其說盡迂迴。"]'),
('fca51b9b-ead6-424a-9e74-9f6fa65e89cc','齊雲觀','馬之純','宋','宋诗','song-poetry','','[]','高高真是與雲齊，直到青霄不用梯。',64,'全唐诗/poet.song.168000.json','["高高真是與雲齊，直到青霄不用梯。", "三閣連延須在下，層城突兀亦居低。", "俯看落雨自天半，平視流星從屋西。", "好是嬪嬙遊翠輦，却如僊子駕青霓。"]'),
('b73591f5-f572-4299-8f15-9fa397856728','層城觀','馬之純','宋','宋诗','song-poetry','','[]','人世佳期惟七夕，星躔至巧是天孫。',64,'全唐诗/poet.song.168000.json','["人世佳期惟七夕，星躔至巧是天孫。", "直從樓上將身乞，所欠雲間著手捫。", "聞得鵲聲云報喜，看來蛛網似傳言。", "工夫只是憑心手，此外冥茫不足論。"]'),
('5c1c1573-f195-4474-8279-c573ef41d5b5','古華林苑','馬之純','宋','宋诗','song-poetry','','[]','當時園上想歡娛，不見當時見畫圖。',64,'全唐诗/poet.song.168000.json','["當時園上想歡娛，不見當時見畫圖。", "縹緲神僊來絳闕，分明人世有蓬壺。", "庭花唱斷風生砌，蓮蕩歸來月滿湖。", "萬點華燈星似綴，明朝簪珥得青蕪。"]'),
('bd810b01-3112-4119-86e2-5b3c2b3738d6','古芳林苑','馬之純','宋','宋诗','song-poetry','','[]','昔日曾爲府署來，誰人都把插桃栽。',64,'全唐诗/poet.song.168000.json','["昔日曾爲府署來，誰人都把插桃栽。", "不聞華屋笙簫響，但見芳林錦繡堆。", "幾度劉郎來觀裏，半年阮客住天台。", "如今此地知何在，桑柘成陰撥不開。"]'),
('64b30d54-132c-4506-96c9-4b4aece9f882','古南苑','馬之純','宋','宋诗','song-poetry','','[]','當時南苑最新奇，勝似其他東復西。',64,'全唐诗/poet.song.168000.json','["當時南苑最新奇，勝似其他東復西。", "多少園亭行不到，從橫石徑動成迷。", "香風十里荷花蕩，翠影千行柳樹隄。", "伊被何人曾借住，端如誤入武陵溪。"]'),
('eb47e750-db2d-445b-972e-265b7180480a','詠臺城','馬之純','宋','宋诗','song-poetry','','[]','吳時後苑晉宮城，見得當時似玉京。',64,'全唐诗/poet.song.168000.json','["吳時後苑晉宮城，見得當時似玉京。", "往事茫茫同水遠，長郊渺渺與雲平。", "珠璣常向耕鋤得，禁禦今爲陌路行。", "只有月華還似舊，徘徊花上聽寒更。"]'),
('ad8d8525-eb68-4917-b644-970c8f0fb54d','石麒麟','馬之純','宋','宋诗','song-poetry','','[]','石虎石羊還石人，此間獨有石麒麟。',64,'全唐诗/poet.song.168000.json','["石虎石羊還石人，此間獨有石麒麟。", "定應側近藏陵墓，仗此威靈護鬼神。", "一石琢成高且大，兩頭相望儼如真。", "參天宰木知何在，今與漁樵作四鄰。"]'),
('18557bb5-8565-4d44-9374-0108de7aafbc','斷碑','馬之純','宋','宋诗','song-poetry','','[]','百尺豐碑立路南，盡停車馬試來看。',64,'全唐诗/poet.song.168000.json','["百尺豐碑立路南，盡停車馬試來看。", "不知神道是誰墓，爲問康王何代官。", "初謂流傳須永永，安知磨滅已漫漫。", "姓名不足標青史，休把將來碇石看。"]'),
('f1154cea-f85d-4e93-a292-9d7a629d4bc5','鍾山','馬之純','宋','宋诗','song-poetry','','[]','石城爲虎此爲龍，都邑無如此地雄。',64,'全唐诗/poet.song.168000.json','["石城爲虎此爲龍，都邑無如此地雄。", "萬壑千巖皆拱北，三江七澤盡朝東。", "埋金依舊祥光現，鑿浦仍前地脈通。", "吳晉六朝嘗已驗，如今留鑰比關中。"]'),
('c569ac5a-1ccf-4ab8-a3eb-6f33fc1f5398','石頭城','馬之純','宋','宋诗','song-poetry','','[]','幾年聞說石頭城，初謂堅牢似削成。',64,'全唐诗/poet.song.168000.json','["幾年聞說石頭城，初謂堅牢似削成。", "只是一拳如卓望，初非四面有樓棚。", "依山最好防車騎，舉眼何防矙賊營。", "爲問區區徒自守，何如席卷向宸京。"]'),
('30501371-8d4f-4f9e-955b-6ce6f8534fa4','幕府山','馬之純','宋','宋诗','song-poetry','','[]','當初一馬過江來，幕府權宜向此開。',64,'全唐诗/poet.song.168000.json','["當初一馬過江來，幕府權宜向此開。", "萬里封疆吾舊物，一時賓客爾多才。", "建臺此事雖堪羨，掩泣其人更可哀。", "相視不曾言及此，欲教天意此時回。"]'),
('eeea5e94-4574-4416-b7fa-2f147e061ae2','靈和殿前蜀柳','馬之純','宋','宋诗','song-poetry','','[]','此柳栽從蜀郡移，宮中諸柳不能垂。',64,'全唐诗/poet.song.168000.json','["此柳栽從蜀郡移，宮中諸柳不能垂。", "祗緣草木根靈異，非是乾坤雨露私。", "輕似行雲清似水，軟於吹絮細於絲。", "風流可愛如何比，最是風生月上時。"]'),
('c634db20-d529-4c9e-bf67-54a1b18b79cd','天闕山','馬之純','宋','宋诗','song-poetry','','[]','不知象魏欲何爲，布政頒條總在茲。',64,'全唐诗/poet.song.168000.json','["不知象魏欲何爲，布政頒條總在茲。", "凡有往來須仰視，庶幾衆庶可周知。", "後來江左當新造，好向城隅踵舊規。", "却指牛頭作天闕，此言多少被人嗤。"]'),
('e9b2dff7-4d17-40c3-a8b3-b490cea7c3e5','清暑殿','馬之純','宋','宋诗','song-poetry','','[]','見說當持百尺梁，四圍修竹翠雲長。',64,'全唐诗/poet.song.168000.json','["見說當持百尺梁，四圍修竹翠雲長。", "正當盛暑都無熱，不有薰風亦自涼。", "那與人間同日月，直疑天上兩陰陽。", "有時更取龍皮浸，凜凜如飛六月霜。"]'),
('81509a76-2bd9-4de9-afbf-1ea73ef3292f','梅梁殿','馬之純','宋','宋诗','song-poetry','','[]','太極初時欠一梁，漂流偶見石城傍。',64,'全唐诗/poet.song.168000.json','["太極初時欠一梁，漂流偶見石城傍。", "曾聞禹廟還如此，可見川祇欲效祥。", "不但千年無朽蠹，能令滿殿有芬香。", "要將盛事傳來世，畫出梅花十丈長。"]'),
('6d55a0b3-beae-456e-9231-95e6cc4d816d','潛鶴鼓','馬之純','宋','宋诗','song-poetry','','[]','板木爲腔冒以皮，其中寧有鶴來棲。',64,'全唐诗/poet.song.168000.json','["板木爲腔冒以皮，其中寧有鶴來棲。", "如何音響聞西洛，未必源流自會稽。", "既被兵人都擊破，却云禽鳥不鳴嘶。", "分明僞妄無人辨，可笑諸人識見迷。"]'),
('8befa46c-f588-483e-b42f-ee4920476453','促粧鍾','馬之純','宋','宋诗','song-poetry','','[]','禁鼓城頭報五更，景陽樓上打鍾聲。',64,'全唐诗/poet.song.168000.json','["禁鼓城頭報五更，景陽樓上打鍾聲。", "祇疑髣髴天將曉，不省徘徊月尚明。", "閃閃青燈星戶綴，鬆鬆綠鬢霧窗橫。", "蜂黄蝶粉都描得，那有鴉兒畫不成。"]'),
('028e583a-a8f7-4c79-b0d2-32caa2f00d76','銅螭署','馬之純','宋','宋诗','song-poetry','','[]','洛陽當日鑄銅螭，徒得形模怪且奇。',64,'全唐诗/poet.song.168000.json','["洛陽當日鑄銅螭，徒得形模怪且奇。", "玉刺口中藏不見，蟲居腹內出無時。", "移來建業尚如此，徙在江陵無復茲。", "此說流傳真誕妄，便當不信不須疑。"]'),
('4472f28f-f1c9-4918-9544-c8a6e8e370d0','金城柳','馬之純','宋','宋诗','song-poetry','','[]','金城四面柳爲營，此日征西路再經。',64,'全唐诗/poet.song.168000.json','["金城四面柳爲營，此日征西路再經。", "憶昔僅能高咫尺，如今端可拂青冥。", "清眸漸隔花中霧，綠髮俄懸鏡裏星。", "功業未成多少事，攀枝挽葉淚淋零。"]'),
('0b6724f8-eb68-4fc5-b635-01944c065b1b','東山謝安','馬之純','宋','宋诗','song-poetry','','[]','人物江南第一流，居常不肯利名求。',64,'全唐诗/poet.song.168000.json','["人物江南第一流，居常不肯利名求。", "壯年甘向東山隠，暇日須將妓女遊。", "既與斯人嘗共樂，固應有患即同憂。", "後來一爲蒼生起，破敵成功祇坐籌。"]'),
('acbdc7b9-49e0-4dc1-9d18-0617426e1673','披香殿','馬之純','宋','宋诗','song-poetry','','[]','繡栭藻井柏爲梁，翡翠簾櫳映璧璫。',64,'全唐诗/poet.song.168000.json','["繡栭藻井柏爲梁，翡翠簾櫳映璧璫。", "寶篆煙雲凝馥郁，華林錦綺競紛芳。", "荷花永晝湘江靜，桂子西風陌路長。", "最是春衣裁已就，領巾飄動盡天香。"]'),
('c799d17a-12f6-4993-9941-754abbcac592','古越城','馬之純','宋','宋诗','song-poetry','','[]','府城西北瓦棺東，尚有遺基在此中。',64,'全唐诗/poet.song.168000.json','["府城西北瓦棺東，尚有遺基在此中。", "旋折纔方二里許，規模不得小邦同。", "正當進取爭彊霸，聊作屯營備敵衝。", "老范智謀曾不識，却云爭似建康宮。"]'),
('e35578a8-3014-480a-b495-820386459335','西州城','馬之純','宋','宋诗','song-poetry','','[]','運瀆居東西冶城，西州遺迹甚分明。',64,'全唐诗/poet.song.168000.json','["運瀆居東西冶城，西州遺迹甚分明。", "多言東晉纔經始，或說孫吳已創成。", "池苑春風羅綺市，樓臺夜月管絃聲。", "入門盡是嬉遊地，惟有羊公不願行。"]'),
('9dcf51ad-7171-4ba4-a8c2-4901b7472c2b','王導宅','馬之純','宋','宋诗','song-poetry','','[]','當時一馬渡江來，幕府山頭刈草萊。',64,'全唐诗/poet.song.168000.json','["當時一馬渡江來，幕府山頭刈草萊。", "四海紛披都似此，一時締創亦艱哉。", "朝綱治具提還挈，國本人心壅更培。", "輔佐中興功第一，應須千尺上雲臺。"]'),
('16443802-e7fe-43c4-aa63-2d3902486b25','陸機宅','馬之純','宋','宋诗','song-poetry','','[]','只聞二陸住華亭，却有書堂在秣陵。',64,'全唐诗/poet.song.168000.json','["只聞二陸住華亭，却有書堂在秣陵。", "如此弟兄無比擬，翕然京洛有聲稱。", "辯亡著論真難及，受命專征若易能。", "十萬河橋俱潰散，儒生虛語不堪憑。"]'),
('bbe68c55-5642-40fa-b608-a134578b30b7','沈約宅','馬之純','宋','宋诗','song-poetry','','[]','飽觀明月雙溪水，徧倚清風八詠樓。',64,'全唐诗/poet.song.168000.json','["飽觀明月雙溪水，徧倚清風八詠樓。", "但見遺蹤留婺女，安知故宅在昇州。", "文章至好雖堪羨，節行全虧亦可羞。", "看得齊梁相禪際，只宜稱隠不稱侯。"]'),
('bb1ecbef-170f-4c9b-a595-1ecd13b0c755','江總宅','馬之純','宋','宋诗','song-poetry','','[]','青溪第宅鬭鮮妍，最是江家宅可憐。',64,'全唐诗/poet.song.168000.json','["青溪第宅鬭鮮妍，最是江家宅可憐。", "路上行人爭指處，橋邊遺跡尚依然。", "南冠辭住長安日，北客歸來建鄴年。", "惜此屋廬還似舊，不知曾讀黍離篇。"]'),
('60c23d5b-ab19-469c-8e69-7b9da122c2e3','三山','馬之純','宋','宋诗','song-poetry','','[]','九華境上曾親歷，五老峰前亦屢過。',64,'全唐诗/poet.song.168000.json','["九華境上曾親歷，五老峰前亦屢過。", "不似三山殊媚好，何須千仞極嵯峩。", "翠圍宛似屏間畫，綠折全如水上波。", "況與滄江苦相近，見來心眼定如何。"]'),
('aa6cc90a-ebc4-4d10-aaf7-427eb1d1fe57','卞壼墓','馬之純','宋','宋诗','song-poetry','','[]','當時風俗尚清談，笑道公心瓦石含。',64,'全唐诗/poet.song.168000.json','["當時風俗尚清談，笑道公心瓦石含。", "臨難此曹皆處女，惟公一箇是奇男。", "一門忠孝真難得，六代衣冠孰與參。", "墓草沒頭人不見，令人惆悵極無堪。"]'),
('cc19c677-ec82-41da-be4f-c6dad11113f8','謝安墓','馬之純','宋','宋诗','song-poetry','','[]','中興江左百餘年，人物誰如太傅賢。',64,'全唐诗/poet.song.168000.json','["中興江左百餘年，人物誰如太傅賢。", "桓賊尋常思問鼎，苻秦百萬已臨邊。", "笑談解折姦雄銳，指顧能摧敵陣堅。", "平昔經綸纔試此，依然賫恨向重泉。"]'),
('eb33d536-bda6-40a7-8813-cc764e2a570c','冥漠君墓','馬之純','宋','宋诗','song-poetry','','[]','經營東府役紛紛，掘土城壕得古墳。',64,'全唐诗/poet.song.168000.json','["經營東府役紛紛，掘土城壕得古墳。", "便見雙棺垂欲朽，不知何世了無聞。", "遂令移殯北墉上，仍與號爲冥漠君。", "萬事到頭成幻滅，祭時猶讀惠連文。"]'),
('f31bedf0-4ffe-40e4-825d-42c85486bd68','蔣帝廟  其一','馬之純','宋','宋诗','song-poetry','','[]','一尉爲官亦已輕，後來封爵一何榮。',64,'全唐诗/poet.song.168000.json','["一尉爲官亦已輕，後來封爵一何榮。", "骨青相貌由來異，羽白威神儼似生。", "嘗遣陰兵隨義旅，不從私鑄長姦萌。", "自當血食鍾山上，仍與鍾山換却名。"]'),
('b953908c-8209-4e9d-bfa0-f646924e8700','蔣帝廟  其二','馬之純','宋','宋诗','song-poetry','','[]','爵以封王從六代，謚爲莊武自南唐。',64,'全唐诗/poet.song.168000.json','["爵以封王從六代，謚爲莊武自南唐。", "緣何血食垂千祀，爲有威靈庇一方。", "魏有鍾離尋敗走，秦屯淝水輒奔亡。", "蟲生火起徒妖怪，載記還應擇未詳。"]'),
('1b48ab75-fd0e-437d-b08d-bb11414d2086','晉謝將軍廟','馬之純','宋','宋诗','song-poetry','','[]','苻秦親自到淮淝，真有回山倒海威。',64,'全唐诗/poet.song.168000.json','["苻秦親自到淮淝，真有回山倒海威。", "只遣八千精銳去，能令百萬敗亡歸。", "雖從太傅求方略，要是將軍識事機。", "廟食如今知幾歲，英風隠隠動窗扉。"]'),
('0eb86dd9-7fe4-4dfc-aea3-5ac11e76efe1','晉陰山廟','馬之純','宋','宋诗','song-poetry','','[]','相君一日到郊坰，步騎俄逢十數兵。',64,'全唐诗/poet.song.168000.json','["相君一日到郊坰，步騎俄逢十數兵。", "拂曉見來殊隠約，中宵夢此極分明。", "陰山血食當知我，晉帝南巡適從行。", "事既奏聞因立廟，坡坨亦復享嘉名。"]'),
('2f926e08-ecf8-4e91-9a49-1ca8fbc4358a','蔣山太平興國禪寺','馬之純','宋','宋诗','song-poetry','','[]','凌晨同作蔣山游，細雨絲輕霧不收。',64,'全唐诗/poet.song.168000.json','["凌晨同作蔣山游，細雨絲輕霧不收。", "謝得東風如有意，故教晴色漸盈眸。", "松陰十里青絲障，石磴千層白玉樓。", "彌望寬平如有此，故應常作帝王州。"]'),
('2ed8ce62-2edc-4b11-a3b7-ace95c1f7375','清凉廣惠禪寺  其一','馬之純','宋','宋诗','song-poetry','','[]','出郭無多遠，登山有許高。',48,'全唐诗/poet.song.168000.json','["出郭無多遠，登山有許高。", "舊游曾到處，此地足稱豪。", "日月真雙轂，關河等一毫。", "松篁知我意，故與北風鏖。"]'),
('dc079c26-85b7-432b-a018-b57511c4b911','清凉廣惠禪寺  其二','馬之純','宋','宋诗','song-poetry','','[]','舊時月過女牆頭，風雨摧頹廢不脩。',64,'全唐诗/poet.song.168000.json','["舊時月過女牆頭，風雨摧頹廢不脩。", "地老天荒無處問，松聲灘響替人愁。", "祥刑使者來何暮，弔古詩篇清更幽。", "收拾江山入懷袖，却歸講席進鴻疇。"]'),
('f81f91f7-e39e-4909-a620-fbbd77773a7b','天禧寺阿育王塔','馬之純','宋','宋诗','song-poetry','','[]','兩山回處是爲干，有塔亭亭高似山。',64,'全唐诗/poet.song.168000.json','["兩山回處是爲干，有塔亭亭高似山。", "不但裝嚴增梵剎，可能形勝助城關。", "燈明星斗掛林木，鈴動天風吹佩環。", "陌上行人遥見此，有時東往又西還。"]'),
('1e77aa41-fdee-4e34-bb65-28987c2621eb','佛窟寺','馬之純','宋','宋诗','song-poetry','','[]','牛頭山上有深隈，佛窟何人向此開。',64,'全唐诗/poet.song.168000.json','["牛頭山上有深隈，佛窟何人向此開。", "過去辟支還示見，分明彌勒又生來。", "刀如敝盡鋒何在，形若銷亡氣莫回。", "死復受形胎可入，有無真妄使人猜。"]'),
('2584c550-2448-4c19-8cf2-d5c9e6c8a540','祀馬將軍竹枝辭  其一','馬之純','宋','宋诗','song-poetry','','[]','草頭無數入松山，一遇將軍都敗還。',32,'全唐诗/poet.song.168000.json','["草頭無數入松山，一遇將軍都敗還。", "試問當初戰何所，將軍巖下水猶殷。"]'),
('fd96b199-a71d-4226-9ff0-ec6ba2c445c0','祀馬將軍竹枝辭  其二','馬之純','宋','宋诗','song-poetry','','[]','白羽青絲手自持，雙鞬錦領步兵隨。',32,'全唐诗/poet.song.168000.json','["白羽青絲手自持，雙鞬錦領步兵隨。", "幾番欲到伊吾北，笑殺曹兒行路迷。"]'),
('83b0cc9c-4b35-44d1-a4b3-624e2d7469b1','祀馬將軍竹枝辭  其三','馬之純','宋','宋诗','song-poetry','','[]','曹州孽火遍燒天，不見兵車只漢川。',32,'全唐诗/poet.song.168000.json','["曹州孽火遍燒天，不見兵車只漢川。", "若得將軍把關要，鴉軍不用過山前。"]'),
('24b358b1-3661-44dd-8ba3-12627193fb1c','祀馬將軍竹枝辭  其四','馬之純','宋','宋诗','song-poetry','','[]','麥隴桑疇溪路斜，溪南溪北自千家。',32,'全唐诗/poet.song.168000.json','["麥隴桑疇溪路斜，溪南溪北自千家。", "當年戰守知誰力，好把寒泉薦菊花。"]'),
('c50d3c08-b603-4faf-997f-378195394e30','祀馬將軍竹枝辭  其五','馬之純','宋','宋诗','song-poetry','','[]','桑麻影裏千餘戶，絃管聲中百許年。',32,'全唐诗/poet.song.168000.json','["桑麻影裏千餘戶，絃管聲中百許年。", "但見年華今日好，也須回首看巖前。"]'),
('5755fcec-1080-4f08-96ec-d05261a999f6','祀馬將軍竹枝辭  其六','馬之純','宋','宋诗','song-poetry','','[]','松山父老至今思，嘗問將軍歸不歸。',32,'全唐诗/poet.song.168000.json','["松山父老至今思，嘗問將軍歸不歸。", "巖頭草木成戈戟，雨後溪聲聽鼓鼙。"]'),
('3a31d528-ba07-40aa-a6bf-3b50cd55af19','祀馬將軍竹枝辭  其七','馬之純','宋','宋诗','song-poetry','','[]','倒指於今四百年，竹間祠宇尚依然。',32,'全唐诗/poet.song.168000.json','["倒指於今四百年，竹間祠宇尚依然。", "藤蘿掛木長如旆，苔蘚侵堦碧似錢。"]'),
('26345c2d-cacf-4cff-8f8d-1f8e7712949c','祀馬將軍竹枝辭  其八','馬之純','宋','宋诗','song-poetry','','[]','幾年精爽尚依依，水旱只須來禱祠。',32,'全唐诗/poet.song.168000.json','["幾年精爽尚依依，水旱只須來禱祠。", "勸汝鄉人宜善事，祀時同唱竹枝辭。"]'),
('a62a973f-1869-4577-ad97-469dda2cd551','擬峴亭詩','馬之純','宋','宋诗','song-poetry','','[]','吾縣西峴峰，亭以擬峴名。',288,'全唐诗/poet.song.168000.json','["吾縣西峴峰，亭以擬峴名。", "嘗見父老說，寺中有碑銘。", "昔晉殷仲文，作郡有政聲。", "去而人思之，屐齒有餘榮。", "余聞諸老說，此事不可憑。", "臣子從弒逆，罪合五鼎烹。", "桓玄在荆州，世爲晉公卿。", "一朝睨漢鼎，舉兵向金陵。", "是時殷仲文，實守新安城。", "棄郡以從玄，惟欲事逆成。", "策命九錫文，未至先經營。", "桓楚既竊位，寢所地忽崩。", "仲文於此時，巧言如簧笙。", "其後玄事敗，奔走向南荆。", "仲文憂不免，奉二后還京。", "叛晉復叛玄，鼠雀同偷生。", "寄奴後代晉，又欲居朝廷。", "出爲東陽郡，怏怏無好情。", "嘗覽鏡自照，不見頭顱形。", "豈非從逆者，未誅先受刑。", "無忌牧荆州，仲文嘗趨迎。", "便道不過府，無忌殊不平。", "言于宋武帝，此輩謀舉兵。", "宋武盡族誅，流血幾成坑。"]'),
('c960de7a-4eaa-4661-85d6-b02fae449341','以鑑贈趙制置','袁燮','宋','宋诗','song-poetry','','[]','吁嗟此鑑，惟銅之精。',240,'全唐诗/poet.song.168000.json','["吁嗟此鑑，惟銅之精。", "磨之治之，瑩乎其明。", "其明維何，洞燭毫髮。", "非由外至，實自中發。", "我有良友，天支之英。", "雄鎮江淮，爲時長城。", "我寶此鑑，持以贈之。", "此鑑此心，昭晰無疑。", "鑑揭於斯，中涵萬象。", "物自不逃，初非鑑往。", "人心至神，無體無方。", "有如斯鑑，應而不藏。", "鑑以塵昏，心以欲翳。", "欲全其明，盍去其累。", "經武折衝，厥任匪輕。", "勿貪小利，勿徇虛名。", "律身惟謹，上功必實。", "欺心不萌，精忠貫日。", "選擇僚佐，爲己强助。", "衆明翼之，厥光彌著。", "昔者武侯，發教羣下。", "孜孜求益，不自滿假。", "陸抗摧敵，東還樂鄉。", "貌無矜色，謙沖如常。"]'),
('82e94ced-60d8-42f4-b591-e083561d99e1','丁未之冬營房告成有亭翼然名之曰勸功且爲歌訓迪有衆','袁燮','宋','宋诗','song-poetry','','[]','維此江壖，控扼之所。',240,'全唐诗/poet.song.168000.json','["維此江壖，控扼之所。", "居安思危，可無備禦。", "維彼强狡，巧於乘隙。", "萌蘗弗除，其欲罔極。", "孰堪制之，維汝弓兵。", "猛虎在山，百獸震驚。", "勇無堅敵，謀無遺慮。", "如彼獵師，靡逸狐兔。", "亦如農夫，稂莠是芟。", "寇盜斯戢，善良斯安。", "吾民膏血，爲汝衣食。", "可不念此，爲民除慝。", "國用方窘，于汝常給。", "可不念此，竭誠報國。", "無或徇私，貪求肆虐。", "無或荒嬉，酣飲蒱博。", "强汝志氣，精汝武藝。", "習汝行陳，昭汝果毅。", "我聞在昔，元勳茂烈。", "發迹弧矢，登壇授鉞。", "反觀此身，均一丈夫。", "彼既能然，我豈不如。", "黽勉從事，不辭險阻。", "風餐露宿，含辛茹苦。"]'),
('f5f33d68-cb63-494f-8781-9885a71eec41','安邊','袁燮','宋','宋诗','song-poetry','','[]','安邊在良將，至矣晁生語。',288,'全唐诗/poet.song.168000.json','["安邊在良將，至矣晁生語。", "邊疆無良臣，胡能固吾圉。", "孰爲國之良，四德貴兼取。", "智能制勍敵，仁能撫軍旅。", "勇足任爪牙，忠足寄心膂。", "信哉人中傑，勳名在王府。", "斯人世不乏，感會待明主。", "藝祖英睿資，一劍定區宇。", "憤彼敵人驕，求我萬虎侶。", "三邊十四將，人人奮材武。", "威名被草木，折衝自樽俎。", "當年寵遇隆，噲等莫爲伍。", "關市擅征榷，金帛豐賜予。", "機要時面陳，延見虛當宁。", "天顔對咫尺，殿坐得容與。", "等級忘尊卑，親愛均肺腑。", "久戍二十載，近亦十寒暑。", "漢超守關南，販鬻如巨賈。", "法令安有此，優詔特聽許。", "進也治居第，𤭁瓦覆其宇。", "有司每墜執，視進等兒女。", "府庫有餘蓄，捐棄如糞土。", "犒賞飫牛酒，驍雄率鼓舞。", "貪夫冒絕險，敵情畢親覩。"]'),
('c2058bd9-5503-41fd-9ec5-7fa28b48600f','上中書陳舍人三首  其一','袁燮','宋','宋诗','song-poetry','','[]','鳴玉青瑣闥，揮毫紫微垣。',72,'全唐诗/poet.song.168000.json','["鳴玉青瑣闥，揮毫紫微垣。", "仰參鸞鵠翔，俯視燕雀喧。", "異時憂世士，才學窮根源。", "亦有濟時策，無因通旁閽。", "公居清切班，日對龍顔溫。", "嘉會千一遇，論思毋憚煩。"]'),
('9671b638-ba98-4cba-b3d5-9e11b766a680','上中書陳舍人三首  其二','袁燮','宋','宋诗','song-poetry','','[]','士方負材業，高價敵璠璵。',72,'全唐诗/poet.song.168000.json','["士方負材業，高價敵璠璵。", "一朝聲稱減，碌碌盆盎如。", "貴名豈不欲，名盛復難居。", "所以古君子，謹終如厥初。", "自公到京國，聞望傾萬夫。", "願言益進德，名與天壤俱。"]'),
('a2e5b1dd-3eee-42e3-bc43-3e38e2694643','上中書陳舍人三首  其三','袁燮','宋','宋诗','song-poetry','','[]','重明麗宸極，萬國熙王春。',72,'全唐诗/poet.song.168000.json','["重明麗宸極，萬國熙王春。", "翹首望德政，從今斯一新。", "當年羽翼客，休戚一體均。", "致主欲堯舜，規模戒因循。", "古來王佐才，宇宙歸經綸。", "期公繼前作，百世稱偉人。"]'),
('7b6acec2-6d77-4a37-94b3-ce592dbb02c6','與范總幹','袁燮','宋','宋诗','song-poetry','','[]','賢士未達時，懷寶混塵境。',240,'全唐诗/poet.song.168000.json','["賢士未達時，懷寶混塵境。", "得志行所爲，澤民效伊尹。", "常深納溝念，疾苦勤訪問。", "所期培殖豐，肯詫裁決敏。", "所以龔黄輩，仁聲達幽隠。", "是時民氣樂，魚躍快於牣。", "高躅欲追攀，是心先戒謹。", "日憐老鈍資，不敢汙蘭省。", "朅來楚江邊，宣布寬大令。", "牧養乃其職，此事無窮盡。", "孳孳撫凋瘵，凜凜憂饑饉。", "今歲雨意慳，齋心罄三請。", "甘澤幸滂沱，良田稍膏潤。", "雜種亦復熟，窮閭庶安枕。", "亭平富詞學，春華灼千品。", "貽我喜雨篇，仁心極矜軫。", "源流自介庵，句法深以穩。", "擾擾淫哇中，聞此古歌詠。", "我無爲霖手，丹闕何由覲。", "兀坐哦君詩，字字堪企敬。"]'),
('9d33b305-fc20-4229-8743-923f1e15b4c7','送黄疇若尚書','袁燮','宋','宋诗','song-poetry','','[]','軒裳本外物，輕重非所關。',276,'全唐诗/poet.song.168000.json','["軒裳本外物，輕重非所關。", "俗子不識真，貪榮强躋攀。", "苟求既得志，巧計仍朋姦。", "誰知國士胸，取舍超人寰。", "不憂節不高，任重憂力孱。", "公家太史氏，閲世多險艱。", "無心羨尊顯，名塞穹壤間。", "尚書續正脈，清泉瀉潺潺。", "操修不敢怠，粹美無可刪。", "垂垂躡政途，念念思江山。", "上欲登絕頂，下欲臨碧灣。", "勇退得所願，喜見冰雪顔。", "是中有真趣，景貺天所慳。", "一朝歸領略，拔萃玉筍班。", "豈若嗜進徒，終身墮荒菅。", "家聲遂復振，舊觀欣重還。", "平生萬事足，只欠素與蠻。", "美官非我願，寧復憐綠鬟。", "却須富篇什，麗錦爭斕斑。", "九重念耆德，詎許長清閒。", "强敵未殄滅，罷甿正恫瘝。", "譬如建大厦，運斧無輸般。", "願公勉加餐，暫歸隨賜環。"]'),
('26f8d045-ad82-4dff-ae5f-a00af63972f4','寄武岡使君表兄','袁燮','宋','宋诗','song-poetry','','[]','符竹剖千里，休戚繫一方。',288,'全唐诗/poet.song.168000.json','["符竹剖千里，休戚繫一方。", "田里息愁嘆，民安由吏良。", "方今重茲選，俾近天子光。", "臨遣重丁寧，考察何精詳。", "吾兄富才業，敏銳鋒莫當。", "論事切時務，玉音屢褒揚。", "都梁雖遠郡，于今爲邊防。", "帝曰惟汝諧，專城頼紀綱。", "吾兄勤布宣，德意達窮鄉。", "朝夕念此民，啟處幾不遑。", "世方急催科，下令嚴秋霜。", "罷癃因鞭笞，男女失耕桑。", "財貨豈不足，衆弊實蠹傷。", "但能澄其源，府庫有餘藏。", "無告深可憫，盻盻將流亡。", "根本不護惜，忍以斤斧戕。", "吾兄獨反是，屬邑頼小康。", "願言堅此志，益使仁風翔。", "此邦介荆蠻，其俗氣稟剛。", "宜以寬治之，馴擾狡與强。", "用法人固畏，中心要易忘。", "十步有茂草，多士詠思皇。", "況有賢師儒，德行侔珪璋。", "薰陶亦既久，濟濟觀趨蹌。"]'),
('27af1df0-5d61-46a7-9953-26762de9327c','送李鳴鳳使君','袁燮','宋','宋诗','song-poetry','','[]','道山羣玉府，密邇日月光。',156,'全唐诗/poet.song.168000.json','["道山羣玉府，密邇日月光。", "夐與塵世隔，恍如白雲鄉。", "李侯好古士，來自天一方。", "峩冠英俊林，掉鞅翰墨場。", "著庭秉直筆，省戶推望郎。", "高情遽勇退，遠業真難量。", "黎庶多困窮，撫摩仗循良。", "鷹鸇豈不鷙，鳳鳥乃嘉祥。", "生財固有道，視民當如傷。", "寧乏强敏稱，毋令本根戕。", "仁聖子萬姓，邇遐如一堂。", "賢牧著聲績，璽書隨褒揚。", "我歸伏茅荆，翹首觀高翔。"]'),
('0248155c-43c6-489c-a86c-c94812a0cd21','送李左藏三首  其一','袁燮','宋','宋诗','song-poetry','','[]','中都衣冠地，振羽良獨難。',72,'全唐诗/poet.song.168000.json','["中都衣冠地，振羽良獨難。", "美材副時須，步武隨鵷鸞。", "平生根柢學，萬卷胸中蟠。", "清規照冰玉，健筆翻波瀾。", "宦游聊復爾，榮利不可干。", "去去展壯圖，士友拭目看。"]'),
('eb8e68e4-06d9-4c12-afdb-e156f137c0e4','送李左藏三首  其二','袁燮','宋','宋诗','song-poetry','','[]','憶昔議和日，權門機穽深。',72,'全唐诗/poet.song.168000.json','["憶昔議和日，權門機穽深。", "平居自好者，亦或喪其心。", "偉哉人中傑，獨立山萬尋。", "佐時豈不欲，枉己非所欽。", "蔚然歲寒姿，肯受霜雪侵。", "願言繼前作，冠冕英俊林。"]'),
('cc4f4e73-bede-4c1c-a900-812a080d61ef','送李左藏三首  其三','袁燮','宋','宋诗','song-poetry','','[]','人生貴得友，勝己我所求。',72,'全唐诗/poet.song.168000.json','["人生貴得友，勝己我所求。", "搜尋窮怪珍，逢此荆山璆。", "虛懷略輩行，傾蓋均交游。", "許賡清絕句，每嘆風雅儔。", "中年畏作別，握手如隠憂。", "尺素煩警策，慰我思悠悠。"]'),
('f9f5d1d6-a1b2-43f5-a1fb-4eeb8a700b34','送治中楊司直','袁燮','宋','宋诗','song-poetry','','[]','岷蜀古多士，聲名爭頡頏。',156,'全唐诗/poet.song.168000.json','["岷蜀古多士，聲名爭頡頏。", "近代推三蘇，奮發眉之陽。", "君侯亦眉人，源委故深長。", "少日隨游宦，中年擅詞場。", "笑談掇高科，步武聯周行。", "蟠胸富籌策，振羽方翺翔。", "一朝遽勇退，萬里還故鄉。", "名邦贊佳政，海沂還復康。", "無計留君行，臨分徒自傷。", "我亦歸舊隠，後會殊渺茫。", "小兒獲同升，此好固難忘。", "流俗久頹敝，棖也焉得剛。", "期君懋遠業，志氣常堅彊。"]'),
('7df36169-61d2-42da-9501-1baae775f47b','送姜子謙丞於潛','袁燮','宋','宋诗','song-poetry','','[]','磻溪有君子，玉壺貯寒冰。',240,'全唐诗/poet.song.168000.json','["磻溪有君子，玉壺貯寒冰。", "一朝辭舊隠，去爲畿邑丞。", "畿邑天下劇，贊府須賢能。", "才刃肯嘗試，心源先自澄。", "古來人中傑，進德如川增。", "規模百年後，感慨中夜興。", "終焉不碌碌，泰華高崚嶒。", "君侯資敏達，而以古自繩。", "嗜書殆成癖，幾載雞窗燈。", "詞場賈餘勇，先取蝥弧登。", "成功不自伐，得善勤服膺。", "筌蹄寧復顧，堂奧從今升。", "時哉佐裁決，行矣蜚聲稱。", "吾民久憔悴，德政先哀矜。", "寧書考下下，莫忘心兢兢。", "俯仰無愧怍，正直神所憑。", "相期志遠大，可但觀飛騰。", "久要忽語別，慘戚不自勝。", "我無錦繡段，何以贈良朋。", "一言布心腹，舊貫古所仍。"]'),
('48fd6124-4b78-432d-8574-85fb84c06f61','送樓叔韶尉東陽三首  其一','袁燮','宋','宋诗','song-poetry','','[]','吾鄉多賢士，我友更偉奇。',72,'全唐诗/poet.song.168000.json','["吾鄉多賢士，我友更偉奇。", "見之立衰懦，不見令人思。", "暫別已作惡，況乃三歲暌。", "躊躇西郊外，此意誰能知。", "剛强不可恃，柔弱難自恃。", "願君日進德，古人以爲期。"]'),
('c96d1591-a1b4-426a-8233-ac611afdc29f','送樓叔韶尉東陽三首  其二','袁燮','宋','宋诗','song-poetry','','[]','古人重世家，非爲世其祿。',60,'全唐诗/poet.song.168000.json','["古人重世家，非爲世其祿。", "世祿非不朽，風流要相續。", "君家富才傑，海內仰名族。", "豈徒衣冠盛，要使操履篤。", "邇來益光華，君其繼高躅。"]'),
('41a0e3fa-7cde-4a41-a01d-fb2051ca1d01','送樓叔韶尉東陽三首  其三','袁燮','宋','宋诗','song-poetry','','[]','尉職最親民，亦足行所學。',60,'全唐诗/poet.song.168000.json','["尉職最親民，亦足行所學。", "吾民苟安枕，微官有餘樂。", "嘗聞長老言，人性原不惡。", "迷塗偶忘返，見善寧不怍。", "君能復其初，治行乃超卓。"]'),
('d1dec2ed-a043-490b-9b7c-53d44e9805f9','送路德章芾三首  其一','袁燮','宋','宋诗','song-poetry','','[]','窮途分愚賢，是非少復真。',72,'全唐诗/poet.song.168000.json','["窮途分愚賢，是非少復真。", "圭璧委道側，輪囷爲國珍。", "由來磊落士，處世多邅迍。", "對越我無歉，幽居志常伸。", "豐城有利劍，紫氣干星辰。", "終然不埋沒，龍化延平津。"]'),
('0ee5bb9b-0a55-41c7-bd69-d09aedadba46','送路德章芾三首  其二','袁燮','宋','宋诗','song-poetry','','[]','後學寡師承，私知妄穿鑿。',84,'全唐诗/poet.song.168000.json','["後學寡師承，私知妄穿鑿。", "緬懷東萊公，天才負超卓。", "英詞粲星斗，偉量包海嶽。", "寬平復謹嚴，精密更恢廓。", "哀哉梁木摧，誰歟繼前作。", "幸有二三友，潛心味博約。", "相期在不朽，與道爲郛郭。"]'),
('3f60118f-70d9-4919-aac1-7bbfb7fbe054','送路德章芾三首  其三','袁燮','宋','宋诗','song-poetry','','[]','賢哉子路子，德性兼剛柔。',84,'全唐诗/poet.song.168000.json','["賢哉子路子，德性兼剛柔。", "險難極變態，志節凜高秋。", "訪我大江濱，亟別挽莫留。", "問子將何之，長淮理扁舟。", "主人得仁賢，欲爲經遠謀。", "男兒處斯世，器業追前修。", "努力建碩畫，勿貽師門羞。"]'),
('12aac45c-1bb8-4313-a2a7-44458c68d5a1','送趙大冶晦之','袁燮','宋','宋诗','song-poetry','','[]','謝公中年後，畏與親友別。',288,'全唐诗/poet.song.168000.json','["謝公中年後，畏與親友別。", "歲月苦不長，交情固難輟。", "況於桑榆景，撫事心欲折。", "一朝舍我去，遂恐成永訣。", "感君遇我厚，肝膽每傾竭。", "惓惓念斯時，言論多激烈。", "憶君哦松日，志操已超越。", "庾臺欲推薦，風之使來謁。", "恥於呈其身，保此端以潔。", "君今宰壯縣，便道理舟楫。", "不騎京國鯨，不改歲寒節。", "升沈分自定，義理我所說。", "黎甿久困窮，恩惠思周浹。", "姦欺巧蒙蔽，精神要昭徹。", "鄰境猶繹騷，武備不可闕。", "弓兵暨保甲，閲習貴嚴切。", "懸賞勸之射，人人藝精絕。", "莫言一邑小，振作在賢傑。", "士氣苟奮揚，威聲必震疊。", "自憐老且病，羨君健而決。", "老病保餘生，健決廣賢業。", "自期素不淺，有志終煒燁。", "日誦論孟書，端如明鑑揭。", "聖賢以爲法，今古同一轍。"]'),
('ba273477-abe6-43c2-ac61-1021161b8cee','贈蔣德言昆仲三首  其一','袁燮','宋','宋诗','song-poetry','','[]','平生無所嗜，耽玩惟古今。',96,'全唐诗/poet.song.168000.json','["平生無所嗜，耽玩惟古今。", "以我淺陋質，期於江海深。", "萬事不掛胸，須臾惜光陰。", "五夜常自起，簡牘勤披尋。", "清風遞晨鐘，鏗然感予心。", "年來因多事，力弱不自任。", "叢書未暇讀，塵埃積中襟。", "何當脫鞅絆，歸歟松竹林。"]'),
('761e7beb-fa76-473b-9387-50e1b8c4e8b4','贈蔣德言昆仲三首  其二','袁燮','宋','宋诗','song-poetry','','[]','平生寡所諧，疎拙以自守。',108,'全唐诗/poet.song.168000.json','["平生寡所諧，疎拙以自守。", "天鍾鑿枘性，人棄我獨取。", "世道方荆榛，營利不絕口。", "我欲挽衰俗，每每掣其肘。", "仕版謂假途，何用醫國手。", "再拜謝誨言，古人貴不苟。", "乘田與委吏，勤勤魯中叟。", "吾心不可昧，豈問人知否。", "此意當與誰，寄我二三友。"]'),
('d12c9a45-20cb-4d57-897f-9bd4e57b4e16','贈蔣德言昆仲三首  其三','袁燮','宋','宋诗','song-poetry','','[]','我生亦何幸，佳友在鄰牆。',96,'全唐诗/poet.song.168000.json','["我生亦何幸，佳友在鄰牆。", "道義共講貫，心親形迹忘。", "邇來忽問闊，千里遥相望。", "爲別似未久，炎赫變飛霜。", "歲月易因循，志士宜自强。", "良心虞放逸，古人嚴範防。", "及此閒暇日，書林擷其芳。", "他年恢遠業，雲路觀騰驤。"]'),
('5255e40e-7cb8-4d29-ab5e-830fbfddd109','贈游宣教','袁燮','宋','宋诗','song-poetry','','[]','連日雨滂沱，閭閻應甚苦。',48,'全唐诗/poet.song.168000.json','["連日雨滂沱，閭閻應甚苦。", "慨念樂隠翁，蕭然坐環堵。", "術業豈不精，一寒乃如許。", "請君姑置之，對婦酌芳醑。"]'),
('6098d7aa-13c9-4697-860a-980c34bdf558','贈吳氏甥二首  其一','袁燮','宋','宋诗','song-poetry','','[]','男兒何所急，爲學要立志。',180,'全唐诗/poet.song.168000.json','["男兒何所急，爲學要立志。", "此志苟堅彊，天下無難事。", "超然貴於物，萬善無不備。", "厥初本高明，有過則昏蔽。", "但能改其過，輝光照無際。", "厥初本篤實，有過則虛僞。", "但能改其過，金玉等精粹。", "改過貴乎勇，不勇真自棄。", "有過如坑穽，改過如平地。", "平地可安行，坑穽宜急避。", "事親貴乎孝，事長貴乎弟。", "是爲立身本，奉承無失墜。", "門戶久衰頹，盍作興起計。", "是心通神明，勿使形骸累。", "持之久而純，百福如川至。"]'),
('b903f3be-29e2-4343-813f-e443f3b220d6','贈吳氏甥二首  其二','袁燮','宋','宋诗','song-poetry','','[]','農夫力耕耘，歲功必倍收。',192,'全唐诗/poet.song.168000.json','["農夫力耕耘，歲功必倍收。", "吾儒用心苦，學業亦有秋。", "聖賢有遺訓，好古敏以求。", "韋編至三絕，發憤窮深幽。", "寢食俱相忘，此志何時休。", "矧今後生輩，未脫童丱儔。", "刻苦猶不足，詎可思悠悠。", "而母早孀居，其窮未易瘳。", "殷勤撫二子，不暇爲身謀。", "雜然萬馬羣，望爾爲驊騮。", "翕如衆樂奏，望爾爲天球。", "勿云年尚幼，歲月如川流。", "及今不加鞭，壯大徒包羞。", "輕璧惜寸陰，前哲勤進修。", "勉爾務謹重，戒爾無輕浮。", "人百己千之，庶解而母憂。"]'),
('04b718b6-1676-4b70-81b4-665576e8806a','夏日早起','袁燮','宋','宋诗','song-poetry','','[]','舉世憚炎赫，當暑思高秋。',84,'全唐诗/poet.song.168000.json','["舉世憚炎赫，當暑思高秋。", "秋高豈不好，蕭瑟令人愁。", "何如三伏中，五夜風颼颼。", "遥空淡月落，將旦羣陰收。", "却嫌絺綌薄，轉覺林塘幽。", "出門任所適，清與耳目謀。", "借問塵埃人，知此佳致不。"]'),
('39d69c91-2966-45d7-9613-6965e75706dd','枕上有感呈呂子約','袁燮','宋','宋诗','song-poetry','','[]','俗學淺無源，澗谷纔咫尺。',120,'全唐诗/poet.song.168000.json','["俗學淺無源，澗谷纔咫尺。", "志士務廣深，滄溟渺難測。", "俗子一作吏，書几塵土積。", "志士雖涖官，羣書玩無斁。", "廢書固俗子，既俗又奚責。", "嗜書苟不已，無乃曠厥職。", "臧穀均亡羊，孰爲失與得。", "古人有大端，後學宜取則。", "有餘不可盡，不足在所益。", "努力求至當，毋蹈一偏失。"]'),
('0d6a5433-37d6-472c-9729-89d40c6ffd8c','和呂子約霜月有感二首  其一','袁燮','宋','宋诗','song-poetry','','[]','寒松飽霜雪，冉冉翠光濕。',84,'全唐诗/poet.song.168000.json','["寒松飽霜雪，冉冉翠光濕。", "萬物困波流，砥柱獨中立。", "比德有君子，逸氣難拘縶。", "平生憂世心，如彼救焚急。", "朅來席未溫，冥鴻去何適。", "勸君且淹留，斯民待安輯。", "小試活國手，腠理猶可及。"]'),
('3cadbc29-de29-49ac-94c0-92fb6494e1ef','和呂子約霜月有感二首  其二','袁燮','宋','宋诗','song-poetry','','[]','頑夫禪作窟，狂士醉爲鄉。',84,'全唐诗/poet.song.168000.json','["頑夫禪作窟，狂士醉爲鄉。", "誰知名教中，悠悠滋味長。", "嗟余學無窮，勺水淺可揚。", "講習得益友，麗澤期交相。", "風月古猶今，時序燠與凉。", "一笑聊復爾，片心到羲皇。", "乾坤入吾懷，始信居中央。"]'),
('fd14c161-4934-4407-b4c9-2678efa5d922','喜雪謝東林','袁燮','宋','宋诗','song-poetry','','[]','去冬雪意慳，稍稍臘三白。',252,'全唐诗/poet.song.168000.json','["去冬雪意慳，稍稍臘三白。", "飛霙纔到地，轉盼已消釋。", "緬懷大有年，兆見瓊玉積。", "今茲杳難期，春信亦已迫。", "天公豈不仁，拙政難感格。", "何時愜人意，四顧苦無策。", "東林惠佳句，似慶平地尺。", "見戲唯何甚，余方自刻責。", "東林達余心，精禱覬有獲。", "沈水煙未收，冰花已如席。", "皓皓埋羣山，霏霏連數夕。", "郊原迷畔岸，徑畛失分畫。", "兒童見未曾，耆老記疇昔。", "幾年無此瑞，驚喜欲折屐。", "皆云窮臘中，得此夜光璧。", "莫言不堅牢，究竟多利益。", "端能殄遺蝗，亦復滋宿麥。", "歡聲沸閭里，和氣蠲癘疫。", "老守差自慰，足寄孤危跡。", "小己不足道，吾民幸安宅。", "作詩謝東林，至誠動金石。"]'),
('875b48af-2f26-4b84-937f-9ee3e828c083','遊寶方山','袁燮','宋','宋诗','song-poetry','','[]','幽巖如高人，氣骨天所賦。',288,'全唐诗/poet.song.168000.json','["幽巖如高人，氣骨天所賦。", "凜然超塵寰，不受俗氣污。", "湖湘饒峰巒，往往窮僻處。", "城郭去之遠，誰能躡芒屨。", "安知古都梁，爽塏有真趣。", "徜徉東郊外，青山在指顧。", "山中八洞列，天巧於此覷。", "蜿蜒老螭蟠，嶄巖怒虎踞。", "如屏亦如龕，一起復一仆。", "卷阿坐良穩，狹徑足難措。", "帝觀若險隘，中道本宏裕。", "疊翠常回環，寒泉日傾注。", "石乳一何粲，和氣知有聚。", "所見皆可人，十步目九寓。", "造物不能祕，奇詭遂呈露。", "奎畫賁精舍，鬼神昔呵護。", "古稱小有天，仇池乃其附。", "甬東有勝境，豁然四窗具。", "玲瓏皆自然，匪以雕鎸故。", "誰謂寶方小，是亦洞天數。", "誰謂此邦陋，有景即可慕。", "我本煙波徒，雅性厭馳騖。", "搜尋得所欲，心境頓明悟。", "賞玩有餘味，躋攀了不怖。"]'),
('ed60c99a-1dd9-492d-a337-dae5f04aa822','峽水','袁燮','宋','宋诗','song-poetry','','[]','峽石險而怪，峽水清且湍。',108,'全唐诗/poet.song.168000.json','["峽石險而怪，峽水清且湍。", "伊誰剪蒙密，發此奇偉觀。", "兩龍會爲一，激烈不可干。", "蜿蜒潄鳴玉，千古甘以寒。", "誰云巖扉窄，亦復氣象寬。", "我生囂塵中，區區縛微官。", "一見爽心目，古井生波瀾。", "同遊二三子，清賞有餘歡。", "雖非暮春日，便作舞雩看。"]'),
('512584b8-2c82-4355-95e7-e1670da10dfa','含清亭','袁燮','宋','宋诗','song-poetry','','[]','累石爲層峰，而以水環之。',204,'全唐诗/poet.song.168000.json','["累石爲層峰，而以水環之。", "所貴超俗累，瀟灑含幽姿。", "却虞窮臘中，四顧陰雲垂。", "飛霙冷徹骨，智巧無所施。", "督彼執役者，努力無遲遲。", "果然霰先集，六出爭效奇。", "繽紛一晝夜，翦刻非人爲。", "豐登自此兆，疫癘寧復滋。", "明朝便晴朗，工作無愆期。", "二事古難全，今也都不虧。", "天公念下土，所欲皆相隨。", "我山既嶔岑，我沼仍漣漪。", "頻遊不知倦，清坐堪忘饑。", "追懷舞雩風，童冠俱怡怡。", "豈徒耳目玩，要是無瑕疵。", "此樂未易得，天意扶吾衰。", "宿恙不再作，康寧當自茲。"]'),
('a8bf4319-0e04-4624-9e66-12fbc6a138ce','題庸齋','袁燮','宋','宋诗','song-poetry','','[]','人生一世間，當爲一世傑。',48,'全唐诗/poet.song.168000.json','["人生一世間，當爲一世傑。", "瑣瑣混常流，有愧古明哲。", "努力求至道，毫髮無差別。", "偉哉平常心，光明配日月。"]'),
('289419ef-7f98-48cd-9cd0-fc1dd2dce99a','題習齋','袁燮','宋','宋诗','song-poetry','','[]','寓形宇宙間，所至習乃成。',288,'全唐诗/poet.song.168000.json','["寓形宇宙間，所至習乃成。", "事以習故熟，藝以習故精。", "嬰兒始匍匐，習之能自行。", "南人初學沒，習慣如履平。", "承蜩有餘巧，解牛新發硎。", "是皆習熟故，見者爲之驚。", "矧惟君子學，吾道深而宏。", "欲窮聖賢域，精微故難明。", "聖賢與愚鄙，何啻莛與楹。", "愚夫墮惡習，自蹈谷與坑。", "善惡分舜跖，毫釐當細評。", "莫將朱奪紫，無使渭濁涇。", "根源見端的，履踐嚴度程。", "容貌必齊莊，坐立無倚傾。", "視聽一於禮，言語純于誠。", "百行孝爲本，戰戰如奉盈。", "操行潔冰玉，宇量涵滄溟。", "經德豈干祿，爲善非近名。", "方其學習初，是非交戰爭。", "見義勇必爲，有過時自抨。", "造次必致察，思慮防始萌。", "惡念痛掃除，用力如用兵。", "善端謹護持，保己如保城。", "新功生者熟，舊習熟處生。"]'),
('89b69b55-2a7b-4234-8203-16aba518fdfe','謝吳察院惠建茶','袁燮','宋','宋诗','song-poetry','','[]','佳茗世所珍，聲名競馳逐。',180,'全唐诗/poet.song.168000.json','["佳茗世所珍，聲名競馳逐。", "建溪拔其萃，餘品皆臣僕。", "先春擷靈芽，妙手截玄玉。", "形模正而方，氣韵清不俗。", "故將比君子，可敬不可辱。", "御史萬夫特，剛腸憎軟熟。", "味此道之腴，清泠肺肝沃。", "精新味多得，烹啜不忍獨。", "磊落分貢包，殷勤寄心曲。", "斯時屬徂暑，低頭困煩溽。", "一甌瀹花乳，精神驚滿腹。", "此物雪昏滯，敏妙如破竹。", "誰知霜臺傑，功用更神速。", "莫辭風采凜，要使班列肅。", "一朝奮孤忠，萬代仰高躅。"]'),
('7cb6fdf1-d4c0-430b-a1b6-f4db4b7af628','題豢龍圖','袁燮','宋','宋诗','song-poetry','','[]','良馬苦羈馽，巨魚畏網罟。',216,'全唐诗/poet.song.168000.json','["良馬苦羈馽，巨魚畏網罟。", "神龍獨超軼，威燄莫能禦。", "噓爲寒空雲，散作無邊雨。", "能幽復能明，可敬不可侮。", "如何豢龍氏，狎玩等兒女。", "巍然受其朝，勁氣金石沮。", "龍兮喪其魄，聽命無敢拒。", "矧復察秋毫，洞見龍肺腑。", "飲食不强致，嗜好隨所取。", "日日飽甘滋，馴伏固其所。", "誰謂有餘知，拘牽乃如許。", "人生天地間，良心實爲主。", "利慾汩其真，甘與俗子伍。", "胡不鑒此圖，保養虛明府。", "道義有真樂，不羨圭與組。", "於我如浮雲，服膺聖師語。", "吾家素風在，辛苦立門戶。", "勇決早抽身，從我涉幽圃。"]'),
('64cddf60-32a0-4818-a771-fcb57c5e7290','題朝鯉圖','袁燮','宋','宋诗','song-poetry','','[]','魚品不勝多，而鯉爲之宗。',168,'全唐诗/poet.song.168000.json','["魚品不勝多，而鯉爲之宗。", "曷爲此獨貴，無乃能爲龍。", "一躍浪千級，一噓雲萬重。", "變化須臾間，神妙無終窮。", "其他點額輩，不敢攀高蹤。", "維人亦如是，拔萃斯爲雄。", "聖師名其子，勉以德業崇。", "我作朝鯉圖，一鯉居其中。", "衆鯉競趨之，若效臣子恭。", "巨鱖獨不朝，悍然欲爭鋒。", "可憐汝無識，不揆資凡庸。", "一生只爲魚，鯉豈汝可同。", "我亦不如鯉，年老無成功。", "時時展此卷，著鞭期變通。"]'),
('054b47a6-70fa-4bc2-bd88-b9085b55e9ab','鳳仙花','袁燮','宋','宋诗','song-poetry','','[]','鳳仙窈窕姿，階前爲誰容。',288,'全唐诗/poet.song.168000.json','["鳳仙窈窕姿，階前爲誰容。", "淺深十八本，形貌紛不同。", "或饒鮮明色，巧笑雙頰豐。", "或作掩抑態，擡舉差且慵。", "憂彼積雨摧，愛此晴日烘。", "施粉聊自喜，奪朱巧爭雄。", "熒熒似得意，慘慘如無悰。", "妍媸孰與分，我欲爲青銅。", "西子信姝麗，無鹽敢希蹤。", "並育亦已難，我欲爲老農。", "美者倍豐殖，惡者加藴崇。", "花神夜見夢，君何太匆匆。", "正復容顔殊，等是紫與紅。", "何貴復何賤，有淡還有濃。", "氣類豈相絕，塗澤間不工。", "胡爲妄憎愛，襟度殊未洪。", "君看宇宙間，物象無終窮。", "化工大鑪鞴，一一歸陶溶。", "而君獨褊心，不少垂帡幪。", "强分青白眼，力辨雌雄風。", "物情固參差，宇宙要擴充。", "一笑謂花神，嗟爾何顓蒙。", "品彙豈無別，畛域固有封。", "有生分美惡，異路生西東。"]'),
('fe40b794-5f2b-484c-833b-c5e03f33fb31','桂花上侯使君','袁燮','宋','宋诗','song-poetry','','[]','秋雨洗殘暑，秋空渺寥廓。',132,'全唐诗/poet.song.168000.json','["秋雨洗殘暑，秋空渺寥廓。", "秋清入花骨，風致殊灑落。", "何人剪瑠璃，被以寶瓔絡。", "英英妙點綴，細細疑紛錯。", "誰知一粟中，十里香噴礴。", "自便金氣爽，不赴東皇約。", "黄裳得中正，無心羨丹雘。", "我欲縱幽賞，村醪不堪酌。", "攀折不辭勞，相對空索寞。", "風流賢使君，襟懷富丘壑。", "敬爲使君壽，芳菲兩相若。"]'),
('529b06e7-e8e7-4890-97db-0cab76dd1bdd','咏竹二首  其一','袁燮','宋','宋诗','song-poetry','','[]','去年種蒼玉，今歲抽華簪。',120,'全唐诗/poet.song.168000.json','["去年種蒼玉，今歲抽華簪。", "初萌節已具，欲奮力未任。", "雷風驅急雨，滂沱三日霖。", "籜龍不許蟄，倏起騰深林。", "遶徑初戢戢，穿籬俄森森。", "吾觀植物性，漸長歲月深。", "此君獨超軼，生來氣駸駸。", "偉哉歲寒種，有此特達心。", "大勇久不作，進尺退復尋。", "對此發幽興，作詩因自箴。"]'),
('243508e5-c364-478c-a314-7da5cf1d8ee2','咏竹二首  其二','袁燮','宋','宋诗','song-poetry','','[]','野性與俗違，澹然都無營。',120,'全唐诗/poet.song.168000.json','["野性與俗違，澹然都無營。", "窗前水蒼玉，未能獨忘情。", "對之三伏中，爽氣高秋橫。", "數竿亦已好，況此繁陰成。", "中虛洞無物，節勁老更清。", "霜雪自凌厲，柯葉長敷榮。", "物意有相合，人心原自明。", "僻居寡朋儕，命汝爲友生。", "雖無切磋語，而有清越聲。", "入耳久亦佳，此意不可名。"]'),
('6837b073-dae0-4de5-8c98-7323fd563a1b','竹几','袁燮','宋','宋诗','song-poetry','','[]','深林碧琅玕，直節空其中。',60,'全唐诗/poet.song.168000.json','["深林碧琅玕，直節空其中。", "截爲小曲几，貫以青絲總。", "自然光瑩質，不費髹漆工。", "偃仰隠背穩，提挈纔指從。", "兒曹莫輕毀，此物便老翁。"]'),
('121b182c-0c30-4375-93cc-d69aa24fd09a','病目','袁燮','宋','宋诗','song-poetry','','[]','年年苦目眚，過午眊不明。',72,'全唐诗/poet.song.168000.json','["年年苦目眚，過午眊不明。", "治之昏轉甚，不治無由平。", "何如閉目坐，湛然萬慮清。", "非治非不治，無思亦無營。", "不勞薰與沐，神全明自生。", "勿忘勿助長，此理真至精。"]'),
('8bf07185-923d-4c0f-9991-3a09bff6a27a','白髭','袁燮','宋','宋诗','song-poetry','','[]','人生惡白髭，鑷去恨不速。',228,'全唐诗/poet.song.168000.json','["人生惡白髭，鑷去恨不速。", "欲留少年容，藻飾欺盲俗。", "欺人實自欺，舉世迷不復。", "黄葉隕秋風，明年會重綠。", "髭白不再黑，白白長相續。", "光陰駒過隙，轉盼黄粱熟。", "青春挽不住，暮景暗相促。", "古人少壯時，耳目萬夫矚。", "今我忽已老，事業未絲粟。", "蒲柳不禁秋，撫己堪慟哭。", "成功固有分，進德豈不足。", "忽將六尺軀，終身甘退縮。", "白髭謹勿摘，留以警錄錄。", "勇奮千里驥，懈怠轅下跼。", "人生百種病，厥根在多欲。", "芟夷藴崇之，庶使茂嘉穀。", "每懷風木感，悲痛纏心曲。", "立身揚令名，此罪儻可贖。", "旦旦鑑白髭，進進毋自辱。"]'),
('5614063e-10b6-4b12-b377-9ef32bbb54b2','他山之石','袁燮','宋','宋诗','song-poetry','','[]','他山之石能攻玉，詩人此意宜三復。',224,'全唐诗/poet.song.168000.json','["他山之石能攻玉，詩人此意宜三復。", "莫嫌山骨太堅峭，足使國珍充韞匱。", "磨礱砥礪功日新，圭璧琮璜光可燭。", "人生行己良獨難，晝夜營營昏利慾。", "欲爲全德古君子，莫棄忠規甘諂曲。", "忠規未必皆我友，言是人非亦可錄。", "彼雖蒙蔽不自知，察人過差窮隠伏。", "聖人閫域未易到，責我謂我追遐躅。", "觀渠待我最深厚，我聽其言當佩服。", "端知良藥苦難堪，已我沈疴功甚速。", "古人聞過每欣喜，要令忠告來相續。", "今我昏怠不自强，逆耳闊疎親軟熟。", "嗟予未免世俗病，每讀古書知不足。", "今朝偶誦攻玉詩，從此聞善三薰沐。"]'),
('7acd581b-bbe4-4931-aa1d-038f27042ec0','昭君祠','袁燮','宋','宋诗','song-poetry','','[]','昭君天賦傾城色，何事君王未曾識。',245,'全唐诗/poet.song.168000.json','["昭君天賦傾城色，何事君王未曾識。", "徘徊顧影無計留，一朝遠嫁匈奴國。", "匈奴風日暗飛塵，昭君絕艷驚國人。", "單于駭嘆昔未覩，甘心保塞爲藩臣。", "從來敗德由女美，褒妲驪姬及西子。", "玉環飛燕更絕佳，遺臭千載堪咨嗟。", "毛生善畫古無有，强把丹青倒妍醜。", "却教尤物擯絕域，能爲君王罄忠益。", "聞說昭君出塞初，朔風蕭颯吹衣裾。", "聊將琵琶寄離恨，痛絕玉顔嬪老胡。", "老胡死矣義當返，慷慨懷歸曾上書。", "君王有詔從胡俗，慟哭薄命終穹廬。", "自古佳人多命薄，亦如才士多流落。", "人才有益尚疏外，佳人無補何可懟。", "君不見蕭生堪猛豈不忠，君王疑信相半終不容。"]'),
('c8ccd350-e4cd-4797-a263-c90cd71e9aea','題吳參議達觀齋','袁燮','宋','宋诗','song-poetry','','[]','朱公胸次清絕塵，吳公當日心相親。',192,'全唐诗/poet.song.168000.json','["朱公胸次清絕塵，吳公當日心相親。", "風流藴藉接前輩，寥寥斯世能幾人。", "達觀名齋深有意，欲把前修相警厲。", "只今吳公德彌劭，始信磨礱成偉器。", "古人心廣體亦胖，紛紛世俗爭豪端。", "己私未克欲求道，窺見一二皆童觀。", "達人大觀觀底事，天地爲物原不貳。", "癢疴疾痛皆吾身，彼我胡爲分賤貴。", "達觀主人心地明，分符贊幕無虧成。", "每言此身非我有，年來直欲非死生。", "白髮紅顔難老態，福祿方隆殊未艾。", "願君善保千金軀，歸覲紫宸鏘劍佩。"]'),
('a5bdcdd6-6e52-4e6e-9a44-d574a51c78e8','和傅大卿喜雪','袁燮','宋','宋诗','song-poetry','','[]','人情誰不愛飛雪，臘中再見尤奇絕。',160,'全唐诗/poet.song.168000.json','["人情誰不愛飛雪，臘中再見尤奇絕。", "對雪吟哦色即空，仙翁洞照無生滅。", "既積既消還復飛，且飛且積俄又非。", "了然不是堅牢玉，緬懷有感蘇公詩。", "誰知潤澤工夫遠，須索詩家爲明辨。", "香風天上亦飛花，較之窮臘功猶淺。", "綠窗怯寒顰翠娥，窮儒忍凍不能歌。", "何如制閫賢師帥，賸喜嘉祥重婆娑。", "鄮山妝點千巖白，全勝輕花飄細麥。", "氣和之應非偶然，善政端由老邦伯。"]'),
('0570d6c8-ba2f-4d07-80da-bf342a3212f8','林寺丞許惠桂花','袁燮','宋','宋诗','song-poetry','','[]','羨君仙隠占龍山，愛君風度超人寰。',160,'全唐诗/poet.song.168000.json','["羨君仙隠占龍山，愛君風度超人寰。", "手移仙葩第一品，布列竹籬松徑間。", "秋來月色轉清好，秋半花蕊方斕斑。", "對花如在月宮裏，誰道人境非天關。", "徹骨濃薰真酷烈，可人佳態原幽閒。", "雖復施朱未嫌赤，定知鄰女難同班。", "聞說名園富奇麗，芬芳次第如循環。", "丹心自與君子合，瓊枝更許諸郎攀。", "我亦生來有花癖，每逢絕艷一解顔。", "知君百金重然諾，和根遣送應不慳。"]'),
('e724887b-dcfb-4b4e-a8b2-33d49876f9dc','和李左藏荔支','袁燮','宋','宋诗','song-poetry','','[]','姑射山中冰雪姿，凜然標格欺寒威。',288,'全唐诗/poet.song.168000.json','["姑射山中冰雪姿，凜然標格欺寒威。", "一經蒙莊品題後，使人起敬如賓尸。", "仙風道骨今何有，韶顔豐頰誇絕奇。", "閩中有美信姝麗，衣被五色光參差。", "熒煌已訝色奪目，柔滑更喜香浮肌。", "天工著意破炎毒，故遣佳實生繁滋。", "旨哉悅口衆所嗜，豈聞來去分招麾。", "其他所産亦有取，游女敢自同宮妃。", "我家甬東萃閩舶，勝事屢入騷人辭。", "有時根拔信宿至，風枝露葉殊未衰。", "雜然紅綠間陳紫，圖牒所在生致之。", "始知河豚與江柱，詩人取譬聊滑稽。", "賓朋恣食水晶顆，殘膏賸馥霑羣兒。", "年來吏役困奔走，此志不展常低垂。", "輕紅釅白不易得，西風每起蓴鱸思。", "忽蒙傑句警偷懦，一洗塵慮忘渴饑。", "此中滋味甚不薄，吾曹嚌嚅當及時。", "揮毫詠物聊復爾，相待莫負平生期。"]'),
('19b6484e-e3a5-4d2a-bb39-6c50cc3a4239','謝毗陵使君惠畫','袁燮','宋','宋诗','song-poetry','','[]','都尉風流貴公子，結交海內知名士。',288,'全唐诗/poet.song.168000.json','["都尉風流貴公子，結交海內知名士。", "磨礱禁臠驕侈習，雅意登山與臨水。", "十幅煙江疊嶂圖，當時展玩忘朝晡。", "老仙一顧歎奇絕，落筆妙語春華敷。", "此詩千載傳不朽，此畫如今寧復有。", "我來薄宦大江濱，無價之珍俄入手。", "一山雄特倚天立，下視羣峰如拱揖。", "斷崖飛出玉虬龍，元氣淋漓鬼神泣。", "山中喬木堪棟梁，山外煙波凝翠光。", "數間野店傍林樾，一葉扁舟浮淼茫。", "往時只誦蘇公句，想像都尉圖中趣。", "豈期今日見逼真，端與前輩同機杼。", "自憐老大無他求，塵勞羈絆空悠悠。", "安得千巖萬壑裏，尋幽擇勝逍遥游。", "我心欲往足無力，縱觀此畫如親歷。", "毗陵使君真可人，嘉惠不啻千金直。", "平生辭受關鑰嚴，茲焉詎敢傷於廉。", "毗陵萬口皆歸重，道義相與吾何嫌。"]'),
('d8b3b33f-f2e4-41c5-ad81-abb85ad6e452','蜀海棠','袁燮','宋','宋诗','song-poetry','','[]','海棠自是花中傑，西蜀此花尤勝絕。',208,'全唐诗/poet.song.168000.json','["海棠自是花中傑，西蜀此花尤勝絕。", "濯錦江邊艷欲然，浣花溪上繁於纈。", "疇昔聞名未識面，對之頓解憂心結。", "東皇著意欲開時，不許芳心輕漏洩。", "風前醉態真嫣媚，雨過啼妝更鮮潔。", "格高不受塵點汙，韵勝須那香酷烈。", "東南顔色豈不佳，甲乙品題終少劣。", "我公胸次秋水瑩，海內人人頌清節。", "世間珍玩一物無，獨此妖嬈費提挈。", "墀間堂下不勝春，頳頰丹唇儼成列。", "嫣然尤物不移人，未害廣平心似鐵。", "幾年隔絕劍閣外，拔擢孤忠自明哲。", "願公持此坐廟堂，天下妍媸要區別。"]'),
('6d0fc6ca-9e73-4172-90b9-8d27c7323f6d','挽丞相忠定公','袁燮','宋','宋诗','song-poetry','','[]','孝皇龍飛策多士，宗英第一天顔喜。',336,'全唐诗/poet.song.168000.json','["孝皇龍飛策多士，宗英第一天顔喜。", "力言萬事實爲原，要與邦家立基址。", "堂堂碩望聳中外，耿耿丹心貫終始。", "紹熙之末天步艱，忠臣義士肝膽寒。", "元樞扶日上黄道，指顧宗社磐石安。", "億萬生靈疑慮釋，轉移愁嘆爲欣懽。", "帝謂忠勞無與並，爰立作相專魁柄。", "大開公道延時髦，相與同心究民病。", "區分玉石殊薰蕕，賢人得志憸人憂。", "不堪狂雲巧妬月，何意積羽能沈舟。", "衡陽道上霜松勁，日色慘澹風颼颼。", "行路咨嗟淚相續，興懷安靖恩難酬。", "皇情愴然思舊德，辨誣雪謗分白黑。", "誅鋤元惡氛翳掃，昭揭殊勳鼎彝勒。", "由來物理屈必伸，況此柱石真偉人。", "萊公獲譴死海上，至今勳績摩蒼旻。", "中興趙李二人傑，亦復身後褒忠純。", "嗟爾讒夫太無識，徒把巧言汙碩德。", "正人摧折不妨榮，爾輩羞愧寧有極。", "蚤知此事悔難追，當年詎敢懷姦欺。", "我作此詩慰忠烈，因爲人間息邪說。"]'),
('1676ccf7-baaf-499a-8f58-cef45b8a36eb','渡江','袁燮','宋','宋诗','song-poetry','','[]','浮天傳自昔，萬古一澄清。',48,'全唐诗/poet.song.168000.json','["浮天傳自昔，萬古一澄清。", "月耿光猶爛，風號勢欲傾。", "滔滔原不竭，漠漠却無聲。", "便欲乘槎去，臨風試濯纓。"]'),
('be3e1afe-5ccd-4be3-8bc2-a15555c4b3cc','送樓尚書赴詔','袁燮','宋','宋诗','song-poetry','','[]','聽履辭榮反舊廬，高堂燕坐每申如。',64,'全唐诗/poet.song.168000.json','["聽履辭榮反舊廬，高堂燕坐每申如。", "肯隨流俗趨邪徑，要使吾身宅廣居。", "告老未能三閲月，趣歸已奉十行書。", "願公努力扶皇極，展盡胸中萬卷餘。"]'),
('ac64f412-c27c-4480-bcaa-27894b1a924e','和孫吉父登第二首  其一','袁燮','宋','宋诗','song-poetry','','[]','幾載英名表一鄉，今年仙籍始浮香。',64,'全唐诗/poet.song.168000.json','["幾載英名表一鄉，今年仙籍始浮香。", "恩隆雲漢頒宸翰，燕賜韶鈞出教坊。", "父子同登尤煒煜，詩騷爲貺轉鏗鏘。", "願言努力酬天造，勉使吾君冠百王。"]'),
('b3875acf-0d12-4952-8db7-237e97e4a2b7','和孫吉父登第二首  其二','袁燮','宋','宋诗','song-poetry','','[]','生平心事渺無涯，老去情悰豈復嘉。',64,'全唐诗/poet.song.168000.json','["生平心事渺無涯，老去情悰豈復嘉。", "便合扁舟歸故隠，却尋小圃種幽花。", "癡兒僥倖居前列，樸學流傳本故家。", "第一不宜貪顯宦，更煩師友護蘭芽。"]'),
('989457cc-fa73-406d-8935-615568215e12','倚天閣','袁燮','宋','宋诗','song-poetry','','[]','西川劍閣偉岡巒，雖得崢嶸苦未寬。',64,'全唐诗/poet.song.168000.json','["西川劍閣偉岡巒，雖得崢嶸苦未寬。", "豈意危欄臨楚望，獲瞻喬岳峙江干。", "雌雄並立排鋒刃，紫翠相縈繡帨鞶。", "珍重主人貪好景，邀賓攬秀俯林端。"]'),
('1da17c8e-5588-4952-8d11-9b625e52f69f','和治中雪後','袁燮','宋','宋诗','song-poetry','','[]','名利那須較有無，登臨樂處即吾廬。',64,'全唐诗/poet.song.168000.json','["名利那須較有無，登臨樂處即吾廬。", "興濃不覺朔風勁，景好貪看晴雪餘。", "竟日送青娛座客，先春解凍躍潛魚。", "與君不但分風月，水色山光總一如。"]'),
('03bfc11e-48f9-4f11-81fc-a9535b3c1bdd','大雪與俞少卿二首  其一','袁燮','宋','宋诗','song-poetry','','[]','由來臘雪兆年豐，新歲還應與臘同。',64,'全唐诗/poet.song.168000.json','["由來臘雪兆年豐，新歲還應與臘同。", "可喜三陽纔應律，便看六出驟漫空。", "緘藏摯獸安林下，約束遺蝗入地中。", "積至尺餘猶未已，始知嘉政與天通。"]'),
('0e1d9d26-c8dd-4cd1-8f82-6886c7c40cb3','大雪與俞少卿二首  其二','袁燮','宋','宋诗','song-poetry','','[]','歉歲隆冬水不冰，鈴齋誰與破愁城。',64,'全唐诗/poet.song.168000.json','["歉歲隆冬水不冰，鈴齋誰與破愁城。", "繽紛忽作纖腰舞，照曜俄添老眼明。", "玉不堅牢終可貴，花非剪刻自然成。", "大田來歲應多稼，看取倉箱處處盈。"]'),
('502adf46-9e49-4d43-b256-ea00ef04fe3a','寄陳伯耕二首  其一','袁燮','宋','宋诗','song-poetry','','[]','風梳雨沐厭馳驅，我馬虺隤我僕痡。',32,'全唐诗/poet.song.168000.json','["風梳雨沐厭馳驅，我馬虺隤我僕痡。", "惟有風流髯主簿，才高不肯混泥塗。"]'),
('84c232e2-5a94-43c4-80c9-32a6e393115c','寄陳伯耕二首  其二','袁燮','宋','宋诗','song-poetry','','[]','阡陌周旋約已成，妓圍纔合更渝盟。',32,'全唐诗/poet.song.168000.json','["阡陌周旋約已成，妓圍纔合更渝盟。", "宴安有毒君休戀，亟爲蒼生決此行。"]'),
('86aad99c-ff42-4186-b12d-8a1bdffcb9b5','贈毛希元二首  其一','袁燮','宋','宋诗','song-poetry','','[]','浮世塵勞墮渺茫，真儒器業要韜藏。',32,'全唐诗/poet.song.168000.json','["浮世塵勞墮渺茫，真儒器業要韜藏。", "誰知寂寞空山裏，修省工夫未易量。"]'),
('b056eebb-09da-4e04-923d-2cc8dbfcbbfa','贈毛希元二首  其二','袁燮','宋','宋诗','song-poetry','','[]','當年駡賊真忠激，今日藏身似隠淪。',32,'全唐诗/poet.song.168000.json','["當年駡賊真忠激，今日藏身似隠淪。", "抱負如君豈無用，會看膏澤潤斯民。"]'),
('a2924d4c-ebb2-4a04-a941-6810eca1a06b','贈史坑冶二首  其一','袁燮','宋','宋诗','song-poetry','','[]','吾儒根本在修身，恬淡無爲樂性真。',32,'全唐诗/poet.song.168000.json','["吾儒根本在修身，恬淡無爲樂性真。", "此性本無塵可去，去塵猶是未離塵。"]'),
('9c4cd42d-8cf4-48e3-8591-95e35943a5c0','贈史坑冶二首  其二','袁燮','宋','宋诗','song-poetry','','[]','公子詞鋒莫敢當，更兼世故飽更嘗。',32,'全唐诗/poet.song.168000.json','["公子詞鋒莫敢當，更兼世故飽更嘗。", "區區殘寇猶侵侮，願試胸中却敵方。"]'),
('25b30072-d892-4a62-8649-be905f5db1c2','再用前韵二首  其一','袁燮','宋','宋诗','song-poetry','','[]','乞取刀圭救病身，韓公于此枉天真。',32,'全唐诗/poet.song.168000.json','["乞取刀圭救病身，韓公于此枉天真。", "何如夜坐忘軀殻，但有纖毫俱是塵。"]'),
('8782dd53-babd-423d-9099-c9ae9be1ee18','再用前韵二首  其二','袁燮','宋','宋诗','song-poetry','','[]','無味之中味最長，東湖居士獨先嘗。',32,'全唐诗/poet.song.168000.json','["無味之中味最長，東湖居士獨先嘗。", "迺知此藥真良藥，何必求他肘後方。"]'),
('8f651349-1920-4ddc-8bef-cd077b9a0b1f','贈陸伯微三首  其一','袁燮','宋','宋诗','song-poetry','','[]','勝士由來挽不前，肯臨高興復翩然。',32,'全唐诗/poet.song.168000.json','["勝士由來挽不前，肯臨高興復翩然。", "浮雲可籋真天馬，應笑駑駘走市廛。"]'),
('0aaf2079-7a7a-4f3e-8d19-9963e9a5cbd5','贈陸伯微三首  其二','袁燮','宋','宋诗','song-poetry','','[]','斗大書齋以絜名，冰壺表裏要清明。',32,'全唐诗/poet.song.168000.json','["斗大書齋以絜名，冰壺表裏要清明。", "如今塵土填胸臆，幸挽滄浪爲濯纓。"]'),
('a47c08b0-b570-4668-b04d-e25036840ee3','贈陸伯微三首  其三','袁燮','宋','宋诗','song-poetry','','[]','自古真才多命薄，欣聞同志不長貧。',32,'全唐诗/poet.song.168000.json','["自古真才多命薄，欣聞同志不長貧。", "堪嗟世道今如許，願爲吾君致此身。"]'),
('1dcc8085-a6ee-44cf-995c-b08d1d2dae5b','贈京尹八首  其一','袁燮','宋','宋诗','song-poetry','','[]','妙年志氣已超然，不肯隨羣苟目前。',32,'全唐诗/poet.song.168000.json','["妙年志氣已超然，不肯隨羣苟目前。", "才美驟爲當世用，青雲直上躡天躔。"]'),
('3d0fbbe3-32fb-4c35-9ba7-9fafc822e5d2','贈京尹八首  其二','袁燮','宋','宋诗','song-poetry','','[]','彈壓工夫妙入神，能令晉盜總奔秦。',32,'全唐诗/poet.song.168000.json','["彈壓工夫妙入神，能令晉盜總奔秦。", "盤根錯節游餘刃，奏課當爲第一人。"]'),
('444663ba-43a0-4c76-9bb7-1941c6ddb87e','贈京尹八首  其三','袁燮','宋','宋诗','song-poetry','','[]','儒學當年究指歸，服勞王事不言疲。',32,'全唐诗/poet.song.168000.json','["儒學當年究指歸，服勞王事不言疲。", "遥知今日張京尹，不瑕閨房畫婦眉。"]'),
('0430ab4d-2a98-4a47-8366-086fb8677097','贈京尹八首  其四','袁燮','宋','宋诗','song-poetry','','[]','年纔六十已爲卿，際會明時蚤顯榮。',32,'全唐诗/poet.song.168000.json','["年纔六十已爲卿，際會明時蚤顯榮。", "祿厚恩深何以報，惟當努力罄忠誠。"]'),
('cedca274-869c-4182-8a81-23dc9867328d','贈京尹八首  其五','袁燮','宋','宋诗','song-poetry','','[]','吾徒切己無他事，萬善根源一片心。',32,'全唐诗/poet.song.168000.json','["吾徒切己無他事，萬善根源一片心。", "外若崢嶸中有愧，何殊麋鹿强冠襟。"]'),
('1e8e0920-b83b-4fef-a6b5-d7ecdd5323b7','贈京尹八首  其六','袁燮','宋','宋诗','song-poetry','','[]','美名疇昔藹循良，重任今茲典浩穰。',32,'全唐诗/poet.song.168000.json','["美名疇昔藹循良，重任今茲典浩穰。", "摯若蒼鷹非不健，何如鸞鳳效嘉祥。"]'),
('d214be2c-e4d2-42a0-a279-51c2ee32e860','贈京尹八首  其七','袁燮','宋','宋诗','song-poetry','','[]','前古哲人端可法，遺編遐躅尚堪尋。',32,'全唐诗/poet.song.168000.json','["前古哲人端可法，遺編遐躅尚堪尋。", "公餘莫厭頻繙閱，要使胸中廣且深。"]'),
('b1f55348-c034-49b8-8373-2a41bd26bc2d','贈京尹八首  其八','袁燮','宋','宋诗','song-poetry','','[]','上醫醫國豈無方，讜論扶持弱必强。',32,'全唐诗/poet.song.168000.json','["上醫醫國豈無方，讜論扶持弱必强。", "屹若中流爲砥柱，男兒如此是真剛。"]'),
('94aabb58-6e3c-4755-a83a-42f6af6b7e15','與韓撫幹大倫八首  其一','袁燮','宋','宋诗','song-poetry','','[]','故國由來重世臣，芬芳累葉鎮如新。',32,'全唐诗/poet.song.168000.json','["故國由來重世臣，芬芳累葉鎮如新。", "中興第一功臣裔，卓犖如君信有人。"]'),
('0241d716-0b28-4533-8299-a61368530c5f','與韓撫幹大倫八首  其二','袁燮','宋','宋诗','song-poetry','','[]','肯隨流俗慕紛華，閉戶觀書遍五車。',32,'全唐诗/poet.song.168000.json','["肯隨流俗慕紛華，閉戶觀書遍五車。", "器業要爲當世用，直須渟蓄渺無涯。"]'),
('65aaf780-bcbf-4d82-bb24-f9e9431f891e','與韓撫幹大倫八首  其三','袁燮','宋','宋诗','song-poetry','','[]','等閒援筆賦新篇，句法新奇思涌泉。',32,'全唐诗/poet.song.168000.json','["等閒援筆賦新篇，句法新奇思涌泉。", "絕勝唐人作詩苦，推敲一字强雕鎸。"]'),
('9a01072b-59dd-4a97-8bdc-bcb9c851e7ed','與韓撫幹大倫八首  其四','袁燮','宋','宋诗','song-poetry','','[]','幾年慣踏軟紅塵，終日眉攢氣不伸。',32,'全唐诗/poet.song.168000.json','["幾年慣踏軟紅塵，終日眉攢氣不伸。", "每到山齋聞好語，令人胸臆便生春。"]'),
('e39e6329-4754-47ee-81af-ccbcb0dbb424','與韓撫幹大倫八首  其五','袁燮','宋','宋诗','song-poetry','','[]','劇談時事言皆驗，籌略知非小丈夫。',32,'全唐诗/poet.song.168000.json','["劇談時事言皆驗，籌略知非小丈夫。", "獨恨人微言不效，未能推挽上亨衢。"]'),
('8794b9a6-6b34-4784-b578-23ddd84f37c4','與韓撫幹大倫八首  其六','袁燮','宋','宋诗','song-poetry','','[]','思君風度心如結，何日從容迭獻酬。',32,'全唐诗/poet.song.168000.json','["思君風度心如結，何日從容迭獻酬。", "凉入郊墟能過我，奉陪童育兩山游。"]'),
('c8113601-7aba-4677-b242-bdd8bea9b6b0','與韓撫幹大倫八首  其七','袁燮','宋','宋诗','song-poetry','','[]','年幾五十無知己，乘興將爲劍閣行。',32,'全唐诗/poet.song.168000.json','["年幾五十無知己，乘興將爲劍閣行。", "從此與君尤隔絕，興懷疇昔若爲情。"]'),
