('ff0faff1-a0f3-4779-963e-6649e24b4ebc','石井泉  其三','徐誼','宋','宋诗','song-poetry','','[]','發揮有待天須靳，隠顯人間未得知。',32,'全唐诗/poet.song.168000.json','["發揮有待天須靳，隠顯人間未得知。", "翰林主人工墨客，它年稚子亦能詩。"]'),
('7ef875ab-956e-443d-8e5c-5ed8d2706015','謫官南康軍','徐誼','宋','宋诗','song-poetry','','[]','花飛片片上衣襟，拾得飛花寘柳陰。',32,'全唐诗/poet.song.168000.json','["花飛片片上衣襟，拾得飛花寘柳陰。", "莫遣便隨流水去，東君應有惜花心。"]'),
('c4fef005-7cba-4096-b3e4-c5c75644a944','遊溈山','徐誼','宋','宋诗','song-poetry','','[]','我行之宜陽，便作大仰遊。',96,'全唐诗/poet.song.168000.json','["我行之宜陽，便作大仰遊。", "上有參天松，下有漱石流。", "群峰拱梵宇，層層閟清幽。", "老禪雅愛客，要作數日留。", "泉石療我饑，竹風銷我憂。", "征塵積經年，可以少滌不。", "絕勝秋江上，獨釣滄浪舟。", "所恨招不來，莫我更唱酬。"]'),
('43087596-f84c-428f-9f60-e7fc178dd08d','玉梁觀','曾三聘','宋','宋诗','song-poetry','','[]','道人抱道常避人，閉門三月不識春。',96,'全唐诗/poet.song.168000.json','["道人抱道常避人，閉門三月不識春。", "風風雨雨不相識，起迎北斗生精神。", "夜來夢揖梅子真，脫胎換骨隔一塵。", "玉池生液銀河潤，嚥𠻳自有元和津。", "山中且住不須去，九仙嶺上雲迷路。", "擣餘藥裹卧松根，只在丁當鳥鳴樹。"]'),
('a7aa3025-1bbb-4cd6-91bc-33bf694f7453','携茶訪楊東山','曾三異','宋','宋诗','song-poetry','','[]','搴衣不待履霜回，到得如今亦樂哉。',64,'全唐诗/poet.song.168000.json','["搴衣不待履霜回，到得如今亦樂哉。", "泓穎有時供戲劇，軒裳無用任塵埃。", "眉頭猶自懷千恨，興到何如酒一杯。", "知道華山方睡覺，打門聊伴茗奴來。"]'),
('b234e8be-09a8-4b97-b9d8-d112f0ee149f','上陳縣尹','劉爚','宋','宋诗','song-poetry','','[]','舊尹龔熊負令名，至今天日共清明。',64,'全唐诗/poet.song.168000.json','["舊尹龔熊負令名，至今天日共清明。", "案頭未有人稱屈，村裏全無吏敢行。", "滿院茶香敲句穩，一簾花影韵琴清。", "後之學者誰其似，又說陳公政有聲。"]'),
('782d6a84-2965-4f7f-bee8-fc592dc69859','挽蔡西山先生','劉爚','宋','宋诗','song-poetry','','[]','知君嬰世患，垂白竄南方。',48,'全唐诗/poet.song.168000.json','["知君嬰世患，垂白竄南方。", "四海皆稱屈，群兒苦中傷。", "天資隨世殞，遺恨與天長。", "但誦箕山曲，招魂葬故鄉。"]'),
('1e3fc9df-4962-48b1-818d-f7351efa5cb0','過偏嶺','劉爚','宋','宋诗','song-poetry','','[]','山行千里如井底，仰視但見山頭煙。',32,'全唐诗/poet.song.168000.json','["山行千里如井底，仰視但見山頭煙。", "今朝過嶺一縱目，無窮平野無窮天。"]'),
('dc718dfc-326a-439d-8e3b-5be8da441de5','劉寺即事','劉爚','宋','宋诗','song-poetry','','[]','不到茲山二十年，豈知重見舊山川。',32,'全唐诗/poet.song.168000.json','["不到茲山二十年，豈知重見舊山川。", "煙深雖不見湖水，且看長空萬里天。"]'),
('6757f230-c389-4282-a299-1ef9917580c7','仙學堂','劉爚','宋','宋诗','song-poetry','','[]','蒼崖閟仙館，時有讀書聲。',36,'全唐诗/poet.song.168000.json','["蒼崖閟仙館，時有讀書聲。", "餘韵出雲表，泠泠清風生。", "從之不可得，悵望傷我情。"]'),
('fd2841f0-803a-46df-99e5-bd84b8a50e79','句','劉爚','宋','宋诗','song-poetry','','[]','雲影猶带濕，日光初漏明。',12,'全唐诗/poet.song.168000.json','["雲影猶带濕，日光初漏明。"]'),
('bf1bb178-f436-47d0-9618-0276d4ece99c','送程傅叟赴官臨海','陳謙','宋','宋诗','song-poetry','','[]','金華仙伯歌襦久，休父仍孫歛版遲。',64,'全唐诗/poet.song.168000.json','["金華仙伯歌襦久，休父仍孫歛版遲。", "堂下言高鬷蔑惡，官中事了傅咸癡。", "苦心纔覩千年餘，垂翅新翻六月池。", "接淅中山聽餘令，徵黄敕使立多時。"]'),
('b2fc6bad-0dae-455f-ab0c-9841f2fabc8a','送王孟同館黄巖見王簡卿侍郎','陳謙','宋','宋诗','song-poetry','','[]','吾子勇出鄉，賣文供啜菽。',96,'全唐诗/poet.song.168000.json','["吾子勇出鄉，賣文供啜菽。", "誰指石頭路，路滑去能速。", "大溪拍天流，返壑僅盈掬。", "神化闕功能，善世眩兼獨。", "寶瑟迹已陳，閥閲在林麓。", "飽盡天下眼，觀我亦具足。", "尚論宇宙廣，落處即爲福。", "請子房魏偕，點入丹青錄。"]'),
('35994146-41a0-49cd-82c0-601eb35b04e1','溫州劉教授石塔','陳謙','宋','宋诗','song-poetry','','[]','長劉提正律，折衝陳堂堂。',48,'全唐诗/poet.song.168000.json','["長劉提正律，折衝陳堂堂。", "少劉峙其躬，凜凜百鍊剛。", "獨立百世後，共分淵孟香。", "近市人不知，公論在八荒。"]'),
('2a6713e8-d7ba-4800-8203-f85715f29b93','曲臺','陳謙','宋','宋诗','song-poetry','','[]','宗伯舊爲丞，曲臺今作長。',24,'全唐诗/poet.song.168000.json','["宗伯舊爲丞，曲臺今作長。", "欽聞孔聖言，德理政刑上。"]'),
('f3b814fc-8546-4e5b-8832-5690ec7a32ed','凌丹亭  其一','陳謙','宋','宋诗','song-poetry','','[]','夜半脚心生熱雲，真人得法此其真。',32,'全唐诗/poet.song.168000.json','["夜半脚心生熱雲，真人得法此其真。", "只緣露泄天機子，將身却近帝王尊。"]'),
('ebc27ecc-982a-4553-83aa-1ddd4fc1d7a3','凌丹亭  其二','陳謙','宋','宋诗','song-poetry','','[]','虛靜前知固常理，弄丸先生昔如此。',32,'全唐诗/poet.song.168000.json','["虛靜前知固常理，弄丸先生昔如此。", "不曾驚動世間人，須信是中元沒事。"]'),
('262bcaa4-db5f-4866-ab69-8e030b7c1519','凌丹亭  其三','陳謙','宋','宋诗','song-poetry','','[]','松釵滿地竹無聲，已將蛻羽鎖丹陵。',32,'全唐诗/poet.song.168000.json','["松釵滿地竹無聲，已將蛻羽鎖丹陵。", "漱津覓字俱陳跡，又有入山來乞靈。"]'),
('30f2c17c-2c3a-439e-8a26-3d4e0dfc8d27','鄂州南樓','陳謙','宋','宋诗','song-poetry','','[]','折羽沉絃思杳茫，南樓依舊倚斜陽。',64,'全唐诗/poet.song.168000.json','["折羽沉絃思杳茫，南樓依舊倚斜陽。", "江湖草樹不相識，吳蜀舟車秪自忙。", "萬里秋聲驚客枕，一天凉月浸胡床。", "古今多少英雄恨，認取江南舊武昌。"]'),
('addf8714-3a4d-450e-aa4c-f06912ba85fd','瞿唐峽','陳謙','宋','宋诗','song-poetry','','[]','庸蜀諸羌水，荆吳萬里渾。',48,'全唐诗/poet.song.168000.json','["庸蜀諸羌水，荆吳萬里渾。", "不將崖約束，焉免壑崩奔。", "線引溫湯浦，觴浮雪水源。", "槎程疑欲盡，西望氣魂魂。"]'),
('83bb4ccf-ef1f-4cd4-9aa8-84a53a610ca8','華盖山','陳謙','宋','宋诗','song-poetry','','[]','廛隠築東山，林高撼翠寒。',48,'全唐诗/poet.song.168000.json','["廛隠築東山，林高撼翠寒。", "雲藏安石館，竹掃葛仙壇。", "徑繞泉鳴壑，天低月近欄。", "秋風扶杖屨，漉酒助君歡。"]'),
('eb03b9f3-bf18-41eb-a5e5-763e18feb8de','句  其一','陳謙','宋','宋诗','song-poetry','','[]','青衫夜半何曾著，引興參差雜椒糈。',16,'全唐诗/poet.song.168000.json','["青衫夜半何曾著，引興參差雜椒糈。"]'),
('133a756c-dec8-46c3-80e7-b8a37791bd79','句  其二','陳謙','宋','宋诗','song-poetry','','[]','萬卷編抄高似屋，一門師友重如山。',16,'全唐诗/poet.song.168000.json','["萬卷編抄高似屋，一門師友重如山。"]'),
('d4f6ca4a-2a41-4299-9b99-b2f6a4e6e5f4','詠松','李訦','宋','宋诗','song-poetry','','[]','半依巖岫倚雲端，獨立亭亭耐歲寒。',32,'全唐诗/poet.song.168000.json','["半依巖岫倚雲端，獨立亭亭耐歲寒。", "一事頗爲清節累，秦時曾作大夫官。"]'),
('ff45aebf-083d-459b-81c6-8e7795ea66dc','謁丞相祠觀八陣圖','李訦','宋','宋诗','song-poetry','','[]','人言忠孝不磨滅，神物護持存水滸。',160,'全唐诗/poet.song.168000.json','["人言忠孝不磨滅，神物護持存水滸。", "千家陵谷幾變遷，此石不移自章武。", "本由黄帝古兵法，六十四以八爲伍。", "髯孫且懼仲達走，賊操遊魂何敢拒。", "刻銘沙石水底碑，教戰石存山下鼓。", "一片丹心天地間，萬世聞風猶禦侮。", "我來起敬凜如生，再拜一言公必取。", "瀼流東截陣圖前，寖隳城壁頹民宇。", "能安拳石止波流，願回瀼患思民撫。", "常使夔人知感公，踏磧年年弔千古。"]'),
('2c1c099d-639c-42a9-9907-27c4d8668d83','控巴臺次韵  其一','李訦','宋','宋诗','song-poetry','','[]','翠岸紅燈寄語，要自江南看來。',28,'全唐诗/poet.song.168000.json','["翠岸紅燈寄語，要自江南看來。", "多景齊雲樓下，當年使鷁招回。"]'),
('55da303a-d83a-4c99-8b58-125c5ecd9f44','控巴臺次韵  其二','李訦','宋','宋诗','song-poetry','','[]','誰道地拘偪窄，須知天閟幽妍。',28,'全唐诗/poet.song.168000.json','["誰道地拘偪窄，須知天閟幽妍。", "一段丹青臺閣，何人淡掃松烟。"]'),
('9d78971a-2b1f-4136-bf09-953f83482ecd','題平亭','李訦','宋','宋诗','song-poetry','','[]','狄公有記記蠻平，蠻不難平將貴精。',32,'全唐诗/poet.song.168000.json','["狄公有記記蠻平，蠻不難平將貴精。", "勉矣諸君修將業，請將平字作亭名。"]'),
('49b71c84-5294-4022-8370-fd9af6bc4e14','詠芍藥','謝堯仁','宋','宋诗','song-poetry','','[]','花蓓大如拳，花面或徑尺。',120,'全唐诗/poet.song.168000.json','["花蓓大如拳，花面或徑尺。", "紫者棲紫鸞，黄者浴黄鵠。", "或似扶桑枝，推上一輪赤。", "或似玻璃盆，稍久擎無力。", "又有似平叔，愛矜素粉白。", "又有似蜀人，喜染天水碧。", "或似包綠錦，未放丹砂折。", "或似浴青囊，未放沉麝發。", "應須和露剪，莫使見日色。", "廣陵精神全，免笑花無骨。"]'),
('b3795524-f778-432e-87b0-249e1545f45d','荷花','謝堯仁','宋','宋诗','song-poetry','','[]','奇奇水上花，湛湛花下水。',48,'全唐诗/poet.song.168000.json','["奇奇水上花，湛湛花下水。", "花得水扶持，水因花富貴。", "當中既植藕，四畔還種葦。", "自然秋風生，便有江湖意。"]'),
('099b18b8-c377-46fb-b633-6662432aab5e','酴醿','謝堯仁','宋','宋诗','song-poetry','','[]','下騰赤蛟身，上抽碧龍頭。',60,'全唐诗/poet.song.168000.json','["下騰赤蛟身，上抽碧龍頭。", "千枝蟠一蓋，一蓋簪萬毬。", "花要带月看，香要和露收。", "一點落衣袂，經月氣未休。", "一點入釀甕，經歲味尚留。"]'),
('5d6b7f26-71cb-4cdc-88a2-e9412d09b912','九日登屏山','謝堯仁','宋','宋诗','song-poetry','','[]','有約携壺九日遊，扶筇選勝豁雙眸。',64,'全唐诗/poet.song.168000.json','["有約携壺九日遊，扶筇選勝豁雙眸。", "天空晴送羣峰翠，野曠寒生落木愁。", "濁酒故饒狂士態，黄花羞插老人頭。", "憑高不管風吹帽，坐破屏山一色秋。"]'),
('948e4293-44c8-4264-a67e-dfd221222e27','句','謝堯仁','宋','宋诗','song-poetry','','[]','半夜鬼神朝水府，五更鼓角動揚州。',16,'全唐诗/poet.song.168000.json','["半夜鬼神朝水府，五更鼓角動揚州。"]'),
('e74db8da-13a7-403b-ac5a-8dac10f11104','辭靈康廟留題','劉坦之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','木落天高廟妥靈，去來潮汐繞山青。',64,'全唐诗/poet.song.168000.json','["木落天高廟妥靈，去來潮汐繞山青。", "年登民俗饒怡樂，海近蛟虯入杳冥。", "萬里一身頭既白，清樽三奠德惟馨。", "出門更合燒沈炷，青草連雲接洞庭。"]'),
('b44b865b-a160-4164-990e-1c5c457b9003','雲洲','郭師元','宋','宋诗','song-poetry','','[]','昭代元豐日，雲洲致瑞祥。',48,'全唐诗/poet.song.168000.json','["昭代元豐日，雲洲致瑞祥。", "氤氳浮嶺表，精彩燦霞光。", "德政聞名邑，文章冠試場。", "二人符美應，今古共流芳。"]'),
('00b8c3a0-5cda-4b7a-be56-eef5611ec46a','和經略直閣寺丞贈劉升之蟄龍巖二首  其一','唐弼','宋','宋诗','song-poetry','','[]','古人事業不關書，聖處工夫咏舞雩。',32,'全唐诗/poet.song.168000.json','["古人事業不關書，聖處工夫咏舞雩。", "窈窕崖居辱題品，南陽端有卧龍無。"]'),
('2b9a5d43-df10-4797-869a-7d091c79dff3','和經略直閣寺丞贈劉升之蟄龍巖二首  其二','唐弼','宋','宋诗','song-poetry','','[]','倚天寒碧鎖嵌空，咫尺丹霄有路通。',32,'全唐诗/poet.song.168000.json','["倚天寒碧鎖嵌空，咫尺丹霄有路通。", "莫向明時縮頭角，風雲只在笑談中。"]'),
('e382d732-d84b-4f3d-a1f7-de0104284a13','三洲巖','唐弼','宋','宋诗','song-poetry','','[]','峒裏光陰經幾春，峒前蒼木垂千尋。',64,'全唐诗/poet.song.168000.json','["峒裏光陰經幾春，峒前蒼木垂千尋。", "不知空谷當年事，誰識龐眉處士心。", "殘月照人吞遠徼，晚風吹夢入幽岑。", "我來須訪神仙宅，好聽雲端環佩音。"]'),
('f6e1d39e-daba-4937-9bf6-0cce940f0636','汀州','陳映','宋','宋诗','song-poetry','','[]','元豐陳汀州，見謂黄太史。',24,'全唐诗/poet.song.168000.json','["元豐陳汀州，見謂黄太史。", "年登境無蝗，政恐不相似。"]'),
('ee0e996a-9564-4072-a8c5-d825165ecf89','北樓','陳映','宋','宋诗','song-poetry','','[]','南澗吹雲過北團，北山飛鳥入南山。',32,'全唐诗/poet.song.168000.json','["南澗吹雲過北團，北山飛鳥入南山。", "區區雲鳥緣何事，未似風流太守閒。"]'),
('d6296957-29d4-41ba-b500-4c4335bf3eea','句','陳映','宋','宋诗','song-poetry','','[]','鄞江一丈水，清可照人心。',12,'全唐诗/poet.song.168000.json','["鄞江一丈水，清可照人心。"]'),
('fc9312ec-a157-47b7-aca4-b28c1df450c0','環溪夜坐','吳璋','宋','宋诗','song-poetry','','[]','江天閒晚已斜陽，靜掩柴門對草堂。',64,'全唐诗/poet.song.168000.json','["江天閒晚已斜陽，靜掩柴門對草堂。", "葉落轉枝翻鶻影，星飛橫水带螢光。", "微風得雋驅殘暑，新月出音生嫩凉。", "坐覺秋容轉清爽，一聲漁笛在滄浪。"]'),
('249925b7-2261-4860-9a9d-ba007e436040','上人陳情十首之一','吳璋','宋','宋诗','song-poetry','','[]','下筆非能不自休，清談未足第三流。',64,'全唐诗/poet.song.168000.json','["下筆非能不自休，清談未足第三流。", "夢中讀易疑神動，醉裏吟詩想鬼愁。", "飛鶻豈徒驚燕雀，騎馿直欲度驊騮。", "此君須異無人識，慚愧當年遇褚裒。"]'),
('9658aaf6-22f2-4d62-885f-afbbec23e424','句  其一','吳璋','宋','宋诗','song-poetry','','[]','各自芬芳花默默，兩相呼喚鳥津津。',16,'全唐诗/poet.song.168000.json','["各自芬芳花默默，兩相呼喚鳥津津。"]'),
('88ff7c02-698a-439b-aa3e-f6db2fdc1ff6','句  其二','吳璋','宋','宋诗','song-poetry','','[]','風急城闉砧杵動，雨餘園圃轆轤收。',16,'全唐诗/poet.song.168000.json','["風急城闉砧杵動，雨餘園圃轆轤收。"]'),
('6047113e-1bb7-4ff9-a74c-a467e067308f','句  其三','吳璋','宋','宋诗','song-poetry','','[]','始訝長郊從此斷，忽驚行客近前來。',16,'全唐诗/poet.song.168000.json','["始訝長郊從此斷，忽驚行客近前來。"]'),
('2a044680-5595-418b-9ab6-2626b1a789a1','句  其四','吳璋','宋','宋诗','song-poetry','','[]','倒懸欲墮花如綴，背立將飛鳥似驚。',16,'全唐诗/poet.song.168000.json','["倒懸欲墮花如綴，背立將飛鳥似驚。"]'),
('ebd2b5d5-c7da-4407-986e-f6c32b55e74d','句  其五','吳璋','宋','宋诗','song-poetry','','[]','池塘不用夢春草，風雪何須在灞橋。',16,'全唐诗/poet.song.168000.json','["池塘不用夢春草，風雪何須在灞橋。"]'),
('b4e87768-3d2f-4064-8a89-14a784dd6789','句  其六','吳璋','宋','宋诗','song-poetry','','[]','惜別有情空執手，贈行無緒不成章。',16,'全唐诗/poet.song.168000.json','["惜別有情空執手，贈行無緒不成章。"]'),
('35d367b3-7f07-4de5-b450-17ed9eaafa3e','句  其七','吳璋','宋','宋诗','song-poetry','','[]','雁飛雲抹欹斜字，魚躍波摇出沒星。',16,'全唐诗/poet.song.168000.json','["雁飛雲抹欹斜字，魚躍波摇出沒星。"]'),
('5bd3acda-f7de-46cc-a7c6-a1d5c36f16b3','句  其八','吳璋','宋','宋诗','song-poetry','','[]','水流天際驚春動，山入雲間鬭碧攢。',16,'全唐诗/poet.song.168000.json','["水流天際驚春動，山入雲間鬭碧攢。"]'),
('d1124b36-5ca3-4a95-b9af-1f8af015a377','句  其九','吳璋','宋','宋诗','song-poetry','','[]','地暖尚疑消玉馬，雲開早欲放金雅。',16,'全唐诗/poet.song.168000.json','["地暖尚疑消玉馬，雲開早欲放金雅。"]'),
('aaaae46e-ed97-412b-ad5d-73d4d53b2ca7','句  其一○','吳璋','宋','宋诗','song-poetry','','[]','衣無錦繡勞心織，味乏膏粱困舌耕。',16,'全唐诗/poet.song.168000.json','["衣無錦繡勞心織，味乏膏粱困舌耕。"]'),
('f56ed2d7-10dd-475a-82e3-d280554caee0','句  其一一','吳璋','宋','宋诗','song-poetry','','[]','閒中坐作蜘蛛隠，夢裏逃成燕雀禪。',16,'全唐诗/poet.song.168000.json','["閒中坐作蜘蛛隠，夢裏逃成燕雀禪。"]'),
('349db9cc-216d-4941-9a70-fdc22cfbe646','句  其一二','吳璋','宋','宋诗','song-poetry','','[]','弈棋但以忘憂耳，縱酒無如作病何。',16,'全唐诗/poet.song.168000.json','["弈棋但以忘憂耳，縱酒無如作病何。"]'),
('475283f6-0a55-490e-a7bf-e2178a05597b','句  其一三','吳璋','宋','宋诗','song-poetry','','[]','龍肝雉尾瓜蓴好，玉核金槌棗柰香。',32,'全唐诗/poet.song.168000.json','["龍肝雉尾瓜蓴好，玉核金槌棗柰香。", "只有牛心猶未割，願如逸少得先嘗。"]'),
('7a353641-5c6c-4dcb-815a-94c2af4cedd8','春日焦山觀瘞鶴銘','吳琚','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昔愛山樵書，今踏山樵路。',120,'全唐诗/poet.song.168000.json','["昔愛山樵書，今踏山樵路。", "江邊春事動，梅柳皆可賦。", "犖确石徑微，白浪灑衣履。", "臨淵魚龍驚，捫崖猿鳥懼。", "古刻難細讀，斷缺蒼蘚護。", "歲月豈易考，書法但增慕。", "摩挲復三歎，欲去還小住。", "習氣未掃除，齒髮恨遲暮。", "華亭鶴自歸，長江只東注。", "寂寥千古意，落日起煙霧。"]'),
('50c059e6-2af9-4665-b4a4-362974a16b73','牡丹','吳琚','宋','宋诗','song-poetry','','[]','牡丹乘春芳，風雨苦相妬。',48,'全唐诗/poet.song.168000.json','["牡丹乘春芳，風雨苦相妬。", "朝來小庭中，零落已無數。", "魂銷梓澤國，腸斷馬嵬路。", "盡日向欄干，踟躕不能去。"]'),
('48875b06-7781-47fc-a2f9-b56c85e1b368','句  其一','吳琚','宋','宋诗','song-poetry','','[]','細看爽氣無朝暮，浪說元規塵污人。',16,'全唐诗/poet.song.168000.json','["細看爽氣無朝暮，浪說元規塵污人。"]'),
('e41246e8-6441-4d5f-8065-1f51961ce508','句  其二','吳琚','宋','宋诗','song-poetry','','[]','春歸百卉今無幾，獨立清微殿閣風。',16,'全唐诗/poet.song.168000.json','["春歸百卉今無幾，獨立清微殿閣風。"]'),
('62ea9c9b-0ef8-4652-8bf5-99e6bdceca39','湖上命酒作','尤棐','宋','宋诗','song-poetry','','[]','長風捲急雨，蕭條湖上來。',72,'全唐诗/poet.song.168000.json','["長風捲急雨，蕭條湖上來。", "癡雲低壓樹，雷霆助喧豗。", "雨過了無跡，萬物萌新荄。", "化機本無滯，爽氣先暗催。", "披衣一延攬，中情其徘徊。", "浩然觀太空，薄言命尊罍。"]'),
('df496db0-5a4a-4480-ba76-12e3c17fc230','飲翁常之宅分韵得友字','陳峴','宋','宋诗','song-poetry','','[]','杖屨隨春風，邂逅得良友。',72,'全唐诗/poet.song.168000.json','["杖屨隨春風，邂逅得良友。", "行行西域道，觸目盡花柳。", "還步過茆茨，交歡亦何有。", "東鄰頗好事，邀我意良厚。", "南窗竹風涼，更命新醅酒。", "一醉何足辭，期此百年久。"]'),
('8fa96b6e-07de-43cc-994d-f2056d7555a2','宿董山寺','陳峴','宋','宋诗','song-poetry','','[]','送客聯鑣歸，得得招提宿。',84,'全唐诗/poet.song.168000.json','["送客聯鑣歸，得得招提宿。", "晚渡滄江口，路入青山曲。", "突兀忽在眼，一洗奔馳俗。", "然燈遽呼酒，僧留供野蔌。", "林高上明月，談聲響空谷。", "坐久夜益深，同來或鼾熟。", "明朝返城郭，此興真可錄。"]'),
('2df10ad2-2b0a-4d1c-af8a-b6b8c91da287','雨中偶成','陳峴','宋','宋诗','song-poetry','','[]','雨聲春不絕，綠漲與池平。',48,'全唐诗/poet.song.168000.json','["雨聲春不絕，綠漲與池平。", "久摘花猶好，新鋤草又生。", "閉門惟我獨，終日斷人行。", "對酒還憂病，裁詩强遣情。"]'),
('91d935a1-9073-4348-a23b-d9c291eb0875','舟次鄂州','陳峴','宋','宋诗','song-poetry','','[]','蜀江來滾滾，楚望意悠悠。',48,'全唐诗/poet.song.168000.json','["蜀江來滾滾，楚望意悠悠。", "浩氣高情曉，新寒带晚秋。", "關山方北顧，烟火又南樓。", "蓬鬢天涯客，蕭然一葉舟。"]'),
('3ce4bcac-e21b-419a-9899-75c276b5e074','全州觀風樓','陳峴','宋','宋诗','song-poetry','','[]','江源發蠻荒，來與湘灌遇。',168,'全唐诗/poet.song.168000.json','["江源發蠻荒，來與湘灌遇。", "交流趨城隅，清映日東注。", "群山半楚越，馳驟若競赴。", "譙門百步南，樓堞此雄踞。", "觀風久標名，棟宇初改故。", "極目渺塞嶺，蔚起矗雲霧。", "千里聳翠碧，衆水橫練素。", "古寺带林薄，漁艇依野渡。", "村墟互隠見，風烟自朝暮。", "東西亙井絡，碁分雜營戍。", "偶值豐登年，樂此保生聚。", "秋風黄花天，良集盛簪屨。", "肴觴固匪虔，藉此山水具。", "登臨方興深，諸君幸少駐。"]'),
('116fa91f-ec62-4ec9-abaf-661af30335bb','楚南偉觀樓','陳峴','宋','宋诗','song-poetry','','[]','平生足迹窮遐陬，一麾更守湖湘州。',160,'全唐诗/poet.song.168000.json','["平生足迹窮遐陬，一麾更守湖湘州。", "西接懸崖五溪曲，南望渺極蒼梧愁。", "天涯牢落孰慰意，千嶂倒影三江流。", "千里脈絡茲要會，意趣端與江山投。", "羣峰四遶立碧玉，带映林薄如雕鎪。", "虯蟠虎驟互起伏，天作地涌非凡儔。", "郊村依約半洲渚，遠明天際來歸舟。", "湖南素號清絕地，一旦呈露疑神謀。", "作成英奇易舊觀，俗化遠與鄒魯侔。", "寄語後來無泯沒，共保佳致傳千秋。"]'),
('ee94952b-f781-4d54-8677-0c8d054ce736','郡圃依綠亭','陳峴','宋','宋诗','song-poetry','','[]','修林平沼久荒埃，招領春風一笑回。',64,'全唐诗/poet.song.168000.json','["修林平沼久荒埃，招領春風一笑回。", "掃凈莓苔分徑岸，剩添桃李結亭臺。", "時因休吏文書了，忽作閒人杖屢來。", "待與邦人同醉樂，一樽何惜少徘徊。"]'),
('d59070fb-5570-41e6-853c-4ccfd5d7bcd2','龍隠巖','陳峴','宋','宋诗','song-poetry','','[]','烟蘿深鎖非凡境，泉石相逢似故人。',32,'全唐诗/poet.song.168000.json','["烟蘿深鎖非凡境，泉石相逢似故人。", "歸認落花猶恐誤，天風爲我隔囂塵。"]'),
('66416d90-7ef8-4200-be3e-73bc38e28fdc','全州礲巖','陳峴','宋','宋诗','song-poetry','','[]','泉流縈带戛冰玉，石壁深窈寒侵衣。',32,'全唐诗/poet.song.168000.json','["泉流縈带戛冰玉，石壁深窈寒侵衣。", "開鑿應勞造化力，窟宅如待靈仙歸。"]'),
('62571087-9ac4-475e-9708-3deaf0ce4459','宿西湖凈寺聽僧樂梵唄','趙善漮','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天涯知己集琳宮，文武升沉氣味同。',64,'全唐诗/poet.song.168000.json','["天涯知己集琳宮，文武升沉氣味同。", "仙樂幾回來座上，梵音半夜落天中。", "幻身何日脫塵劫，慧眼於今識色空。", "興盡歸來情不盡，晨昏隠隠麗譙東。"]'),
('2e564cf6-9cf4-418a-afe0-012c38d2e3ad','遊西山  其一','趙善漮','宋','宋诗','song-poetry','','[]','閒向西山頂上游，碧天高掛晚雲收。',64,'全唐诗/poet.song.168000.json','["閒向西山頂上游，碧天高掛晚雲收。", "雨餘花氣濃如酒，風鼓松聲冷似秋。", "險句每驚神鬼泣，雅懷不貯古今愁。", "恍疑身在蓬萊境，笑指前溪當弱流。"]'),
('938e0ccd-c82d-43ec-bc64-a3ef97d79a8d','遊西山  其二','趙善漮','宋','宋诗','song-poetry','','[]','古廟嵯峨占地靈，四山環抱聳螺青。',64,'全唐诗/poet.song.168000.json','["古廟嵯峨占地靈，四山環抱聳螺青。", "松壇鶴去雲無伴，石洞龍歸雨亦腥。", "弛擔樵歌屯別徑，倚蓬漁笛起前汀。", "箇中真覺凝眸豁，一點心無俗慮縈。"]'),
('bbffdb18-957c-4d7e-8074-a710207e0ad7','謝周益公招賞木犀','楊炎正','宋','宋诗','song-poetry','','[]','翠圍侍女擁紅幢，霞臉調朱笑額黄。',64,'全唐诗/poet.song.168000.json','["翠圍侍女擁紅幢，霞臉調朱笑額黄。", "共醉東君千日酒，更翻西母九霞觴。", "人間天上高低影，月下風前自在香。", "輸得廣寒宮裏客，年年綠鬢賞秋光。"]'),
('64f53d7d-e058-45da-b7b0-1842b016beb7','錢塘迎酒歌','楊炎正','宋','宋诗','song-poetry','','[]','錢塘妓女顔如玉，一一紅妝新結束。',192,'全唐诗/poet.song.168000.json','["錢塘妓女顔如玉，一一紅妝新結束。", "問渠結束何所爲，八月皇都酒新熟。", "酒新熟，浮蛆香，十三庫中誰最强。", "臨安大尹索酒嘗，舊有故事須迎將。", "翠翹金鳳烏雲髻，雕鞍玉勒三千騎。", "金鞭爭道萬人看，香塵冉冉沙河市。", "琉璃杯深琥珀濃，新翻曲調聲摩空。", "使君一笑賜金帛，今年酒賽真珠紅。", "畫樓突兀臨官道，處處繡旗誇酒好。", "五陵年少事豪華，一斗十千誰復校。", "黄公壚下謾徜徉，何曾見此大堤倡。", "惜無顔公三十萬，往醉金釵十二行。"]'),
('9045679c-9153-423b-8f2a-e0de550e6f70','贈醫士陳國器','楊炎正','宋','宋诗','song-poetry','','[]','君不曾三折肱，又不曾九折臂，海內行醫稱寡二。',150,'全唐诗/poet.song.168000.json','["君不曾三折肱，又不曾九折臂，海內行醫稱寡二。", "活人無數不言功，隨處得錢供一醉。", "道是宋清君不是，道似洞賓君不似。", "蕭然藍縷一烏巾，喚作醫家湖海士。", "觀君用藥如有神，問君傳方殊不秘。", "胸中活用三八法，二十四證無不治。", "痔兮痔兮果何物，我老甯堪爾爲累。", "五醫十手療不得，直待君來乞良劑。", "病根一去不留殘，勝似并州剪刀利。"]'),
('18bf8bb4-9ecd-4ce5-9a91-379eba504d43','謝朱宰借船','楊炎正','宋','宋诗','song-poetry','','[]','書生祿遬空自憐，三年官滿囊無錢。',128,'全唐诗/poet.song.168000.json','["書生祿遬空自憐，三年官滿囊無錢。", "身如絆驥心千里，安得一舸西風前。", "令君磊落濟川手，留滯亦憐窮獨叟。", "大舟百尺影白虹，借我船家我何有。", "函牛之鼎著雞肋，涓滴渠須瓢五石。", "劣留兩席置圖書，輦石囊沙壓摇兀。", "典衣買酒餉三老，槌鼓鳴鑼人看好。", "相過重讀借船帖，我自盧胡君絕倒。"]'),
('da168af2-caa0-4adc-b097-20f0ac789b30','竹','楊炎正','宋','宋诗','song-poetry','','[]','此君清苦真吾似，更對騷人細說詩。',64,'全唐诗/poet.song.168000.json','["此君清苦真吾似，更對騷人細說詩。", "松鼎炷香無俗韵，荷盤盛果近兒嬉。", "人情上下鷗在水，世事紛紜蛛挂絲。", "已約青山同晚節，一杯當釂莫牢辭。"]'),
('929b2331-3276-42cf-835a-e8f82de6ba52','題鄒氏桂軒','楊炎正','宋','宋诗','song-poetry','','[]','六六天頭一輪月，玉斧修成廣寒闕。',96,'全唐诗/poet.song.168000.json','["六六天頭一輪月，玉斧修成廣寒闕。", "□邊桂樹影婆娑，不許凡人手攀折。", "嫦娥嫁得月中仙，桂呈丹蕊月宮前。", "香風散盡花結子，子落下土生風烟。", "君家對月開軒戶，占斷風烟最佳處。", "花開天上定聞香，乘風快問蟾宮路。"]'),
('6c89b257-40d0-4ee7-b44a-5995e23c6f8d','送詩卷還周益公','楊炎正','宋','宋诗','song-poetry','','[]','萬象供吟景不慳，文窮催入鬢毛斑。',64,'全唐诗/poet.song.168000.json','["萬象供吟景不慳，文窮催入鬢毛斑。", "譚犀豈止退三舍，識豹僅能窺一虨。", "水落舊痕溪石出，風收新雨嶺雲閑。", "湖山千里無逃景，都入騷人卷軸間。"]'),
('54e39d5e-c733-4199-be2f-3d76485aabbb','壽周益公  其一','楊炎正','宋','宋诗','song-poetry','','[]','一相今年老，三孤只舊班。',48,'全唐诗/poet.song.168000.json','["一相今年老，三孤只舊班。", "鼎彜都刻了，杖屨不勝閑。", "青遍人間眼，朱生鏡裏顔。", "君王記弧節，應賜壽香山。"]'),
('135c78ca-d510-4976-9f25-c9a87325595d','壽周益公  其二','楊炎正','宋','宋诗','song-poetry','','[]','小住人間世，猶須五百年。',48,'全唐诗/poet.song.168000.json','["小住人間世，猶須五百年。", "平園日成趣，相國地行仙。", "玉律吹秋至，冰輪向夜圓。", "不妨斟壽酒，和月入金船。"]'),
('07907cbf-3f75-4734-95ef-2dfccd4d44a1','壽宮使余丞相','楊炎正','宋','宋诗','song-poetry','','[]','間世生英傑，于時瑞幅員。',240,'全唐诗/poet.song.168000.json','["間世生英傑，于時瑞幅員。", "昔爲天下宰，今作地行仙。", "帝渴梅調鼎，民思楫濟川。", "元戎辭屏翰，珍館逸林泉。", "勳業麒麟上，聲名奏華顛。", "落成新紫府，拂拭舊青氈。", "暇日來簪履，春風可管弦。", "蓮開花十丈，桃熟歲三千。", "雲駐東山境，星輝北斗躔。", "笑談皆雨露，指顧即陶甄。", "烏景行添線，蟾華且上弦。", "垂弧當紀節，稱兕正迎年。", "四海俱瞻仰，三宮助祝延。", "匹休和有宋，受福總無邊。", "試吏如孤遠，蒙恩夙記憐。", "姓名勤剡奏，庖廩費周旋。", "頂踵思持報，絲毫力未宣。", "一憑難老頌，再炷博山烟。", "願把如椽筆，重歸秉化權。", "倍書中令考，穩穩戴貂蟬。"]'),
('1b27c5af-a190-4699-a92e-aba132a0a5fb','壽周樞使  其一','楊炎正','宋','宋诗','song-poetry','','[]','璧月秋光滿，銀河夜色開。',48,'全唐诗/poet.song.168000.json','["璧月秋光滿，銀河夜色開。", "嘗從北辰所，飛墮一星來。", "許國身爲棟，居庭面對槐。", "黄封天上酒，歲歲酌金罍。"]'),
('61986060-f4da-4eb8-b98b-e0b3ab918312','壽周樞使  其二','楊炎正','宋','宋诗','song-poetry','','[]','文武今三相，東西冠兩班。',48,'全唐诗/poet.song.168000.json','["文武今三相，東西冠兩班。", "公身爲九鼎，國勢屹南山。", "經濟談間了，昇平掌上還。", "腐儒徒醉頌，窮老愧心顔。"]'),
('5d77c995-d60e-45a0-8f24-f96d09d32251','壽趙帥  其一','楊炎正','宋','宋诗','song-poetry','','[]','今夕知何夕，祥光發帝庭。',48,'全唐诗/poet.song.168000.json','["今夕知何夕，祥光發帝庭。", "五雲扶聖日，一點見台星。", "廊廟須材久，絲綸洗耳聽。", "願從來歲始，天上酌脩齡。"]'),
('6c4895b3-429b-4764-810d-0ff9709eca83','壽趙帥  其二','楊炎正','宋','宋诗','song-poetry','','[]','昨歲將冰漕，今年握帥符。',48,'全唐诗/poet.song.168000.json','["昨歲將冰漕，今年握帥符。", "九街平甃玉，萬壽起浮圖。", "楚舞熙風月，湘歌暖袴襦。", "祝公香一瓣，處處博山爐。"]'),
('25bd9c71-5e62-490f-9e2b-1fb489ab522e','蘧老寄龍涎香','楊炎正','宋','宋诗','song-poetry','','[]','瘴海驪龍供素沫，蠻村茉莉挹清滋。',32,'全唐诗/poet.song.168000.json','["瘴海驪龍供素沫，蠻村茉莉挹清滋。", "微參鼻觀猶疑似，全在爐煙未發時。"]'),
('ddce3580-28bd-4da6-8d9c-0ef95e9618c8','送竹根香鑪與人','楊炎正','宋','宋诗','song-poetry','','[]','枯槁形骸惟見耳，彫殘鬢髮只留鬚。',32,'全唐诗/poet.song.168000.json','["枯槁形骸惟見耳，彫殘鬢髮只留鬚。", "平生大節堪爲底，今日灰心始見渠。"]'),
('494068da-ff5d-4b8b-9455-9cf050315c38','送柬牋與人','楊炎正','宋','宋诗','song-poetry','','[]','檢點交房有宿儲，楮先生輩亦中書。',64,'全唐诗/poet.song.168000.json','["檢點交房有宿儲，楮先生輩亦中書。", "小王辭客元無用，大阮才高正要渠。", "揮洒雅宜供五鳳，緘題更可寄雙魚。", "春來觸物皆詩料，從此賡酬莫見疎。"]'),
('7a04bcfc-e786-4c12-9ff5-0b64739ffc89','送紙筆與何慶遠','楊炎正','宋','宋诗','song-poetry','','[]','阿連詩語已通神，玉板霜毫不厭珍。',32,'全唐诗/poet.song.168000.json','["阿連詩語已通神，玉板霜毫不厭珍。", "老我簿書安用此，自應回施與青春。"]'),
('5465fd4d-8e1c-4fcf-9bde-52d7f4b12f67','謝人送墨','楊炎正','宋','宋诗','song-poetry','','[]','黑月黳雲脫太清，海風吹上筆頭輕。',32,'全唐诗/poet.song.168000.json','["黑月黳雲脫太清，海風吹上筆頭輕。", "瑣窗冷透芙蕖碧，定有新銘到九成。"]'),
('ff52db17-ab22-43fb-8534-2c067c35d77b','送錢文季赴闕','楊炎正','宋','宋诗','song-poetry','','[]','赤城往歲南來雁，送客去時歲云晚。',64,'全唐诗/poet.song.168000.json','["赤城往歲南來雁，送客去時歲云晚。", "客來雁去兩三回，悵望赤城天共遠。", "狀元此去朝京師，不待玉立春班齊。", "疾飛一步上芸閣，有夢只報梅花知。"]'),
('405e6101-4a24-4283-9962-2c7d6cb5afc3','送崔憲使赴召','楊炎正','宋','宋诗','song-poetry','','[]','詔使乘軺赴日邊，此行何以異登仙。',64,'全唐诗/poet.song.168000.json','["詔使乘軺赴日邊，此行何以異登仙。", "蓬萊路近春風暖，閶闔門開曉色鮮。", "不用歷階三粉署，便應平步五花磚。", "有人借問湘州倅，但道皤然雪滿顛。"]'),
('4f4c7414-1d91-4b85-8329-747bca41a773','句  其一','楊炎正','宋','宋诗','song-poetry','','[]','斷橋斜取路。',6,'全唐诗/poet.song.168000.json','["斷橋斜取路。"]'),
('d4fe01ec-1d38-43e9-b598-5d271dbc9603','句  其二','楊炎正','宋','宋诗','song-poetry','','[]','扶筇向水村。',6,'全唐诗/poet.song.168000.json','["扶筇向水村。"]'),
('be380257-5bf7-42d3-9448-f3b4f7d82b6b','句  其三','楊炎正','宋','宋诗','song-poetry','','[]','此道欣逢泰。',6,'全唐诗/poet.song.168000.json','["此道欣逢泰。"]'),
('746ee288-69d3-4983-99bd-7850a2764734','句  其四','楊炎正','宋','宋诗','song-poetry','','[]','老子興悠哉。',6,'全唐诗/poet.song.168000.json','["老子興悠哉。"]'),
('3550adfe-738e-47a6-af67-ebdb650bd265','句  其五','楊炎正','宋','宋诗','song-poetry','','[]','漁人四五家。',6,'全唐诗/poet.song.168000.json','["漁人四五家。"]'),
('f90c2d6a-b9bd-4b96-9b5d-9b99b846c7f7','句  其六','楊炎正','宋','宋诗','song-poetry','','[]','熏爐炷麝煤。',6,'全唐诗/poet.song.168000.json','["熏爐炷麝煤。"]'),
('4aa0ad14-6d49-423d-b9f8-5e14fdae2058','句  其七','楊炎正','宋','宋诗','song-poetry','','[]','無人語心事。',6,'全唐诗/poet.song.168000.json','["無人語心事。"]'),
('1ab187cf-e880-4647-8763-844b5fbd016e','句  其八','楊炎正','宋','宋诗','song-poetry','','[]','吟詩報答閑。',6,'全唐诗/poet.song.168000.json','["吟詩報答閑。"]'),
('d4d2387a-d4c4-4a0c-aba3-b86d92480b4d','句  其九','楊炎正','宋','宋诗','song-poetry','','[]','柴門引徑斜。',6,'全唐诗/poet.song.168000.json','["柴門引徑斜。"]'),
('e08bb732-c7b0-4bef-a912-53b1c8909073','句  其一○','楊炎正','宋','宋诗','song-poetry','','[]','寒空散晚霞。',6,'全唐诗/poet.song.168000.json','["寒空散晚霞。"]'),
('1c5f26f9-b841-47c6-9ae2-e4963ff5e1ef','句  其一一','楊炎正','宋','宋诗','song-poetry','','[]','風月充三益。',6,'全唐诗/poet.song.168000.json','["風月充三益。"]'),
('607ef6c4-0a40-48f6-b04d-e49d0d96618f','句  其一二','楊炎正','宋','宋诗','song-poetry','','[]','只今且爲梅花醉。',8,'全唐诗/poet.song.168000.json','["只今且爲梅花醉。"]'),
('f990cd5f-2e98-4b31-9ca5-fb4388712eed','句  其一三','楊炎正','宋','宋诗','song-poetry','','[]','尚須客裏訪蹉跎。',8,'全唐诗/poet.song.168000.json','["尚須客裏訪蹉跎。"]'),
('f231d229-e146-404e-aaab-46187efd4c2c','句','章森','宋','宋诗','song-poetry','','[]','渝舞氣豪傳漢俗，丙魚味美敵吳鄉。',16,'全唐诗/poet.song.168000.json','["渝舞氣豪傳漢俗，丙魚味美敵吳鄉。"]'),
('33c35363-19d5-497c-9d8b-9f2e51a5c283','勞拙堂歌','王謙','宋','宋诗','song-poetry','','[]','民吾同胞兮，撫之不得不勞兮。',49,'全唐诗/poet.song.168000.json','["民吾同胞兮，撫之不得不勞兮。", "拙雖獲罪，庸可逃兮。", "僞不能以終朝兮，作之亦徒勞兮。", "拙雖未敗，久乃昭兮。"]'),
('c535045d-9a1f-4d80-b437-e579b46d4713','鐵橋峰','宋煜','宋','宋诗','song-poetry','','[]','拄杖何年擲向空，雲端隠約化晴虹。',32,'全唐诗/poet.song.168000.json','["拄杖何年擲向空，雲端隠約化晴虹。", "此橋端的通霄漢，誰與同遊訪月宮。"]'),
('d851bc08-ee28-4757-92aa-a33af5833c5d','題朱明洞','宋煜','宋','宋诗','song-poetry','','[]','澗流一一抱峰回，面面林巒錦帳開。',32,'全唐诗/poet.song.168000.json','["澗流一一抱峰回，面面林巒錦帳開。", "我品洞天居第七，只應題作小蓬萊。"]'),
('2572ddc7-5bee-42ec-a386-63e9a6da8114','蝴蝶洞','宋煜','宋','宋诗','song-poetry','','[]','陰深古木護漣漪，洞裏藏春人不知。',32,'全唐诗/poet.song.168000.json','["陰深古木護漣漪，洞裏藏春人不知。", "不是桃源深有路，如向蝴蝶滿璚枝。"]'),
('ea175689-764e-42a9-8bda-b8a52d19599e','石臼洞','宋煜','宋','宋诗','song-poetry','','[]','清泉一派水潺潺，石穴端然一臼安。',32,'全唐诗/poet.song.168000.json','["清泉一派水潺潺，石穴端然一臼安。", "洗藥煉丹仙已去，只留踪跡與人看。"]'),
('9353f9e3-f84f-406c-9c54-1a166622aa86','遺衣壇','宋煜','宋','宋诗','song-poetry','','[]','駕鶴乘鸞歸紫府，仙凡從此不相干。',32,'全唐诗/poet.song.168000.json','["駕鶴乘鸞歸紫府，仙凡從此不相干。", "要傳當日飛昇事，收拾遺衣爲結壇。"]'),
('6d07ce38-7377-4f40-b32e-dfda7f5b9237','朱子庵','宋煜','宋','宋诗','song-poetry','','[]','仙人自昔好樓居，怪石稜層倚碧虛。',32,'全唐诗/poet.song.168000.json','["仙人自昔好樓居，怪石稜層倚碧虛。", "見說通天中有路，世間何處覓飆車。"]'),
('b51c5a56-d0e2-402f-a658-afef529d9e62','黄野人庵','宋煜','宋','宋诗','song-poetry','','[]','淮南鷄犬上雲端，底事先生獨世間。',32,'全唐诗/poet.song.168000.json','["淮南鷄犬上雲端，底事先生獨世間。", "上界應嫌官府足，不如平地且驂鸞。"]'),
('7b2fce7e-2262-46f7-b2c9-d613a8014346','竹符','宋煜','宋','宋诗','song-poetry','','[]','仙篆元非世俗書，筆端會把鬼神驅。',32,'全唐诗/poet.song.168000.json','["仙篆元非世俗書，筆端會把鬼神驅。", "當年筆迹今何在，洞客爭傳竹葉符。"]'),
('16fa4609-d293-46c5-9a8b-51ce2678e40e','句  其一','應子和','宋','宋诗','song-poetry','','[]','兩岸夕陽紅。',6,'全唐诗/poet.song.168000.json','["兩岸夕陽紅。"]'),
('9460557a-62a9-4918-be3b-fd5338e77040','句  其二','應子和','宋','宋诗','song-poetry','','[]','蠟炬短燒紅。',6,'全唐诗/poet.song.168000.json','["蠟炬短燒紅。"]'),
('2e6485ad-7ace-4095-bdf6-bc8ffbab1f8d','句  其三','應子和','宋','宋诗','song-poetry','','[]','風過落花紅。',6,'全唐诗/poet.song.168000.json','["風過落花紅。"]'),
('3179bdcf-1d76-4de6-9ea9-8ca7bbe38177','挽呂東萊先生  其一','陳孔碩','宋','宋诗','song-poetry','','[]','北望非吾土，南來獨此翁。',48,'全唐诗/poet.song.168000.json','["北望非吾土，南來獨此翁。", "孔顔當日意，杞宋百年風。", "與物陽春闊，隨形鏡影空。", "吾儕竟何罪，斯道合成窮。"]'),
('0aee114e-129f-4d3d-abce-247a78520ab5','挽呂東萊先生  其二','陳孔碩','宋','宋诗','song-poetry','','[]','語絕香奩壞，人非鐵磬存。',48,'全唐诗/poet.song.168000.json','["語絕香奩壞，人非鐵磬存。", "罷官空數日，挾策與誰論。", "丈室塵埃亂，層城草木昏。", "寸心無訴處，號絕向令原。"]'),
('b352f03b-7919-4364-8323-ab1ff6886492','牡丹','陳孔碩','宋','宋诗','song-poetry','','[]','既全國色與天香，底用人間紫與黄。',32,'全唐诗/poet.song.168000.json','["既全國色與天香，底用人間紫與黄。", "却喜騷人稱第一，至今喚作百花王。"]'),
('ce8e0922-9cdc-4c94-818e-340963a594c7','海棠','陳孔碩','宋','宋诗','song-poetry','','[]','幾樹繁紅一徑深，春風裁剪錦成屏。',32,'全唐诗/poet.song.168000.json','["幾樹繁紅一徑深，春風裁剪錦成屏。", "花前莫作淵才恨，且看楊妃睡未醒。"]'),
('ff8340af-7a8e-4d58-82d0-3d0451f039a3','楊柳','陳孔碩','宋','宋诗','song-poetry','','[]','臘雪逢春次第消，等閒著脚上溪橋。',32,'全唐诗/poet.song.168000.json','["臘雪逢春次第消，等閒著脚上溪橋。", "柳條畢竟带兒女，一夜東風眼便嬌。"]'),
('409d307d-28c9-4a76-81a2-21f7f96a5154','寄題劉潛夫于蔿于齋','陳孔碩','宋','宋诗','song-poetry','','[]','昔聞子元子，愛歌于蒍于。',72,'全唐诗/poet.song.168000.json','["昔聞子元子，愛歌于蒍于。", "遣風今有繼，此意古爲徒。", "犢價踰刀劍，原飴變堇荼。", "聞絃知豈弟，連袂此歡呼。", "近事先苞篚，何人問牧芻。", "聚星亭澗好，容我受廛無。"]'),
('8e4161b9-4a63-48ba-88e9-66aa045199d5','無題','陳孔碩','宋','宋诗','song-poetry','','[]','鳴鼓人皆可，彈琴今復誰。',24,'全唐诗/poet.song.168000.json','["鳴鼓人皆可，彈琴今復誰。", "儘賒王媼酒，休賦大蘇詩。"]'),
('c46ad56f-45f3-47a7-9e3a-0744b72ba186','句','陳孔碩','宋','宋诗','song-poetry','','[]','南民何德辱公憂，六轡周遭死始休。',16,'全唐诗/poet.song.168000.json','["南民何德辱公憂，六轡周遭死始休。"]'),
('c4fe72b1-23de-49ad-bd96-33193617a107','萬山','許錫','宋','宋诗','song-poetry','','[]','平時西北望山峰，我忽西行山忽東。',32,'全唐诗/poet.song.168000.json','["平時西北望山峰，我忽西行山忽東。", "東望不如西望好，只緣身已出山中。"]'),
('120d208f-41db-431e-940b-a04f3336139f','詩一首','張斗南','宋','宋诗','song-poetry','','[]','辭得官來性又便，恰如病馬解韁牽。',32,'全唐诗/poet.song.168000.json','["辭得官來性又便，恰如病馬解韁牽。", "雖無白日三聲喏，贏得清宵一枕眠。"]'),
('ce16ec44-8c11-41e7-8618-e609a2b25124','高宗皇帝挽詞  其一','李巘','宋','宋诗','song-poetry','','[]','建炎恢聖統，太上極尊名。',48,'全唐诗/poet.song.168000.json','["建炎恢聖統，太上極尊名。", "夏祀參天永，堯勳冠古榮。", "艱難成帝業，付託本皇明。", "俯閲人間世，飈遊跨九清。"]'),
('1b710f4e-db4d-4c38-a11b-b8ef4d5ee685','高宗皇帝挽詞  其二','李巘','宋','宋诗','song-poetry','','[]','壽歷開金筴，皇歡奉玉顔。',48,'全唐诗/poet.song.168000.json','["壽歷開金筴，皇歡奉玉顔。", "難諶天道遠，忽愴帝鄉還。", "敷德戎夷外，安民禮樂間。", "功崇超大禹，神穴枕稽山。"]'),
('01b5cac2-931e-4b35-b3da-454687591862','高宗皇帝挽詞  其三','李巘','宋','宋诗','song-poetry','','[]','赫奕中興事，洪圖久系隆。',48,'全唐诗/poet.song.168000.json','["赫奕中興事，洪圖久系隆。", "垂裳三紀後，脫屣再星終。", "靈馭龍騰座，仙晨鶴翥空。", "薰琴無盡意，遏密卷悲風。"]'),
('d2968699-102a-49e5-be37-c1b008ac1411','高宗皇帝挽詞  其四','李巘','宋','宋诗','song-poetry','','[]','漢帝傷心地，羹牆夢正勞。',48,'全唐诗/poet.song.168000.json','["漢帝傷心地，羹牆夢正勞。", "珠藏超赤水，鼎在泣烏號。", "神藻光仍煥，仁風遠更翺。", "百皇誰比德，商廟獨推高。"]'),
('aa89f915-9a4a-4cb7-b0ee-e503d260fd12','高宗皇帝挽詞  其五','李巘','宋','宋诗','song-poetry','','[]','映日龍輴動，喧天鳳吹休。',48,'全唐诗/poet.song.168000.json','["映日龍輴動，喧天鳳吹休。", "橋仙融路碧，梧野結雲愁。", "萬葉休符衍，三年孝制脩。", "臣民瞻祖載，慟哭拜江流。"]'),
('edbccfc3-b84f-4921-b7ec-658265541247','句','傅夢泉','宋','宋诗','song-poetry','','[]','吾非愛海棠，吾愛與吾惡，海棠自海棠。',18,'全唐诗/poet.song.168000.json','["吾非愛海棠，吾愛與吾惡，海棠自海棠。"]'),
('d1a1c584-948c-4d94-b3e1-6f55de631523','題真仙巖','賈遵祖','宋','宋诗','song-poetry','','[]','翰林以謫流夜郎，我亦何爲涉此境。',224,'全唐诗/poet.song.168000.json','["翰林以謫流夜郎，我亦何爲涉此境。", "生平山水債未了，宦遊直度桂州嶺。", "牂牁江繞古融城，拂拭冠纓照清影。", "舉頭忽見真仙巖，盤空攫拏勢馳騁。", "天教刻削無遺巧，不知斤斧誰手秉。", "吻如蝕月醜蝦蟆，枵腹穹窿寬一頃。", "尸居龍見柱下史，宴坐似說常清靜。", "貫穿石澗飛驚湍，兩岸峽束垂機穽。", "茲晨邂逅得勝踐，身到中間發深省。", "青牛昔過函谷關，我陪五老曾造請。", "依然一念浩劫初，墮在塵埃官獨冷。", "童兒徐甲今何所，朝從南箕暮東井。", "當時與我極綢繆，默而禱之意相領。", "扶携騰上虛皇前，賜我金丹凌倒景。"]'),
('93762d0d-af1c-42d8-ae3e-9a7530d2b56b','鼠莽草','喬夢符','宋','宋诗','song-poetry','','[]','聞有一草名鼠莽，食之隨死不可醫。',96,'全唐诗/poet.song.168000.json','["聞有一草名鼠莽，食之隨死不可醫。", "非惟自己受毒烈，輒使妻兒常號悲。", "本圖將此報私忿，不知官府誠難欺。", "人生樂國豈易得，輕命如此何愚癡。", "縣令慚無功及民，徒有勤懇形諸辭。", "後來有問誰爲此，但道東陽田家兒。"]'),
('0f8bb039-efe9-4724-b319-eb6fa136e8f8','中興寺環翠閣','喬夢符','宋','宋诗','song-poetry','','[]','□盡烟波闊，風多客袂涼。',48,'全唐诗/poet.song.168000.json','["□盡烟波闊，風多客袂涼。", "清談饒有致，白日不知長。", "麥隴高低熟，繅車啞軋忙。", "歸來猶怪早，人影在斜陽。"]'),
('4c0b062c-4cea-47ff-869c-1870db2b4909','題古城巖','鄒補之','宋','宋诗','song-poetry','','[]','依然雉堞古城基，開創由來自漢隋。',64,'全唐诗/poet.song.168000.json','["依然雉堞古城基，開創由來自漢隋。", "南北兩門餘舊日，黔黎百歲話當時。", "循山㶁㶁陳公堨，鑿石巖巖葛令碑。", "萬丈懸崖如削玉，也應容我恣題詩。"]'),
('dffbdabe-140e-43be-b518-85b546820838','句','鄒補之','宋','宋诗','song-poetry','','[]','曲江丞相言不售，范陽烽火連京畿。',16,'全唐诗/poet.song.168000.json','["曲江丞相言不售，范陽烽火連京畿。"]'),
('44081bd5-bcd9-43cd-ba79-a0dab7e17f47','夏日觀農','尤槩','宋','宋诗','song-poetry','','[]','行行曠野間，田家功正甫。',72,'全唐诗/poet.song.168000.json','["行行曠野間，田家功正甫。", "老農謂予言，此中情難數。", "焦枯慮連旱，陰損慮積雨。", "插蒔復耕耘，酷日無從拒。", "豈不愛四肢，望歲忘其苦。", "但願慶豐年，得給人三鬴。"]'),
('44d9c2ce-88b1-41be-8d4c-38aaeca899da','第一山','蔣介','宋','宋诗','song-poetry','','[]','第一山前萬里秋，野花衰草替人愁。',32,'全唐诗/poet.song.168000.json','["第一山前萬里秋，野花衰草替人愁。", "中原好在平如掌，莫把長淮當白溝。"]'),
('e1d6a750-3f88-4614-976c-7047940998ef','碧澗書堂','林夢英','宋','宋诗','song-poetry','','[]','臨川遇鄒君，示我銅陵辨。',204,'全唐诗/poet.song.168000.json','["臨川遇鄒君，示我銅陵辨。", "相邀游其間，百聞須一踐。", "自從雙耳聾，已辦兩足繭。", "武夷乃招隠，仙都輒策蹇。", "遥睇麻源村，夢思勞輾轉。", "今披碧澗記，華岡訂訛舛。", "疑信吁莫論，是非爭之褊。", "但欣泉石奇，堂成書可輦。", "晁侯雲夢胸，妙處參墳典。", "家有萬竹坡，琳琅閟營翦。", "徘徊康樂舊，此興尤不淺。", "人生貴自得，假物非至善。", "山川侈遭逢，所託各偕顯。", "嚴光釣越灘，叔子登楚峴。", "氣象不低摧，吾徒志當勉。", "相思邀未到，烟霞自舒卷。", "唯應原上月，共照人孤狷。"]'),
('95e5cb17-a70b-472a-a803-42982d4e0194','金石臺  其一','林夢英','宋','宋诗','song-poetry','','[]','雲作巖扉風自關，清陰半壑樹中間。',32,'全唐诗/poet.song.168000.json','["雲作巖扉風自關，清陰半壑樹中間。", "傍廂更著茅亭好，放入西南一面山。"]'),
('68bf7c6f-dd35-426a-ba9a-696ac592335b','金石臺  其二','林夢英','宋','宋诗','song-poetry','','[]','臺後漫山十里梅，村南村北總詩材。',32,'全唐诗/poet.song.168000.json','["臺後漫山十里梅，村南村北總詩材。", "荒寒莫恨無人領，會與奚奴杖屨來。"]'),
('4f3da5a7-c454-446b-9db0-dad779b0bdf1','屠甸','莫若沖','宋','宋诗','song-poetry','','[]','偶然屠甸見浮屠，爲問屠中有物無。',32,'全唐诗/poet.song.168000.json','["偶然屠甸見浮屠，爲問屠中有物無。", "見說庖丁游刃在，恢恢全不費工夫。"]'),
('fff8aecc-7a80-488f-89f1-8a2a931213d7','趙仁父宴邑官平綠見招','莫若沖','宋','宋诗','song-poetry','','[]','平綠題詩四十年，尋幽不厭水雲邊。',64,'全唐诗/poet.song.168000.json','["平綠題詩四十年，尋幽不厭水雲邊。", "一犂還又耕春後，三白曾來醉臘前。", "自笑挂冠林下客，獲陪揮麈坐中賢。", "絕嫌幻色撩人思，快覩晴川遠接天。"]'),
('98acf5c2-dc4c-4a05-bfed-6d32b9c94ef1','過崇勝院','莫若沖','宋','宋诗','song-poetry','','[]','首歲融春卜有秋，曉行猶自索貂裘。',64,'全唐诗/poet.song.168000.json','["首歲融春卜有秋，曉行猶自索貂裘。", "身閒暫脫微官縛，市隠何如此地幽。", "一水相望三里近，十年重到片時留。", "買田擬作終焉計，真是飄然不繫舟。"]'),
('c9af7f60-fef6-4ceb-b475-1c4a5ac1e98b','題石門張氏園','莫若沖','宋','宋诗','song-poetry','','[]','爲米徒勞束带難，當時彭澤便休官。',32,'全唐诗/poet.song.168000.json','["爲米徒勞束带難，當時彭澤便休官。", "高情曾賦歸來句，盡入名園扁署看。"]'),
('d9c4f7a5-f35e-4a7c-94c7-e5d93af6df9a','句','楊炳','宋','宋诗','song-poetry','','[]','釀溪煮海恩無極，千家沽酒萬家鹽。',16,'全唐诗/poet.song.168000.json','["釀溪煮海恩無極，千家沽酒萬家鹽。"]'),
('e9618b8f-5ba3-405a-b935-e325501ffa64','雪','趙善沛','宋','宋诗','song-poetry','','[]','兒笑真珠滿盤碎，女疑荷葉雨中來。',32,'全唐诗/poet.song.168000.json','["兒笑真珠滿盤碎，女疑荷葉雨中來。", "道人心下無些事，三箇柴頭品字煨。"]'),
('db1c08d7-7ccd-41ea-bc89-49e39f59623c','梅花','趙師俠','宋','宋诗','song-poetry','','[]','南山有佳人，迥立未可親。',24,'全唐诗/poet.song.168000.json','["南山有佳人，迥立未可親。", "而況得道者，其間梅子真。"]'),
('3bc49d8e-f7f2-4166-bace-2d62a110395f','游陽華巖  其一','趙師俠','宋','宋诗','song-poetry','','[]','出郭曾無十里賒，僊巖迎日號陽華。',32,'全唐诗/poet.song.168000.json','["出郭曾無十里賒，僊巖迎日號陽華。", "雲藏奧穾嵐光潤，信美元郎詠可家。"]'),
('26dc7239-20fb-4a76-b04b-20515ad17df4','游陽華巖  其二','趙師俠','宋','宋诗','song-poetry','','[]','石罅空明石色鮮，霞舒乳滴巧雕鎸。',32,'全唐诗/poet.song.168000.json','["石罅空明石色鮮，霞舒乳滴巧雕鎸。", "縈迴棧道泉湍響，疑是僊家小有天。"]'),
('866e4d52-0b5e-41eb-9501-bceea3a5e680','次踏磧韻','費士戣','宋','宋诗','song-poetry','','[]','寶釧金釵盛峽風，遨頭爭逐去匆匆。',64,'全唐诗/poet.song.168000.json','["寶釧金釵盛峽風，遨頭爭逐去匆匆。", "旗標陣磧規模古，筵挹晴嵐氣色葱。", "宜有明珠酬白璧，空慚瓦缶間黄鐘。", "紛紛雪片呈佳瑞，一飽端知萬姓同。"]'),
('41df5863-ac44-4626-96e2-8c971eab9d16','挈家來游飫山林之美款泉石之勝引睇莆陽扁畫因慨思關河鼎沸版圖之歸無期當有任其咎者','趙彥吶','宋','宋诗','song-poetry','','[]','吏餘得得叩仙扃，蕭散還吾自在身。',64,'全唐诗/poet.song.168000.json','["吏餘得得叩仙扃，蕭散還吾自在身。", "到耳鳴蟬□更靜，傍簷飛鳥亦相親。", "層巖障日崖根險，危柱擎空□色新。", "應念中州方熱惱，願分清泚藥斯民。"]'),
('45948b2c-d0cb-4d1e-ac9a-1815bc6846b8','烏林行','馬子嚴','宋','宋诗','song-poetry','','[]','荆州兒曹不足恃，何物老瞞欺一世。',131,'全唐诗/poet.song.168000.json','["荆州兒曹不足恃，何物老瞞欺一世。", "兵書浪語十三篇，不料烏林出奇計。", "隆準雲孫驅伏龍，紫髯强援要江東。", "戈船植羽蔽寒日，雪浪崩崖驚晚風。", "行閒一卒如兒戲，持火絕江人不意。", "灰銷漢賊終老心，功入喬家少年壻。", "君不見華容道旁春草生，魂銷不聽車馬聲。", "哀猿夜啼霜月冷，空餘野燐沙邊明。"]'),
('f14837eb-16e8-4619-adf7-ebd359322136','仙霞嶺','馬子嚴','宋','宋诗','song-poetry','','[]','鎮日崎嶇度遠山，遠山深處解征鞍。',64,'全唐诗/poet.song.168000.json','["鎮日崎嶇度遠山，遠山深處解征鞍。", "翠環水石四圍匝，凍積冰霜一夜寒。", "月影自催人起早，泉聲不許客眠安。", "明朝直向烟霞去，身在亨衢天地寬。"]'),
('d9ed5244-a0f0-4997-aada-b00fd14f9167','雲巖','馬子嚴','宋','宋诗','song-poetry','','[]','林深路轉山，巖虛雲觸石。',180,'全唐诗/poet.song.168000.json','["林深路轉山，巖虛雲觸石。", "是中立數椽，僅足安一室。", "斷罅開碧落，當晝懸白日。", "虬蘗掛乳竇，飛鼠傅石脊。", "山中古老人，對我誦記憶。", "昔爲鬼仙家，乃藉巨人力。", "劃地剖疆界，印泥遺指跡。", "至今百年餘，住世三度易。", "吾非梅子真，身是江南客。", "詹子武夷俊，邂逅願已適。", "扶携一登覽，相與有儔匹。", "林逋葉靜能，俱來一同席。", "二子善鼓琴，無弦徒挂壁。", "日暮雲已歸，今夕竟何夕。", "徘徊卧白雲，華胥何處覓。"]'),
('6d65a4ee-60a9-4528-8b59-eff88708314a','章巖','馬子嚴','宋','宋诗','song-poetry','','[]','拳石中虛屋數椽，洞門東闢半規圓。',64,'全唐诗/poet.song.168000.json','["拳石中虛屋數椽，洞門東闢半規圓。", "木高長蔽三竿日，人到同觀一片天。", "行路不堪秋後暑，禪牀聊借午時眠。", "山僧爲我敲茶臼，相對爐香起暮烟。"]'),
('be67cbeb-ccca-4151-909b-273ec700b4a1','黄花渡','馬子嚴','宋','宋诗','song-poetry','','[]','黄竹歌成雪未休，黄花渡口上橫舟。',64,'全唐诗/poet.song.168000.json','["黄竹歌成雪未休，黄花渡口上橫舟。", "百錢買酒可能醉，千里懷人不奈愁。", "歲事只餘旬五日，家山猶隔兩三州。", "飛雲在目還知否，肯爲彫胡一餉留。"]'),
('f55927ab-7765-4c7c-b661-8f0d7f54569a','句  其一','馬子嚴','宋','宋诗','song-poetry','','[]','章村蓬蓽兩三家，籬落縱橫被野花。',16,'全唐诗/poet.song.168000.json','["章村蓬蓽兩三家，籬落縱橫被野花。"]'),
('f9b42c34-a5ee-43e9-a610-05b25bc4022f','句  其二','馬子嚴','宋','宋诗','song-poetry','','[]','亂點瓊葩豔豔明。',8,'全唐诗/poet.song.168000.json','["亂點瓊葩豔豔明。"]'),
('c5800a6b-ed5c-4c4d-8826-f25d21c6f5b8','墨池發祥詩呈蔣教','劉名世','宋','宋诗','song-poetry','','[]','城頭學宮高巍巍，中有方井號墨池。',304,'全唐诗/poet.song.168000.json','["城頭學宮高巍巍，中有方井號墨池。", "窮冬不竭春不溢，往往石眼通江湄。", "故老相傳右軍宅，滌硯濡毫向池側。", "蘭亭絕筆跡成塵，此間池水猶能黑。", "紹興之年值丙寅，一夕鬰鬰浮烏雲。", "鄉閭拭目看盛事，集英三唱人姓陳。", "又聞淳熙改元歲，隔春預作文章瑞。", "甲科奪得漢庭魁，賢關解褐冠多士。", "九歲奇童面聖顔，闔郡十人俱賜第。", "近來復作烟霧飛，盈盈玉斗磨歙絲。", "忽焉陰霾黯蒼漢，模糊頃刻風披披。", "巧如奇花開異草，天女織出絞綃衣。", "須臾變態千萬狀，妙手點染水墨奇。", "此事頗亦涉神怪，疑有鬼物來遊嬉。", "不然下墊千年龜，圖書之祥將發揮。", "吾鄉文物盛洙泗，執經問道肩相隨。", "殘膏賸馥大沾溉，諸生借潤今其時。", "文昌終有應圖契，韓門高第皆可爲。", "先令地脈進佳貺，主張在公非義之。"]'),
('e5f6778e-af28-400c-8372-7563cabb43b4','句','劉名世','宋','宋诗','song-poetry','','[]','槐影已高公事少，蒲鞭不試訟庭閒。',16,'全唐诗/poet.song.168000.json','["槐影已高公事少，蒲鞭不試訟庭閒。"]'),
('0388786c-dd8f-4fcc-bec8-a306709caa77','龍爪石','翁華','宋','宋诗','song-poetry','','[]','香開巖桂露凄清，翠鎖晴嵐潑眼明。',64,'全唐诗/poet.song.168000.json','["香開巖桂露凄清，翠鎖晴嵐潑眼明。", "風度南枝烏鵲囀，月斜西塢玉繩橫。", "來游十里水雲窟，償我一生邱壑情。", "詩句乞君高挂壁，且容鼻息撼雷鳴。"]'),
('836977b8-426d-4ba6-80e0-5f9e66edab17','陽華巖','孟坦中','宋','宋诗','song-poetry','','[]','路入瀟南地一隅，天開洞府若爲模。',64,'全唐诗/poet.song.168000.json','["路入瀟南地一隅，天開洞府若爲模。", "石扃高透雲常出，澗水中通崖不枯。", "來訪恍然驚澤國，醉眠清甚在冰壺。", "淡巖誰道真稀有，須信陽華天下無。"]'),
('fe586d24-b3e4-4907-a886-61950e0bf179','寄丹丘林詠道','桑世昌','宋','宋诗','song-poetry','','[]','小別俄驚歲屢周，尺書每每寄江頭。',64,'全唐诗/poet.song.168000.json','["小別俄驚歲屢周，尺書每每寄江頭。", "逢時共歎君肥遯，投老誰憐我倦游。", "書足三冬應潤屋，詩成千首必經侯。", "一尊縱負東湖約，尚及黄花碧樹秋。"]'),
('597385bb-d77d-42e7-a619-2f61d5758cdd','夜對巾山塔燈呈史君李孟達寺簿','桑世昌','宋','宋诗','song-poetry','','[]','光明臺畔舊曾逢，何自飛來碧海東。',64,'全唐诗/poet.song.168000.json','["光明臺畔舊曾逢，何自飛來碧海東。", "未問眼根齊等級，要先心地證圓通。", "八還究竟千光合，四面回旋一視同。", "坐想玉霄風月夕，超然清對一詩翁。"]'),
('6e0f546c-3e0e-4e77-9e19-049ab16159d0','句','桑世昌','宋','宋诗','song-poetry','','[]','翠添鄰塹竹，紅照屋山花。',12,'全唐诗/poet.song.168000.json','["翠添鄰塹竹，紅照屋山花。"]'),
('157bde94-ea53-4bb7-90e9-649cd83f56c4','臨終偈','劉堯夫','宋','宋诗','song-poetry','','[]','不到清泉白石邊，却來城市走喧喧。',32,'全唐诗/poet.song.168000.json','["不到清泉白石邊，却來城市走喧喧。", "夜來一派銀潢水，瀉向瓊臺玉檻前。"]'),
('f951123d-b921-43d3-9c27-8b0dced63aea','句','劉堯夫','宋','宋诗','song-poetry','','[]','力推獰龍借水飲，手却猛虎奪石坐。',16,'全唐诗/poet.song.168000.json','["力推獰龍借水飲，手却猛虎奪石坐。"]'),
('db11500e-c71e-4bc4-b953-ae555b41bb25','潭州','黄裳','宋','宋诗','song-poetry','','[]','維衡屹南荒，作鎮自開闢。',24,'全唐诗/poet.song.168000.json','["維衡屹南荒，作鎮自開闢。", "定王十里城，處處見山色。"]'),
('b25b197e-e8d7-4d21-a8fb-dafa588679b6','漢中行','黄裳','宋','宋诗','song-poetry','','[]','漢中沃野如關中，四五百里烟濛濛。',377,'全唐诗/poet.song.168000.json','["漢中沃野如關中，四五百里烟濛濛。", "黄雲連天夏麥熟，水稻漠漠吹秋風。", "七月八月䆉䅉紅，一家往往收千鍾。", "行人歎息風土好，居人生計何草草。", "老翁扶杖泣我前，此事何堪與君道。", "君不見屯軍十萬如貔貅，椎牛釃酒不得飽，飛芻輓粟無時休。", "禾稼登場雖滿眼，十有八九歸徵求。", "軍前輸米更和糴，囊括顆粒無乾餱。", "棱棱殺氣森平原，雖食我肉不敢言。", "陣馬如雲動雷電，戈戟摐撞相騰喧。", "口邊奪食與馬齧，馬飽人饑無處說。", "大吏明知但吁歎，百姓俛首當擭竊。", "天高日薄炊煙冷，村落蕭條往來絕。", "君莫問我漢中連年事，肝膈難言眼流血。", "似聞今年春，關外四五州。", "歲饑人無食，餓者頗亦稠。", "蕃人欲寇邊，此事信有不。", "時塗苟如此，人生不如死。", "死即萬事休，生則何時已。", "語多情極辭轉哀，野風颯颯吹黄埃。", "荒村相對兩嗚咽，收淚問我何方來。", "作官騎馬不易得，具與天子憐嬰孩。", "老翁已老死不惜，家有兒孫方戢戢。", "願君富貴爲愛惜，莫教還似翁今日。"]'),
('b92c2925-068e-4f21-9c7e-eadcef3dfda8','罷糴行','黄裳','宋','宋诗','song-poetry','','[]','邊頭八月秋田熟，南村北村夜舂粟。',224,'全唐诗/poet.song.168000.json','["邊頭八月秋田熟，南村北村夜舂粟。", "大平車子走無輪，載米入場聲轆轆。", "官置斗斛人自量，市價日與時低昂。", "得錢却載車上去，出門掉臂歸山鄉。", "老翁扶杖笑且語，大兒踏歌小兒舞。", "酒酣歌罷喜復悲，却憶前年輸糴苦。", "田頭刈禾人未歸，吏已打門嗔我遲。", "名爲和糴實强取，使我父子長寒饑。", "今年官場有糴米，賣米得錢固其理。", "力排衆議改舊法，聞說郎中人姓李。", "小民無力酬天公，但願穀米年年豐。", "年年與官足兵食，三軍飽食眠秋風。", "郎中歸坐天子側，更與小民說休戚。", "莫使明年復開糴，老翁還作前年泣。"]'),
('4cec21d6-9bd2-47a7-bf84-f2585385f879','句','黄裳','宋','宋诗','song-poetry','','[]','障塞應懸隔，崇墉謾太高。',12,'全唐诗/poet.song.168000.json','["障塞應懸隔，崇墉謾太高。"]'),
('391ecdd0-2977-46a9-99b5-179551363b19','梅開一花','彭蠡','宋','宋诗','song-poetry','','[]','昨夜花神有底忙，先教踏白入南邦。',64,'全唐诗/poet.song.168000.json','["昨夜花神有底忙，先教踏白入南邦。", "冷將雙眼窺春破，肯把孤心受雪降。", "礬弟得兄呼最長，竹君取友嘆無雙。", "試於月夜窗前看，一在枝頭一在窗。"]'),
('02d945d8-47e1-4c5a-af88-1cf655ccb933','次石屏翁韻','戴龜朋','宋','宋诗','song-poetry','','[]','走遍江湖早得名，歸來哦句伺幃屏。',64,'全唐诗/poet.song.168000.json','["走遍江湖早得名，歸來哦句伺幃屏。", "故人今雨時相過，好酒新春肯獨醒。", "未用阮生三語掾，但遵迂叟四言銘。", "高明已悟閑居福，當見于門發舊馨。"]'),
('3c149c3d-17f0-497b-b8cc-26f9826fd419','金精山','曾興宗','宋','宋诗','song-poetry','','[]','投老篔簹幸卜鄰，蝸蠅更不累閑身。',32,'全唐诗/poet.song.168000.json','["投老篔簹幸卜鄰，蝸蠅更不累閑身。", "烟霞已作仙凡隔，洞戶蟠桃不計春。"]'),
('0d0f8474-28fc-45f8-9b9f-61e04e0f5449','篔簹谷','曾興宗','宋','宋诗','song-poetry','','[]','渭川千畝竹，可比萬戶侯。',108,'全唐诗/poet.song.168000.json','["渭川千畝竹，可比萬戶侯。", "我有篔簹谷，此豈爲食謀。", "南山與北山，清絕真勝遊。", "飛泉助蕭爽，怪石添清幽。", "娛親自足樂，捧檄良可羞。", "日從抱節君，崎嶇經林丘。", "有酒對爾酌，得句爲爾謳。", "共結歲寒心，肯學炎涼儔。", "笑指親密友，不獨王子猷。"]'),
('8d0f7314-8d8d-4b69-a6d3-993d60d1ee4e','水竹幽居堂','曾興宗','宋','宋诗','song-poetry','','[]','山深景最幽，正爲幽人設。',84,'全唐诗/poet.song.168000.json','["山深景最幽，正爲幽人設。", "獲此一段奇，天意亦特達。", "水清濯吾纓，竹勁抱高節。", "鑿池爲延客，築室相娛悅。", "故人來清風，莫逆友明月。", "雅與仙境連，迥隔紅塵絕。", "此樂只自知，切勿與人說。"]'),
('1ab0012a-da04-4c7a-b4c2-d6c6d5808721','湖隄晚行','俞灝','宋','宋诗','song-poetry','','[]','暝色才從草色生，管弦羅綺盡歸城。',32,'全唐诗/poet.song.168000.json','["暝色才從草色生，管弦羅綺盡歸城。", "不應閑却孤山路，我自扶藜月下行。"]'),
('3a565483-83fc-40d7-a884-2ad4ea58af15','武康道中','俞灝','宋','宋诗','song-poetry','','[]','竹窗聽雨自安眠，不道驚湍近屋前。',32,'全唐诗/poet.song.168000.json','["竹窗聽雨自安眠，不道驚湍近屋前。", "省得去年桃葉渡，水痕只到樹傍邊。"]'),
('aa515fde-ab3e-4197-aeb2-1d8dcdd6a6f4','病眼','俞灝','宋','宋诗','song-poetry','','[]','三分春色二分過，檢校花程已下坡。',64,'全唐诗/poet.song.168000.json','["三分春色二分過，檢校花程已下坡。", "近日頓然行樂少，今年分外負春多。", "閑身自在寧須祿，俗客相看只是魔。", "四百病中偏病眼，禁烟禁酒却如何。"]'),
('bfeb0f45-fefe-43a8-8947-1f4fac1b28e5','鸜鵒','俞灝','宋','宋诗','song-poetry','','[]','守黑元知分，能言亦任真。',48,'全唐诗/poet.song.168000.json','["守黑元知分，能言亦任真。", "人知不可食，我得自全身。", "牛背煙村畫，烏群野水春。", "從教鸚鵡貴，籠絡媚宮嬪。"]'),
('25c03e20-2224-4170-8c13-69888136634a','雲海亭','俞灝','宋','宋诗','song-poetry','','[]','戀戀欄干去復留，恍然天地與身浮。',64,'全唐诗/poet.song.168000.json','["戀戀欄干去復留，恍然天地與身浮。", "水涵空界光無際，山在地州翠欲流。", "點破琉璃雲表雁，足成圖畫柳邊舟。", "歲闌却自忘歸興，更欲同爲雪後遊。"]'),
('9449c6a1-fcf0-4a82-a3b6-4b1db9b5d908','三高堂','俞灝','宋','宋诗','song-poetry','','[]','東華車馬日滔滔，始覺三高分外高。',64,'全唐诗/poet.song.168000.json','["東華車馬日滔滔，始覺三高分外高。", "吳越衣冠幾春夢，古今身世一秋毫。", "臨流久立迷烟艇，駕月歸來認雪濤。", "琢句不成風又起，寒蒲霜鬢兩蕭騷。"]'),
('7f61c554-d7f1-4561-a66d-cc3b98e10c4d','偶成','俞灝','宋','宋诗','song-poetry','','[]','白髮黄塵一夢中，又將愁眼對春風。',32,'全唐诗/poet.song.168000.json','["白髮黄塵一夢中，又將愁眼對春風。", "不知夜雨能多少，染得桃花到處紅。"]'),
('1963f196-7e3c-4c98-ac91-7b359cd0ebf0','句','俞灝','宋','宋诗','song-poetry','','[]','不知雨後更精神。',8,'全唐诗/poet.song.168000.json','["不知雨後更精神。"]'),
('364c1305-b0e4-4dbd-8f7a-8612b1694d46','遊雲門','詹騤','宋','宋诗','song-poetry','','[]','輕裘肥馬春三月，到此經遊花正紅。',32,'全唐诗/poet.song.168000.json','["輕裘肥馬春三月，到此經遊花正紅。", "欲覓上方幽隠處，老僧笑指白雲中。"]'),
('68f498e8-825f-49f2-ba92-f26f8d80c107','讀書堂五首  其一','葉子强','宋','宋诗','song-poetry','','[]','詩書不策勳，歲月忽已晚。',108,'全唐诗/poet.song.168000.json','["詩書不策勳，歲月忽已晚。", "墮此塵𡏖網，吾行其既遠。", "胡寧於書事，意愛猶繾綣。", "况之迷蹊人，慕顧祇舊阪。", "扁旁真赤幟，所立示所本。", "又如農人心，終不置穮蔉。", "晞髮茅檐下，榮榮蘭九畹。", "初服苟未替，無亦驚晼晚。", "所逢非所安，吾廬盍云返。"]'),
('450b1a19-0e15-44e9-913d-017ed88f085b','讀書堂五首  其二','葉子强','宋','宋诗','song-poetry','','[]','娟娟百個竹，落落一丈松。',72,'全唐诗/poet.song.168000.json','["娟娟百個竹，落落一丈松。", "豈無桃李華，春事孰與冬。", "寒菊北戶下，不鬭顔色穠。", "氣味如禿翁，忍死無容容。", "霜風落繫雁，露草棲織蛩。", "讀書真可人，明星耿疏篷。"]'),
('ddcc20d3-2e0f-45d9-8ab7-a079764bb6a2','讀書堂五首  其三','葉子强','宋','宋诗','song-poetry','','[]','小山後叢桂，方池前止水。',72,'全唐诗/poet.song.168000.json','["小山後叢桂，方池前止水。", "泠然堂中人，枯槁祇中爾。", "平生不止酒，來此真止矣。", "今辰忽開尊，叵料真未止。", "瓶罍本非二，無罄亦無耻。", "卷尊佩君言，慕之戴星起。"]'),
('8bbaa6ee-9738-478e-a7d7-52ae001fd811','讀書堂五首  其四','葉子强','宋','宋诗','song-poetry','','[]','左角明西方，十分農事回。',72,'全唐诗/poet.song.168000.json','["左角明西方，十分農事回。", "鞭蒲正爾束，繫圄夷然開。", "我胡汝乎德，一朝變喧豗。", "仁義不蹂踐，肺肝自胚胎。", "再拜父老言，美意吾所該。", "詩書不得力，亦自書中來。"]'),
('1e8430b9-ff4e-4666-9ec5-17637dc3ad6e','讀書堂五首  其五','葉子强','宋','宋诗','song-poetry','','[]','少長事壯厲，意氣彌九州。',96,'全唐诗/poet.song.168000.json','["少長事壯厲，意氣彌九州。", "鞭車踏長路，渠料能夷猶。", "困此九折坂，嶔崎不容輈。", "彼須匪所彊，此售寧或求。", "猶有讀書心，大寒索衣裘。", "賤嗜匪貴獻，一拂銷百愁。", "寶此清浄退，相從賦歸休。", "農圃雅所問，同一壑一丘。"]'),
('507b0739-6165-4fe8-bb3f-a0e745ef4c00','奉賦水仙花詩以謝提宮龔丈之貺','葉子强','宋','宋诗','song-poetry','','[]','水晶宮闕雲母軿，列仙夜宴曉未闌。',96,'全唐诗/poet.song.168000.json','["水晶宮闕雲母軿，列仙夜宴曉未闌。", "萬妃倚竹翠袖寒，捧黄金杯白玉盤。", "勸酬未足雲中歡，天門叫班奏祥鸞。", "驚此綽約落塵寰，嫣然花面明雕欄。", "天香宮態冰雪顔，江梅避舍不敢干。", "肯與噲伍羞山樊，說似詩伯平章看。"]'),
('dec1fbee-a9c6-4435-83ec-38a73c1b00d0','光華亭','魏伯恂','宋','宋诗','song-poetry','','[]','亭高爽塏聳牙檐，萬種森羅共一川。',64,'全唐诗/poet.song.168000.json','["亭高爽塏聳牙檐，萬種森羅共一川。", "坐使江山歸舊觀，欣看童稚望郵船。", "柳烟烘日塵迷渚，麥浪降風翠拍天。", "民物熙熙樂康阜，可無詩酒與君傳。"]'),
('dc983033-6291-49d1-bc9a-c4c094ab6ed8','別袁昌州','張孝芳','宋','宋诗','song-poetry','','[]','昌元古佳郡，比屋談經史。',36,'全唐诗/poet.song.168000.json','["昌元古佳郡，比屋談經史。", "山岡疊翠屏，溪瀨瀉清泚。", "蓄爲靈秀質，磊落出髦士。"]'),
('b30f9f85-b03b-45e6-9193-7864e68835ad','句  其一','張孝芳','宋','宋诗','song-poetry','','[]','三十六峰天與寄，雲間只欠我題詩。',16,'全唐诗/poet.song.168000.json','["三十六峰天與寄，雲間只欠我題詩。"]'),
('51102ee4-ec41-4a6d-95a8-06030339c64e','句  其二','張孝芳','宋','宋诗','song-poetry','','[]','鷄骨埋靈塔，龍門□佛龕。',12,'全唐诗/poet.song.168000.json','["鷄骨埋靈塔，龍門□佛龕。"]'),
('e1326688-9391-4bfd-bdd5-57c2e064e6cf','句  其三','張孝芳','宋','宋诗','song-poetry','','[]','發舟馬頭岸，駐車牛尾驛。',12,'全唐诗/poet.song.168000.json','["發舟馬頭岸，駐車牛尾驛。"]'),
('f850ff21-1528-4da6-bc72-4ce23ec298ff','紹熙辛亥六月中伏日出郭觀稼小休野石讀仲權正字壁間所題詩因次韻  其一','滕瑱','宋','宋诗','song-poetry','','[]','稻香藹藹暑風清，下馬傳觴聽水笙。',32,'全唐诗/poet.song.168000.json','["稻香藹藹暑風清，下馬傳觴聽水笙。", "父老指詩懷舊尹，爲鎸巖石寄心聲。"]'),
('66adb878-b994-49ea-8f9a-7eb7558ea1f1','紹熙辛亥六月中伏日出郭觀稼小休野石讀仲權正字壁間所題詩因次韻  其二','滕瑱','宋','宋诗','song-poetry','','[]','身傍蓬萊近紫清，巧言一出忽如笙。',32,'全唐诗/poet.song.168000.json','["身傍蓬萊近紫清，巧言一出忽如笙。", "祗今家食應無恙，書倩衡陽雁寄聲。"]'),
('b07e08d7-7d62-4fa1-909e-901569544c5b','謁張文獻公祠','王偁','宋','宋诗','song-poetry','','[]','停舟曲江滸，吊古謁遺祠。',204,'全唐诗/poet.song.168000.json','["停舟曲江滸，吊古謁遺祠。", "巖巖始興公，遺澤芬在斯。", "堂傾風雨萃，碑斷苔蘚滋。", "芳春□行旅，落日歸文狸。", "唐宮替無事，衡鑒方獨持。", "弼諧展嘉猷，讜論非□□。", "雝雝朝陽鳳，粲粲補衮絲。", "側聞卧病後，九廟煙塵□。", "漁陽突騎來，中華混群彝。", "信哉砥柱力，用舍同安危。", "昭陵鐵馬空，僊李祚九疑。", "維餘蘭菊存，千秋恒若茲。", "我來薦微誠，再拜當前墀。", "顧瞻廟貌間，風度猶可希。", "武溪何茫茫，筆峯亦巍巍。", "只今相業隆，孰與前修期。", "臨風一長歎，山雨來霏霏。"]'),
('9b73f525-33a1-4121-9f6f-6a35b857378b','余襄公祠','王偁','宋','宋诗','song-poetry','','[]','寂寞孤城野水濱，亂餘猶見幾家存。',64,'全唐诗/poet.song.168000.json','["寂寞孤城野水濱，亂餘猶見幾家存。", "女牆落日埋秋草，官樹啼烏集暮雲。", "百戰徒聞存國步，孤忠誰復吊英魂。", "夜來遺廟荒庭月，長逐悲笳不忍聞。"]'),
('3e7ba5c0-e179-4934-be48-69b73a8966bb','寶林寺','王申','宋','宋诗','song-poetry','','[]','千載寶林寺，清幽每往還。',48,'全唐诗/poet.song.168000.json','["千載寶林寺，清幽每往還。", "兩潮巖上井，一塔寺中山。", "門對荒城冷，鄰分古縣閑。", "道人高處坐，役役笑塵寰。"]'),
('52c4af6a-39d1-47a0-8a5a-5290111961ae','上揚州太守','楊冠','宋','宋诗','song-poetry','','[]','古人肉食無遠謀，腰錢騎鶴上揚州。',96,'全唐诗/poet.song.168000.json','["古人肉食無遠謀，腰錢騎鶴上揚州。", "春風十里珠簾捲，但看竹西歌吹樓。", "天朝選用詩書帥，上策公言須自治。", "屏翰堅持保障功，江淮益壯金湯勢。", "北騎不敢縱南牧，關寒烟迷芳草綠。", "健兒歌舞樂昇平，一曲梅花細柳營。"]'),
('4caa2e38-1c01-4a89-aeb9-f2a0242e7948','千手眼白玉觀音偈嘲金使','徑山寺僧','宋','宋诗','song-poetry','','[]','一手動時千手動，一眼觀時千眼觀。',32,'全唐诗/poet.song.168000.json','["一手動時千手動，一眼觀時千眼觀。", "幸自太平無一事，何須做得許多般。"]'),
('f14c7d80-c009-4590-a7a1-ad1e3cd20b71','資國院','羅之紀','宋','宋诗','song-poetry','','[]','倦逢磐石手摩挲，橫壓烏藤漫嘯歌。',64,'全唐诗/poet.song.168000.json','["倦逢磐石手摩挲，橫壓烏藤漫嘯歌。", "烟崦坡陀青玉案，寺山縹緲白雲窩。", "紙窗竹屋小盤礴，林影溪光相盪磨。", "試共老僧參此意，一聲喚醒讀書魔。"]'),
('fcca3ea0-1cf0-4ac2-9064-9eae6f830e26','句','羅之紀','宋','宋诗','song-poetry','','[]','吾道非耶真可恥，此君豈是折腰人。',16,'全唐诗/poet.song.168000.json','["吾道非耶真可恥，此君豈是折腰人。"]'),
('dd5e9f05-9e06-4786-a461-a56d59bd786d','白雲廬','郭時雍','宋','宋诗','song-poetry','','[]','吾愛白雲雲愛吾，朝朝暮暮伴吾廬。',32,'全唐诗/poet.song.168000.json','["吾愛白雲雲愛吾，朝朝暮暮伴吾廬。", "從龍傍鳥隨他去，留與幽人作畫圖。"]'),
('9cd0550a-1b36-417c-a369-a66f214d9c27','九日宴浮金亭','趙宗德','宋','宋诗','song-poetry','','[]','東山樹，何青青。',280,'全唐诗/poet.song.168000.json','["東山樹，何青青。", "鐔津水，何泠泠。", "茂樹可蔭，流水可聽。", "眉山夫子能解事，却于水邊樹下構危亭。", "洪波浴日金錯落，瘴雲不雨烟濛溟。", "風塵澒洞去天遠，草木蓊鬰知地靈。", "監州爲愛黄華節，携我登臨邀衆客。", "假令有酒多似藤江水，豈能洗我胸中之鬰抑。", "甘侯昆玉文武全，傾蓋交游五情熱。", "故人亦有許判官，清政平生心似鐵。", "文采風流喻幕賓，曾陪驄馬清南越。", "劉君元是薇省郎，治民有道多籌策。", "令簿懷才亦不群，芳名皆在斯文列。", "儒林龔魏兩茂學，逸氣直與青雲接。", "孟嘉落帽是何年，岸幘西風感前哲。", "天荒地老事茫茫，白髮無情滿頭雪。", "醒時飲，醉時歌。", "尊前要使衰顔酡，不飲奈此清興何。", "人生聚會能有幾，江海親舊今無多。"]'),
('1974f029-fe9c-4b25-b99c-a78b0ba499bf','僻性','高遁翁','宋','宋诗','song-poetry','','[]','僻性一生忘嗜酒，勞神終日倦吟詩。',32,'全唐诗/poet.song.168000.json','["僻性一生忘嗜酒，勞神終日倦吟詩。", "尋常高卧松床穩，不管庭前鶴到遲。"]'),
('f0fcd645-c9df-498f-b952-e1cb5f2b56a7','曉徑','高遁翁','宋','宋诗','song-poetry','','[]','蘿徑朝飛雨，莓苔染翠濃。',24,'全唐诗/poet.song.168000.json','["蘿徑朝飛雨，莓苔染翠濃。", "登山雙屐健，自擬少年同。"]'),
('cf624749-e71a-4882-b234-b0405e135034','春暮','高遁翁','宋','宋诗','song-poetry','','[]','石橋門外送斜暉，柳灑清風透客衣。',32,'全唐诗/poet.song.168000.json','["石橋門外送斜暉，柳灑清風透客衣。", "老眼看花能有幾，如何啼鳥暮春歸。"]'),
('a9bfdd33-435f-47cd-bda4-3e7906c865c8','市橋晚坐','高遁翁','宋','宋诗','song-poetry','','[]','隔眼風塵寢，閒心照水清。',48,'全唐诗/poet.song.168000.json','["隔眼風塵寢，閒心照水清。", "牛羊歸古坂，鷗鷺集浮萍。", "倦我思垂釣，知誰共濯纓。", "湖光浮一鑑，倒暎夕陽明。"]'),
('2e769e87-ca90-4fc9-b240-3398a1429ba7','秋晚','高遁翁','宋','宋诗','song-poetry','','[]','風掃柴門凈，銀燈吐玉花。',48,'全唐诗/poet.song.168000.json','["風掃柴門凈，銀燈吐玉花。", "納凉憑□石，待月上窗紗。", "老去心猶壯，秋來鬢任華。", "不妨高枕睡，無夢到公家。"]'),
('e64419e5-5af6-4ed0-bb74-48bed8d0fb68','自詠遁翁','高遁翁','宋','宋诗','song-poetry','','[]','虛名蝸角不攖情，老木棉裘分此生。',64,'全唐诗/poet.song.168000.json','["虛名蝸角不攖情，老木棉裘分此生。", "世事只隨今日過，心田留待後人耕。", "舊書豈厭從頭看，險路何妨退步行。", "俯仰欲求無所愧，舉頭惟對月華明。"]'),
('3267983a-cb1a-41a6-8fde-270fd998caa8','甥舅同登進士亦世之不易得者今幸逢其會因吟一律以寄一以表祖宗積善之徵二以謝聖主寵賜之榮三以致勉忠之意二子惟勗諸','高遁翁','宋','宋诗','song-poetry','','[]','潦倒山林已二毛，忽聞□□下衡茅。',64,'全唐诗/poet.song.168000.json','["潦倒山林已二毛，忽聞□□下衡茅。", "祖宗積德幸多世，甥舅何妨共奪標。", "柳拂祥光看虎榜，杏扶春色上雲袍。", "從今莫作懷家計，須効忠良答聖朝。"]'),
('4131e549-6070-4524-8738-4933deccb07c','田園偶興','高質齋','宋','宋诗','song-poetry','','[]','繞簷風景接崆峒，生計年年樂歲豐。',64,'全唐诗/poet.song.168000.json','["繞簷風景接崆峒，生計年年樂歲豐。", "布穀聲傳紅杏雨，□□調起綠楊風。", "桑麻遠近千村裏，禾黍高低一望中。", "每與鄰翁相慶社，醉歌不惜酒樽空。"]'),
('b1b69f60-e5a1-4cea-9dcc-5b01f51e0835','溪石呈李思道','高質齋','宋','宋诗','song-poetry','','[]','共坐溪邊石，溪清心自涼。',48,'全唐诗/poet.song.168000.json','["共坐溪邊石，溪清心自涼。", "魚驚烟艇過，鷗笑野人忙。", "細草侵衣綠，飛花點鬢香。", "東風塵暫息，拍手送斜陽。"]'),
('4aab2560-56f8-4f75-8747-4d297ecd5f16','復和呈莫仲箎','高質齋','宋','宋诗','song-poetry','','[]','溪石綉苔綠，溪風飄晚凉。',48,'全唐诗/poet.song.168000.json','["溪石綉苔綠，溪風飄晚凉。", "坐久得自若，物外知誰忙。", "渴飲竹泉冷，饑飯松花香。", "春光忽云暮，□□□□陽。"]'),
('908b5e02-d9de-49d6-b32b-99179bccd2a3','紀興','高質齋','宋','宋诗','song-poetry','','[]','湖上人家萬木村，白雲深護讀書門。',32,'全唐诗/poet.song.168000.json','["湖上人家萬木村，白雲深護讀書門。", "年來不管頭顱白，自賀清風酒一樽。"]'),
('2828d072-10fc-4264-af55-5d2dacae1ee9','秋日溪亭','高質齋','宋','宋诗','song-poetry','','[]','簾捲柴桑晚，深山俗駕疏。',48,'全唐诗/poet.song.168000.json','["簾捲柴桑晚，深山俗駕疏。", "荒苔留鶴跡，落葉带蟲書。", "竹翠侵香案，泉聲漱石渠。", "烟霞便一枕，應笑把犁鋤。"]'),
('a786352e-c9ca-40a7-b56b-6ed74e4ac7fd','懷古','呂定','宋','宋诗','song-poetry','','[]','我昔遊海上，東望三神山。',60,'全唐诗/poet.song.168000.json','["我昔遊海上，東望三神山。", "風波幾萬里，蒼茫雲靄間。", "魚龍自掀舞，天空日月閒。", "神仙渺無跡，徐福去不還。", "空餘蓬萊閣，千載留人寰。"]'),
('aeeb11dd-ff8e-45ab-8d24-6774ed3cd134','追和蘇子瞻遊峽山寺韻','呂定','宋','宋诗','song-poetry','','[]','山迥寶華閣，水遶金鎖灣。',96,'全唐诗/poet.song.168000.json','["山迥寶華閣，水遶金鎖灣。", "塵慮頓焉息，于茲開我顔。", "疎鐘日夕動，老僧林下還。", "天風吹白雲，悠悠滿松關。", "歸猿有餘悲，月明嘯空山。", "仙人自何來，翱翔八極間。", "手把玉芙蓉，吟笑鏘珮環。", "歌罷忽飛去，千峰堆翠鬟。"]'),
('9ab43681-7011-41b9-aeeb-795882d7b908','赴京','呂定','宋','宋诗','song-poetry','','[]','太白樓前雨乍收，畫船撾鼓上皇州。',64,'全唐诗/poet.song.168000.json','["太白樓前雨乍收，畫船撾鼓上皇州。", "肯因離別牽愁思，要把勳名事壯遊。", "千里關河旗带月，一天星斗劍橫秋。", "胸中賸有安邊策，此去應當獻冕旒。"]'),
('7f446e0b-53bf-4e9b-b825-b9954485fa9f','奉天門朝賀','呂定','宋','宋诗','song-poetry','','[]','曉日初臨萬歲山，寶幢華盖列朝班。',64,'全唐诗/poet.song.168000.json','["曉日初臨萬歲山，寶幢華盖列朝班。", "九重天上來仙樂，五色雲中識聖顔。", "深殿捲簾香霧裊，近臣傳制珮聲還。", "嵩呼齊祝恩如海，散作陽和滿世間。"]'),
('909b8728-62ce-447f-996c-76f084cf3437','調兵','呂定','宋','宋诗','song-poetry','','[]','年少談兵膽氣豪，折衝千里豈辭勞。',64,'全唐诗/poet.song.168000.json','["年少談兵膽氣豪，折衝千里豈辭勞。", "旌旗影動秋風瑟，鼓角聲回夜月高。", "紅錦裁鞍新試馬，黄金裝带舊懸刀。", "臨征自信軍容盛，五色團花繡戰袍。"]'),
('bfd9541b-f2ec-4747-9449-5da9935dec55','扈駕','呂定','宋','宋诗','song-poetry','','[]','八月秋高戰馬肥，觀兵郊外振天威。',64,'全唐诗/poet.song.168000.json','["八月秋高戰馬肥，觀兵郊外振天威。", "一聲鳳吹迎鸞馭，五色龍文雜衮衣。", "劍戟橫空金氣肅，旌旗映日綵雲飛。", "令嚴星火諸軍奮，直斬單于塞上歸。"]'),
('4231ef0d-0e24-41b0-bfd1-7b09b8ca0a47','班師','呂定','宋','宋诗','song-poetry','','[]','紫塞回來雪正晴，王師百萬擁連營。',64,'全唐诗/poet.song.168000.json','["紫塞回來雪正晴，王師百萬擁連營。", "馬嘶大地山河壯，旗捲長空日月明。", "龍虎臺高千嶂聳，鳳皇城近五雲生。", "聖顔有喜天心順，中外歡聞奏凱聲。"]'),
('bc0e4663-68c8-4d28-be1d-c30af66a594c','登東岳山','呂定','宋','宋诗','song-poetry','','[]','海內名山孰與齊，清風掖我上丹梯。',64,'全唐诗/poet.song.168000.json','["海內名山孰與齊，清風掖我上丹梯。", "鵬程九萬扶摇近，世界三千指顧低。", "瀑挂天門驚霹靂，雨蒸日觀出虹霓。", "太平會見東封盛，玉簡金書煥紫泥。"]'),
('fea6a42d-fb6c-412e-a980-c85e8453bb9a','雪夜','呂定','宋','宋诗','song-poetry','','[]','漠漠同雲徧海涯，曉風寒逼綠窗紗。',64,'全唐诗/poet.song.168000.json','["漠漠同雲徧海涯，曉風寒逼綠窗紗。", "飛揚鱗甲三千界，粧點樓臺百萬家。", "何處妙歌金帳酒，誰人清對玉梅花。", "便應石鼎融冰水，烏帽籠頭自煮茶。"]'),
('b98cde2e-1c54-4b84-957d-6ffe4aff7720','望岱岳','呂定','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','岱宗東望鬰嵯峨，萬丈仙橋鳥外過。',64,'全唐诗/poet.song.168000.json','["岱宗東望鬰嵯峨，萬丈仙橋鳥外過。", "秦樹千年空老大，漢碑終古不消磨。", "天壇夜靜乘星斗，石磴春深長薜蘿。", "記得舊遊曾載酒，頹然峰頂放長歌。"]'),
('d3446ecf-4eb8-4859-adb2-6ea2c5765fde','望嶧山','呂定','宋','宋诗','song-poetry','','[]','極目東山秀色濃，紫霄千葉醉芙蓉。',64,'全唐诗/poet.song.168000.json','["極目東山秀色濃，紫霄千葉醉芙蓉。", "題詩尚記仙人洞，飛珮曾過玉女峰。", "樹老孤桐秋露下，碑殘古篆暮雲封。", "何時再醉天門月，卧聽清風萬壑松。"]'),
('b156366d-6beb-4404-ad8a-3c28a586d5c4','登彭城樓','呂定','宋','宋诗','song-poetry','','[]','項王臺上白雲秋，亞夫墳前草樹稠。',64,'全唐诗/poet.song.168000.json','["項王臺上白雲秋，亞夫墳前草樹稠。", "山色不隨人事改，水聲長近戍城流。", "空餘夜月龍神廟，無復春風燕子樓。", "楚漢興亡俱土壤，不須懷古重夷猶。"]'),
('8b3a75bf-58ec-494c-af05-478ae3329fb0','戲馬臺','呂定','宋','宋诗','song-poetry','','[]','據鞍揮指八千兵，昔日中原幾戰爭。',64,'全唐诗/poet.song.168000.json','["據鞍揮指八千兵，昔日中原幾戰爭。", "追鹿已無秦社稷，逝騅方嘆楚歌聲。", "英雄事往人何在，寂寞臺空草自生。", "回首雲山青矗矗，黄流依舊遶彭城。"]'),
('3f0ec97f-bd21-46df-9c60-661a419ad3d5','夜宿甓社湖','呂定','宋','宋诗','song-poetry','','[]','湖光如鏡迥無山，耿耿銀河路可攀。',64,'全唐诗/poet.song.168000.json','["湖光如鏡迥無山，耿耿銀河路可攀。", "萬象不移天地外，一塵能到水雲間。", "月明孤嶼森樓閣，夜靜飛仙過珮環。", "借問孟城何處是，微微燈火綠楊灣。"]'),
('8a5e887a-7566-4cb2-b0e7-f84bdffd2f48','金陵旅夜','呂定','宋','宋诗','song-poetry','','[]','一雨皇都萬象明，東風嬌囀上林鶑。',64,'全唐诗/poet.song.168000.json','["一雨皇都萬象明，東風嬌囀上林鶑。", "火烟亭館春多少，鐘鼓樓臺夜幾更。", "枕上故園蝴蝶夢，枝頭斜月杜鵑聲。", "銀牋欲寫長相憶，滾滾江流不盡情。"]'),
('d105de17-cc92-4cc1-91cc-30470d476252','過小孤山','呂定','宋','宋诗','song-poetry','','[]','八月靈槎溯海門，翠雲臺上醉芳樽。',64,'全唐诗/poet.song.168000.json','["八月靈槎溯海門，翠雲臺上醉芳樽。", "峰頭樓閤相高下，水底魚龍自吐吞。", "萬古青天留玉柱，五更紅日湧金盆。", "宦遊不盡登臨興，欲洗蒼苔頌聖恩。"]'),
('5bcee9b7-cdac-4174-898f-f3de7ff9b1e9','登翠雲臺','呂定','宋','宋诗','song-poetry','','[]','一柱中流亦壯哉，分明世上有蓬萊。',64,'全唐诗/poet.song.168000.json','["一柱中流亦壯哉，分明世上有蓬萊。", "簾開廬阜層層出，船汎岷山滾滾來。", "夜冷神龍蟠水府，天青仙珮下瑶臺。", "閒將玉管吹明月，勾引翩翩彩鳳迴。"]'),
('7c6cbe21-b7ea-4a38-aced-acc6d462b681','遊匡廬山','呂定','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','欲向匡廬觀瀑布，便從鼓蠡驟樓船。',64,'全唐诗/poet.song.168000.json','["欲向匡廬觀瀑布，便從鼓蠡驟樓船。", "一聲長嘯來丹壑，千丈飛流下碧天。", "洞裏樓臺無歲月，雲中鷄犬有神仙。", "憑誰呼起巢松者，醉擁宮袍對酒眠。"]'),
('3e7b2d5f-5a29-4278-adae-0ca09651f6bc','度大庾嶺','呂定','宋','宋诗','song-poetry','','[]','鑿破鴻濛一竅通，至今傳說九齡功。',64,'全唐诗/poet.song.168000.json','["鑿破鴻濛一竅通，至今傳說九齡功。", "天垂瘴雨蠻烟外，路入炎荒火樹中。", "萬里關河瞻北極，兩行旌旆過南雄。", "鷓鴣聲裏端陽近，榕樹青青荔子紅。"]');
